    fn distributed_finality_covers_run(
        &self,
        evidence: &ReadinessEvidence,
        run_profile: &RunProfileReport,
    ) -> bool {
        let produced_blocks = self.blocks.len() as u64;
        let latest_height = self.blocks.last().map(|block| block.height).unwrap_or(0);
        let target_finality_micros = self.cli.target_finality_ms.saturating_mul(1_000);
        let expected_region_count = self.expected_distributed_finality_region_count();
        evidence.distributed_finality_sample_count >= produced_blocks
            && evidence.distributed_finality_validator_count >= self.cli.validator_count
            && evidence.distributed_finality_validator_threshold >= self.cli.validator_threshold
            && evidence.distributed_finality_region_count >= expected_region_count
            && evidence.distributed_finality_target_micros <= target_finality_micros
            && evidence.distributed_finality_max_quorum_certificate_micros <= target_finality_micros
            && evidence.distributed_finality_testnet_manifest_id == self.manifest_id()
            && evidence.distributed_finality_run_profile_report_root == run_profile.report_root
            && evidence.distributed_finality_local_validator_count == self.cli.validator_count
            && evidence.distributed_finality_local_validator_threshold
                == self.cli.validator_threshold
            && evidence.distributed_finality_local_region_count == expected_region_count
            && evidence.distributed_finality_local_target_micros == target_finality_micros
            && evidence.distributed_finality_latest_block_height == latest_height
            && run_profile.passed
    }

