    fn expected_distributed_finality_region_count(&self) -> u64 {
        self.cli.validator_count.clamp(1, 4)
    }

    fn anchor_capacity_evidence_covers_run(&self, evidence: &ReadinessEvidence) -> bool {
        let total_transactions = self.total_public_transaction_count();
        evidence.anchor_capacity_fixed_format_payload
            && evidence.anchor_capacity_observed_epoch_count > 0
            && evidence.anchor_capacity_max_transactions_per_anchor >= DEFAULT_ANCHOR_CAPACITY_TX
            && evidence.anchor_capacity_max_transactions_per_anchor >= self.cli.anchor_capacity_tx
            && evidence.anchor_capacity_max_transactions_per_anchor >= total_transactions
            && evidence.anchor_capacity_payload_bytes > 0
    }

