    fn adversarial_coverage_covers_run(&self, evidence: &ReadinessEvidence) -> bool {
        let produced_blocks = self.blocks.len() as u64;
        let target_finality_micros = self.cli.target_finality_ms.saturating_mul(1_000);
        evidence.adversarial_max_block_count >= produced_blocks
            && evidence.adversarial_max_validator_count >= self.cli.validator_count
            && evidence.adversarial_covered_finality_target_micros <= target_finality_micros
    }

