    fn fee_efficiency_evidence_covers_run(&self, evidence: &ReadinessEvidence) -> bool {
        let total_transactions = self.total_public_transaction_count();
        evidence.fee_efficiency_sample_count >= total_transactions
            && evidence.fee_efficiency_normal_load_tps >= self.cli.blocks.max(1)
            && evidence.fee_efficiency_ratio_bps <= MAX_L2_TO_MONERO_L1_FEE_RATIO_BPS
            && evidence
                .fee_efficiency_l2_p95_fee_piconero
                .saturating_mul(10)
                <= evidence.fee_efficiency_monero_l1_reference_fee_piconero
    }

