fn main() {
    if let Err(error) = run() {
        eprintln!("nebula-testnet error: {error}");
        process::exit(1);
    }
}

fn run() -> Result<(), String> {
    let mut cli = parse_cli(env::args().skip(1).collect())?;
    let mut testnet = Testnet::new(cli.clone());
    testnet.run()?;
    let dry_summary = testnet.summary(Vec::new());
    let status_json = serde_json::to_string(&public_status_manifest(&dry_summary))
        .map_err(|error| format!("failed to encode status json: {error}"))?;
    let probes = if cli.listen_ms > 0 {
        run_probe_window(&cli, status_json)?
    } else {
        Vec::new()
    };
    let mut summary = testnet.summary(probes.clone());
    let mut deployment_from_capture = None;
    if let (Some(capture_path), Some(output_path)) = (
        cli.public_deployment_evidence_assembly_path.as_deref(),
        cli.public_deployment_evidence_output_path.as_deref(),
    ) {
        let deployment =
            write_public_deployment_evidence_from_capture(capture_path, output_path, &summary)?;
        deployment_from_capture = Some(deployment);
    }
    if let Some(capture_path) = cli.public_deployment_capture_verify_path.as_deref() {
        let deployment = verify_public_deployment_capture(capture_path, &summary)?;
        deployment_from_capture = Some(deployment);
    }
    if let Some(deployment) = deployment_from_capture {
        cli.public_deployment_evidence = Some(deployment.clone());
        testnet.cli.public_deployment_evidence = Some(deployment);
        summary = testnet.summary(probes.clone());
    }
    if let Some(path) = cli.public_deployment_evidence_verify_path.as_deref() {
        let deployment = load_public_deployment_evidence(path)?;
        cli.public_deployment_evidence = Some(deployment.clone());
        testnet.cli.public_deployment_evidence = Some(deployment);
        summary = testnet.summary(probes.clone());
    }
    if cli.mainnet_readiness {
        ensure(
            summary.acceptance.no_mainnet_custody
                && summary.acceptance.finality_target_met
                && summary.acceptance.signer_quorum_enforced
                && summary.acceptance.watchtower_challenge_surface_available,
            "mainnet readiness dry-run acceptance failed",
        )?;
    } else {
        ensure(
            summary.acceptance.testnet_ready,
            "testnet acceptance failed",
        )?;
    }
    if let Some(path) = cli.readiness_template_path.as_deref() {
        write_readiness_template(path, &summary)?;
    }
    if let Some(path) = cli.readiness_template_verify_path.as_deref() {
        verify_readiness_template(path, &summary)?;
    }
    if let Some(path) = cli.release_approval_template_path.as_deref() {
        write_release_approval_template(path, &summary)?;
    }
    if let Some(path) = cli.release_approval_template_verify_path.as_deref() {
        verify_release_approval_template(path, &summary)?;
    }
    if let Some(path) = cli.release_authority_registry_template_path.as_deref() {
        write_release_authority_registry_template(path)?;
    }
    if let Some(path) = cli
        .release_authority_registry_template_verify_path
        .as_deref()
    {
        verify_release_authority_registry_template(path)?;
    }
    if let Some(path) = cli.public_bootstrap_profile_path.as_deref() {
        write_public_bootstrap_profile(path, &summary)?;
    }
    if let Some(path) = cli.public_bootstrap_profile_verify_path.as_deref() {
        verify_public_bootstrap_profile(path, &summary)?;
    }
    if let Some(path) = cli.public_status_manifest_path.as_deref() {
        write_public_status_manifest(path, &summary)?;
    }
    if let Some(path) = cli.public_status_manifest_verify_path.as_deref() {
        verify_public_status_manifest(path, &summary)?;
    }
    if let Some(path) = cli.public_deployment_runbook_path.as_deref() {
        write_public_deployment_runbook(path, &summary)?;
    }
    if let Some(path) = cli.public_deployment_runbook_verify_path.as_deref() {
        verify_public_deployment_runbook(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_artifact_manifest_path.as_deref() {
        write_public_launch_artifact_manifest(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_artifact_manifest_verify_path.as_deref() {
        verify_public_launch_artifact_manifest(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_bundle_path.as_deref() {
        write_public_launch_bundle(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_bundle_verify_path.as_deref() {
        verify_public_launch_bundle(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_readiness_report_path.as_deref() {
        write_public_launch_readiness_report(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_readiness_report_verify_path.as_deref() {
        verify_public_launch_readiness_report(path, &summary)?;
    }
    if let Some(path) = cli.public_capture_todo_path.as_deref() {
        write_public_capture_todo(path, &summary)?;
    }
    if let Some(path) = cli.public_capture_todo_verify_path.as_deref() {
        verify_public_capture_todo(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_package_dir.as_deref() {
        write_public_launch_package(path, &summary)?;
    }
    if let Some(path) = cli.public_launch_package_verify_dir.as_deref() {
        verify_public_launch_package(path, &summary)?;
    }
    if let Some(path) = cli.public_testnet_certification_dir.as_deref() {
        write_public_testnet_certification(path, &summary)?;
    }
    if let Some(path) = cli.public_testnet_certification_verify_dir.as_deref() {
        verify_public_testnet_certification(path, &summary)?;
    }
    if let Some(path) = cli.public_deployment_evidence_template_path.as_deref() {
        write_public_deployment_evidence_template(path, &summary)?;
    }
    if let Some(path) = cli
        .public_deployment_evidence_template_verify_path
        .as_deref()
    {
        verify_public_deployment_evidence_template(path, &summary)?;
    }
    if let Some(path) = cli.public_deployment_capture_plan_path.as_deref() {
        write_public_deployment_capture_plan(path, &summary)?;
    }
    if let Some(path) = cli.public_deployment_capture_plan_verify_path.as_deref() {
        verify_public_deployment_capture_plan(path, &summary)?;
    }
    if let (Some(path), Some(package_dir)) = (
        cli.public_deployment_capture_scaffold_path.as_deref(),
        cli.public_deployment_capture_scaffold_package_dir
            .as_deref(),
    ) {
        write_public_deployment_capture_scaffold(path, package_dir, &summary)?;
    }
    if let (Some(path), Some(package_dir)) = (
        cli.public_deployment_capture_scaffold_verify_path
            .as_deref(),
        cli.public_deployment_capture_scaffold_package_dir
            .as_deref(),
    ) {
        verify_public_deployment_capture_scaffold(path, package_dir, &summary)?;
    }
    if let (Some(capture_path), Some(output_path)) = (
        cli.public_deployment_capture_audit_path.as_deref(),
        cli.public_deployment_capture_audit_output_path.as_deref(),
    ) {
        write_public_deployment_capture_audit(capture_path, output_path, &summary)?;
    }
    if let (Some(capture_path), Some(audit_path)) = (
        cli.public_deployment_capture_audit_path.as_deref(),
        cli.public_deployment_capture_audit_verify_path.as_deref(),
    ) {
        verify_public_deployment_capture_audit(capture_path, audit_path, &summary)?;
    }
    if let Some(path) = cli.public_deployment_evidence_verify_path.as_deref() {
        verify_public_deployment_evidence(path, &summary)?;
    }
    let readiness_gap_error = if cli.fail_on_readiness_gaps {
        ensure_artifact_readiness_gates(&summary).err()
    } else {
        None
    };
    let public_launch_gap_error = if cli.fail_on_public_launch_gaps {
        ensure_public_launch_gates(&summary).err()
    } else {
        None
    };
    if cli.json {
        println!(
            "{}",
            serde_json::to_string_pretty(&summary)
                .map_err(|error| format!("failed to encode summary json: {error}"))?
        );
    } else {
        println!(
            "nebula testnet ready: blocks={} latest={} monero={} reserve_covered={} rpc={} p2p={}",
            summary.produced_blocks,
            summary.latest_block_hash,
            summary.monero_network,
            summary.acceptance.reserve_covered,
            summary.rpc_bind,
            summary.p2p_bind
        );
        println!("manifest_id={}", summary.manifest_id);
        println!("reserve_report_root={}", summary.bridge.reserve_report_root);
    }
    if let Some(error) = public_launch_gap_error {
        return Err(error);
    }
    if let Some(error) = readiness_gap_error {
        return Err(error);
    }
    Ok(())
}

fn ensure_artifact_readiness_gates(summary: &TestnetSummary) -> Result<(), String> {
    let gaps = artifact_readiness_gaps(&summary.mainnet_readiness);
    ensure(
        gaps.is_empty(),
        &format!(
            "mainnet readiness artifact gates remain blocked: {}",
            gaps.join(",")
        ),
    )
}

fn artifact_readiness_gaps(readiness: &MainnetReadiness) -> Vec<String> {
    readiness
        .blocking_gaps
        .iter()
        .filter(|gap| gap.as_str() != "mainnet-release-approval")
        .cloned()
        .collect()
}

