fn ensure_public_launch_gates(summary: &TestnetSummary) -> Result<(), String> {
    let gaps = &summary.public_launch_readiness.blocking_gaps;
    ensure(
        gaps.is_empty(),
        &format!("public launch gates remain blocked: {}", gaps.join(",")),
    )
}

#[cfg(test)]
fn public_launch_gaps(summary: &TestnetSummary) -> Vec<String> {
    summary.public_launch_readiness.blocking_gaps.clone()
}

fn public_launch_readiness_report(summary: &TestnetSummary) -> PublicLaunchReadiness {
    let checks = public_launch_checks(summary);
    let remediations = public_launch_remediations(summary, &checks);
    let blocking_gaps = checks
        .iter()
        .filter(|check| check.status != "pass")
        .map(|check| check.id.clone())
        .collect::<Vec<_>>();
    let public_launch_ready = blocking_gaps.is_empty();
    let level = if public_launch_ready {
        "public-launch-ready"
    } else {
        "public-launch-blocked"
    }
    .to_string();
    let check_roots = checks
        .iter()
        .map(|check| {
            root(&[
                "public-launch-readiness-check",
                &check.id,
                &check.status,
                &check.evidence_root,
            ])
        })
        .collect::<Vec<_>>();
    let check_root = collection_root("public-launch-readiness-checks", check_roots);
    let remediation_root = collection_root(
        "public-launch-remediations",
        remediations
            .iter()
            .map(|remediation| remediation.remediation_root.clone())
            .collect::<Vec<_>>(),
    );
    let report_root = root(&[
        "public-launch-readiness-report",
        CHAIN_ID,
        &summary.manifest_id,
        &check_root,
        &remediation_root,
        bool_str(public_launch_ready),
    ]);
    PublicLaunchReadiness {
        level,
        public_launch_ready,
        dry_run: summary.acceptance.mainnet_readiness_dry_run,
        report_root,
        check_root,
        remediation_root,
        blocking_gaps,
        remediations,
        checks,
    }
}

fn public_launch_remediations(
    summary: &TestnetSummary,
    checks: &[ReadinessCheck],
) -> Vec<PublicLaunchRemediation> {
    checks
        .iter()
        .filter(|check| check.status != "pass")
        .map(|check| public_launch_remediation_for_check(summary, check))
        .collect()
}

