fn public_launch_checks(summary: &TestnetSummary) -> Vec<ReadinessCheck> {
    let public_status = public_status_manifest(summary);
    let status_redacted = ensure_public_status_manifest_redacted(&public_status).is_ok();
    let status_root = public_status["public_status_manifest_root"]
        .as_str()
        .unwrap_or("missing-public-status-manifest-root");
    let public_bundle = public_launch_bundle(summary);
    let bundle_redacted = ensure_public_launch_bundle_redacted(&public_bundle).is_ok();
    let bundle_root = public_bundle["public_launch_bundle_root"]
        .as_str()
        .unwrap_or("missing-public-launch-bundle-root");
    let deployment_evidence_root = summary
        .public_deployment
        .evidence_root
        .as_deref()
        .unwrap_or("missing-public-deployment-evidence");
    vec![
        readiness_check(
            "public-launch-no-mainnet-custody",
            summary.acceptance.no_mainnet_custody,
            "public launch must keep Monero mainnet custody disabled",
            &summary.mainnet_readiness.run_checkpoint_root,
        ),
        readiness_check(
            "public-launch-finality-target",
            summary.acceptance.finality_target_met,
            "public launch requires local quorum-certificate finality under the configured <=200ms target",
            &summary.consensus.quorum_certificate_root,
        ),
        readiness_check(
            "public-launch-bootstrap-profile",
            summary.public_bootstrap_profile.passed,
            "public bootstrap profile must bind endpoint commitments, bootnodes, rate limits, faucet/reset policy, monitoring, and runbook roots",
            &summary.public_bootstrap_profile.report_root,
        ),
        readiness_check(
            "public-launch-policy-bounds",
            summary.public_bootstrap_profile.rate_limits_configured
                && summary.public_bootstrap_profile.faucet_limited
                && summary.public_bootstrap_profile.reset_policy_configured
                && summary.public_bootstrap_profile.bootstrap_node_count_valid,
            "public launch policies must keep bootstrap count, RPC/P2P limits, faucet caps, and reset windows inside bounded public-alpha limits",
            &summary.public_bootstrap_profile.profile_root,
        ),
        readiness_check(
            "public-launch-runner-loopback-only",
            summary.public_bootstrap_profile.local_runner_loopback_only
                && summary.public_bootstrap_profile.public_bind_not_enabled_by_runner
                && summary.public_bootstrap_profile.endpoint_commitments_only,
            "local runner must remain loopback-only while deployment proxies expose only committed public endpoints",
            &summary.run_profile.report_root,
        ),
        readiness_check(
            "public-launch-status-manifest-redacted",
            status_redacted,
            "public status manifest must be redacted and root-bound before publication",
            status_root,
        ),
        readiness_check(
            "public-launch-bundle-redacted",
            bundle_redacted,
            "public launch handoff bundle must be redacted and keep full operator summary private",
            bundle_root,
        ),
        readiness_check(
            "public-launch-deployment-attestation",
            summary.public_deployment.passed,
            "schema v5 public deployment evidence must bind incident-contact probes, runbook receipts, fresh multi-observer policy, status/P2P/health/ops/finality, and private-summary denial transcripts to the launch bundle",
            deployment_evidence_root,
        ),
        readiness_check(
            "public-launch-reserve-monitoring",
            summary.reserve_monitoring.passed,
            "public launch requires local reserve monitoring with independent reporters and underreserve alert drill",
            &summary.reserve_monitoring.report_root,
        ),
        readiness_check(
            "public-launch-operations-drills",
            summary.operations_readiness_local.passed,
            "public launch requires incident, rollback, queue-drain, pause/resume, and reserve reconciliation drills",
            &summary.operations_readiness_local.report_root,
        ),
        readiness_check(
            "public-launch-privacy-surface",
            summary.privacy_surface.passed,
            "public launch requires the local public surface to exclude raw Monero or wallet-secret identifiers",
            &summary.privacy_surface.report_root,
        ),
        readiness_check(
            "public-launch-da-watchtower-coverage",
            summary.da_proof_watchtower_coverage.passed,
            "public launch requires DA/proof/watchtower coverage for every produced block",
            &summary.da_proof_watchtower_coverage.report_root,
        ),
        readiness_check(
            "public-launch-wallet-recovery-audit",
            summary.wallet_recovery_audit.passed,
            "public launch requires wallet recovery audit roots for admissions, block status, DA/proof, anchors, and bridge history",
            &summary.wallet_recovery_audit.report_root,
        ),
        readiness_check(
            "public-launch-mempool-accountability",
            summary.mempool_accountability.passed,
            "public launch requires admission/preconfirmation accountability with no expired omissions",
            &summary.mempool_accountability.report_root,
        ),
        readiness_check(
            "public-launch-bridge-release-safety",
            summary.bridge_release_safety.passed,
            "public launch requires reserve, signer quorum, delay, rate-limit, pause, and challenge-hold release safety",
            &summary.bridge_release_safety.report_root,
        ),
    ]
}

