fn ensure_current_run_pointer_bindings(
    actual: &Value,
    expected: &Value,
    artifact_label: &str,
    bindings: &[(&str, &str)],
) -> Result<(), String> {
    for (label, pointer) in bindings {
        ensure(
            actual.pointer(pointer) == expected.pointer(pointer),
            &format!("{artifact_label} {label} mismatch"),
        )?;
    }
    Ok(())
}

