fn public_deployment_capture_next_steps_root(next_steps: &Value) -> String {
    let step_roots = next_steps
        .as_object()
        .map(|steps| {
            let mut entries = steps
                .iter()
                .map(|(key, value)| {
                    root(&[
                        "public-deployment-next-step",
                        key,
                        value.as_str().unwrap_or("missing-next-step-command"),
                    ])
                })
                .collect::<Vec<_>>();
            entries.sort();
            entries
        })
        .unwrap_or_default();
    collection_root("public-deployment-next-steps", step_roots)
}

fn public_deployment_capture_command_sequence() -> Value {
    let commands = public_deployment_capture_commands();
    let steps = [
        (
            1_u64,
            "write_capture_scaffold",
            "nebula-public-launch-package",
            "capture.json",
            true,
        ),
        (
            2_u64,
            "audit_capture",
            "capture.json",
            "capture-audit.json",
            true,
        ),
        (
            3_u64,
            "verify_capture_audit",
            "capture.json + capture-audit.json",
            "verified capture audit",
            true,
        ),
        (
            4_u64,
            "verify_capture",
            "capture.json",
            "strict public launch gate dry-run",
            true,
        ),
        (
            5_u64,
            "assemble_public_deployment",
            "capture.json",
            "nebula-public-deployment.json",
            true,
        ),
        (
            6_u64,
            "verify_public_launch",
            "nebula-public-deployment.json",
            "public-launch-ready gate result",
            true,
        ),
    ];
    let sequence = steps
        .iter()
        .map(
            |(order, command_key, required_input, produced_artifact, required_before_launch)| {
                let command = commands
                    .get(*command_key)
                    .and_then(Value::as_str)
                    .unwrap_or("missing-public-deployment-command");
                let command_step_root = root(&[
                    "public-deployment-command-step",
                    &order.to_string(),
                    command_key,
                    command,
                    required_input,
                    produced_artifact,
                    bool_str(*required_before_launch),
                ]);
                json!({
                    "order": order,
                    "command_key": command_key,
                    "command": command,
                    "required_input": required_input,
                    "produced_artifact": produced_artifact,
                    "required_before_public_launch": required_before_launch,
                    "command_step_root": command_step_root,
                })
            },
        )
        .collect::<Vec<_>>();
    json!(sequence)
}

fn public_deployment_capture_command_sequence_root(sequence: &Value) -> String {
    let step_roots = sequence
        .as_array()
        .map(|steps| {
            steps
                .iter()
                .filter_map(|step| step.get("command_step_root").and_then(Value::as_str))
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    collection_root("public-deployment-command-sequence", step_roots)
}

fn public_launch_package_manifest_root(
    manifest_id: &str,
    testnet_id: &str,
    artifact_set_root: &str,
    package_file_set_root: &str,
    public_launch_level: &str,
    public_launch_ready: bool,
    blocking_gap_count: u64,
    remediation_count: u64,
    public_launch_readiness_report_root: &str,
    public_launch_readiness_artifact_root: &str,
    no_mainnet_custody: bool,
    commands_root: &str,
    next_steps_root: &str,
    command_sequence_root: &str,
) -> String {
    root(&[
        "public-launch-package-manifest",
        CHAIN_ID,
        "1",
        VERSION,
        manifest_id,
        testnet_id,
        bool_str(true),
        bool_str(true),
        bool_str(true),
        bool_str(false),
        bool_str(false),
        "no-mainnet-custody",
        artifact_set_root,
        package_file_set_root,
        public_launch_level,
        bool_str(public_launch_ready),
        &blocking_gap_count.to_string(),
        &remediation_count.to_string(),
        public_launch_readiness_report_root,
        public_launch_readiness_artifact_root,
        bool_str(no_mainnet_custody),
        commands_root,
        next_steps_root,
        command_sequence_root,
    ])
}

fn ensure_public_deployment_capture_next_steps(
    value: &Value,
    artifact_label: &str,
    expected_next_steps: Value,
) -> Result<(), String> {
    let expected_next_steps_root = public_deployment_capture_next_steps_root(&expected_next_steps);
    ensure(
        value.get("next_steps_root").and_then(Value::as_str)
            == Some(expected_next_steps_root.as_str()),
        &format!("{artifact_label} next_steps root mismatch"),
    )?;
    ensure(
        value.get("next_steps") == Some(&expected_next_steps),
        &format!("{artifact_label} next_steps mismatch"),
    )
}

fn ensure_public_deployment_capture_command_sequence(
    value: &Value,
    artifact_label: &str,
    require_command_map: bool,
) -> Result<(), String> {
    if require_command_map {
        let expected_commands = public_deployment_capture_commands();
        let expected_commands_root = public_deployment_capture_commands_root(&expected_commands);
        ensure(
            value.get("commands") == Some(&expected_commands),
            &format!("{artifact_label} command map mismatch"),
        )?;
        ensure(
            value.get("commands_root").and_then(Value::as_str)
                == Some(expected_commands_root.as_str()),
            &format!("{artifact_label} commands root mismatch"),
        )?;
    }
    let expected_sequence = public_deployment_capture_command_sequence();
    ensure(
        value.get("command_sequence") == Some(&expected_sequence),
        &format!("{artifact_label} command sequence mismatch"),
    )?;
    let expected_sequence_root =
        public_deployment_capture_command_sequence_root(&expected_sequence);
    ensure(
        value.get("command_sequence_root").and_then(Value::as_str)
            == Some(expected_sequence_root.as_str()),
        &format!("{artifact_label} command sequence root mismatch"),
    )
}

fn public_capture_todo_artifact(summary: &TestnetSummary) -> Value {
    let capture_plan = public_deployment_capture_plan(summary);
    let readiness_report = public_launch_readiness_report_artifact(summary);
    let public_status = public_status_manifest(summary);
    let launch_bundle = public_launch_bundle(summary);
    let public_status_manifest_root = public_status["public_status_manifest_root"]
        .as_str()
        .unwrap_or("missing-public-status-manifest-root")
        .to_string();
    let public_launch_bundle_root = launch_bundle["public_launch_bundle_root"]
        .as_str()
        .unwrap_or("missing-public-launch-bundle-root")
        .to_string();
    let capture_plan_root = capture_plan["capture_plan_root"]
        .as_str()
        .unwrap_or("missing-capture-plan-root")
        .to_string();
    let capture_contract_root = capture_plan["capture_contract_root"]
        .as_str()
        .unwrap_or("missing-capture-contract-root")
        .to_string();
    let deployment_preflight_checklist_root = capture_plan["deployment_preflight"]
        ["checklist_root"]
        .as_str()
        .unwrap_or("missing-deployment-preflight-checklist-root")
        .to_string();
    let public_deployment_runbook_root = capture_plan["public_deployment_runbook_root"]
        .as_str()
        .unwrap_or("missing-public-deployment-runbook-root")
        .to_string();
    let public_deployment_runbook_step_set_root = capture_plan
        ["public_deployment_runbook_step_set_root"]
        .as_str()
        .unwrap_or("missing-public-deployment-runbook-step-set-root")
        .to_string();
    let public_launch_artifact_manifest_root = capture_plan["public_launch_artifact_manifest_root"]
        .as_str()
        .unwrap_or("missing-public-launch-artifact-manifest-root")
        .to_string();
    let public_launch_artifact_set_root = capture_plan["public_launch_artifact_set_root"]
        .as_str()
        .unwrap_or("missing-public-launch-artifact-set-root")
        .to_string();
    let public_launch_package_file_set_root =
        public_launch_package_file_set_root(&summary.manifest_id, &summary.testnet_id);
    let public_launch_readiness_artifact_root = readiness_report
        ["public_launch_readiness_artifact_root"]
        .as_str()
        .unwrap_or("missing-public-launch-readiness-artifact-root")
        .to_string();
    let external_capture_required = summary
        .public_launch_readiness
        .remediations
        .iter()
        .any(|remediation| remediation.external_capture_required);
    let deferred_repair_root_subchecks =
        public_launch_deferred_repair_root_subchecks_for_remediations(
            &summary.public_launch_readiness.remediations,
        );
    let deferred_repair_root_subcheck_root = collection_root(
        "public-capture-todo-deferred-repair-root-subchecks",
        deferred_repair_root_subchecks.clone(),
    );
    let mut todo = json!({
        "kind": "nebula-public-capture-todo",
        "schema_version": 1,
        "chain_id": CHAIN_ID,
        "version": VERSION,
        "testnet_id": &summary.testnet_id,
        "manifest_id": &summary.manifest_id,
        "public_alpha_only": true,
        "operator_fill_required": true,
        "external_capture_required": external_capture_required,
        "usable_as_public_deployment_evidence": false,
        "usable_as_mainnet_custody_approval": false,
        "custody_mode": "no-mainnet-custody",
        "public_launch_ready": summary.public_launch_readiness.public_launch_ready,
        "blocking_gaps": &summary.public_launch_readiness.blocking_gaps,
        "remediations": &summary.public_launch_readiness.remediations,
        "deferred_repair_root_subchecks": deferred_repair_root_subchecks.clone(),
        "deferred_repair_root_subcheck_count": deferred_repair_root_subchecks.len(),
        "deferred_repair_root_subcheck_root": deferred_repair_root_subcheck_root,
        "public_status_manifest_root": public_status_manifest_root,
        "public_launch_bundle_root": public_launch_bundle_root,
        "public_launch_artifact_manifest_root": public_launch_artifact_manifest_root,
        "public_launch_artifact_set_root": public_launch_artifact_set_root,
        "public_launch_package_file_set_root": public_launch_package_file_set_root,
        "public_launch_readiness_report_root": &summary.public_launch_readiness.report_root,
        "public_launch_readiness_artifact_root": public_launch_readiness_artifact_root,
        "capture_plan_root": capture_plan_root,
        "capture_contract_root": capture_contract_root,
        "deployment_preflight_checklist_root": deployment_preflight_checklist_root,
        "public_deployment_runbook_root": public_deployment_runbook_root,
        "public_deployment_runbook_step_set_root": public_deployment_runbook_step_set_root,
        "minimum_bootstrap_operator_count": MIN_PUBLIC_DEPLOYMENT_OPERATOR_COUNT,
        "minimum_observer_count": MIN_PUBLIC_DEPLOYMENT_OBSERVER_COUNT,
        "minimum_region_count": MIN_PUBLIC_DEPLOYMENT_REGION_COUNT,
        "freshness_window_ms": MAX_PUBLIC_DEPLOYMENT_FRESHNESS_MS,
        "deployment_run_id_must_match_nested_records": true,
        "package_manifest_root_source_file": "nebula-public-launch-package.json",
        "package_manifest_root_source_field": "package_manifest_root",
        "readiness_artifact_root_source_file": "nebula-public-launch-readiness-report.json",
        "readiness_artifact_root_source_field": "public_launch_readiness_artifact_root",
    });
    todo["required_capture_fields"] = json!(REQUIRED_PUBLIC_DEPLOYMENT_CAPTURE_FIELDS);
    todo["required_endpoint_fields"] = json!(REQUIRED_PUBLIC_DEPLOYMENT_ENDPOINT_FIELDS);
    todo["required_public_surfaces"] = json!(REQUIRED_PUBLIC_DEPLOYMENT_SURFACES);
    todo["required_probe_root_fields"] = json!(REQUIRED_PUBLIC_DEPLOYMENT_PROBE_ROOT_FIELDS);
    todo["required_preflight_phase_ids"] = json!(REQUIRED_PUBLIC_DEPLOYMENT_PREFLIGHT_PHASES);
    todo["required_runbook_step_ids"] = json!(PUBLIC_DEPLOYMENT_RUNBOOK_STEPS);
    todo["required_tls_endpoint_pin_roles"] = json!(PUBLIC_TLS_ENDPOINT_PIN_ROLES);
    todo["required_public_surface_probe_roles"] = json!(REQUIRED_PUBLIC_SURFACE_PROBE_ROLES);
    todo["capture_contract"] = capture_plan["capture_contract"].clone();
    todo["deployment_preflight"] = capture_plan["deployment_preflight"].clone();
    let next_steps = public_launch_deployment_attestation_next_steps();
    todo["next_steps_root"] = json!(public_deployment_capture_next_steps_root(&next_steps));
    todo["next_steps"] = next_steps;
    let commands = public_deployment_capture_commands();
    todo["commands_root"] = json!(public_deployment_capture_commands_root(&commands));
    todo["commands"] = commands;
    let command_sequence = public_deployment_capture_command_sequence();
    todo["command_sequence_root"] = json!(public_deployment_capture_command_sequence_root(
        &command_sequence
    ));
    todo["command_sequence"] = command_sequence;
    let todo_root = value_root("public-capture-todo", &todo);
    todo["public_capture_todo_root"] = json!(todo_root);
    todo
}

fn ensure_public_capture_todo_artifact(value: &Value) -> Result<(), String> {
    ensure(
        value.get("kind").and_then(Value::as_str) == Some("nebula-public-capture-todo"),
        "public capture todo kind mismatch",
    )?;
    ensure(
        value.get("schema_version").and_then(Value::as_u64) == Some(1),
        "public capture todo schema_version mismatch",
    )?;
    ensure(
        value.get("chain_id").and_then(Value::as_str) == Some(CHAIN_ID),
        "public capture todo chain_id mismatch",
    )?;
    ensure(
        value.get("version").and_then(Value::as_str) == Some(VERSION),
        "public capture todo version mismatch",
    )?;
    ensure(
        value.get("public_alpha_only").and_then(Value::as_bool) == Some(true),
        "public capture todo must remain public-alpha-only",
    )?;
    ensure(
        value.get("operator_fill_required").and_then(Value::as_bool) == Some(true),
        "public capture todo must require operator fill-in",
    )?;
    ensure(
        value
            .get("usable_as_public_deployment_evidence")
            .and_then(Value::as_bool)
            == Some(false),
        "public capture todo must not claim deployment evidence status",
    )?;
    ensure(
        value
            .get("usable_as_mainnet_custody_approval")
            .and_then(Value::as_bool)
            == Some(false),
        "public capture todo must not claim mainnet custody approval",
    )?;
    ensure(
        value.get("custody_mode").and_then(Value::as_str) == Some("no-mainnet-custody"),
        "public capture todo custody_mode mismatch",
    )?;
    ensure_public_deployment_capture_next_steps(
        value,
        "public capture todo",
        public_launch_deployment_attestation_next_steps(),
    )?;
    ensure_public_deployment_capture_command_sequence(value, "public capture todo", true)?;
    for (field, expected_len) in [
        (
            "required_capture_fields",
            REQUIRED_PUBLIC_DEPLOYMENT_CAPTURE_FIELDS.len(),
        ),
        (
            "required_endpoint_fields",
            REQUIRED_PUBLIC_DEPLOYMENT_ENDPOINT_FIELDS.len(),
        ),
        (
            "required_public_surfaces",
            REQUIRED_PUBLIC_DEPLOYMENT_SURFACES.len(),
        ),
        (
            "required_probe_root_fields",
            REQUIRED_PUBLIC_DEPLOYMENT_PROBE_ROOT_FIELDS.len(),
        ),
        (
            "required_preflight_phase_ids",
            REQUIRED_PUBLIC_DEPLOYMENT_PREFLIGHT_PHASES.len(),
        ),
        (
            "required_runbook_step_ids",
            PUBLIC_DEPLOYMENT_RUNBOOK_STEPS.len(),
        ),
        (
            "required_tls_endpoint_pin_roles",
            PUBLIC_TLS_ENDPOINT_PIN_ROLES.len(),
        ),
        (
            "required_public_surface_probe_roles",
            REQUIRED_PUBLIC_SURFACE_PROBE_ROLES.len(),
        ),
    ] {
        ensure(
            value.get(field).and_then(Value::as_array).map(Vec::len) == Some(expected_len),
            &format!("public capture todo {field} length mismatch"),
        )?;
    }
    ensure(
        value
            .get("capture_contract")
            .and_then(Value::as_object)
            .is_some(),
        "public capture todo missing capture_contract",
    )?;
    ensure(
        value
            .get("deployment_preflight")
            .and_then(Value::as_object)
            .is_some(),
        "public capture todo missing deployment_preflight",
    )?;
    let deferred_repair_root_subchecks = value
        .get("deferred_repair_root_subchecks")
        .and_then(Value::as_array)
        .ok_or_else(|| "public capture todo missing deferred_repair_root_subchecks".to_string())?;
    let deferred_repair_root_subcheck_count = value
        .get("deferred_repair_root_subcheck_count")
        .and_then(Value::as_u64)
        .ok_or_else(|| {
            "public capture todo missing deferred_repair_root_subcheck_count".to_string()
        })?;
    ensure(
        deferred_repair_root_subchecks.len() as u64 == deferred_repair_root_subcheck_count,
        "public capture todo deferred repair root subcheck count mismatch",
    )?;
    let deferred_subchecks = deferred_repair_root_subchecks
        .iter()
        .map(|subcheck| {
            subcheck.as_str().map(str::to_string).ok_or_else(|| {
                "public capture todo deferred repair root subcheck must be a string".to_string()
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    let expected_deferred_root = collection_root(
        "public-capture-todo-deferred-repair-root-subchecks",
        deferred_subchecks,
    );
    ensure(
        value
            .get("deferred_repair_root_subcheck_root")
            .and_then(Value::as_str)
            == Some(expected_deferred_root.as_str()),
        "public capture todo deferred repair root subcheck root mismatch",
    )?;
    let mut rootless = value.clone();
    if let Some(map) = rootless.as_object_mut() {
        map.remove("public_capture_todo_root");
    }
    let expected_root = value_root("public-capture-todo", &rootless);
    ensure(
        value
            .get("public_capture_todo_root")
            .and_then(Value::as_str)
            == Some(expected_root.as_str()),
        "public capture todo root mismatch",
    )
}

fn write_public_capture_todo(path: &str, summary: &TestnetSummary) -> Result<(), String> {
    ensure_local_json_path(path, "--write-public-capture-todo")?;
    let todo = public_capture_todo_artifact(summary);
    ensure_public_capture_todo_artifact(&todo)?;
    let encoded = serde_json::to_string_pretty(&todo)
        .map_err(|error| format!("failed to encode public capture todo json: {error}"))?;
    fs::write(path, format!("{encoded}\n"))
        .map_err(|error| format!("failed to write public capture todo: {error}"))
}

