fn write_public_launch_package(path: &str, summary: &TestnetSummary) -> Result<(), String> {
    ensure_local_output_dir_path(path, "--write-public-launch-package")?;
    let dir = PathBuf::from(path);
    fs::create_dir_all(&dir)
        .map_err(|error| format!("failed to create public launch package directory: {error}"))?;

    let mut package_records = Vec::new();
    for (index, (artifact_id, file_name, root_field)) in
        PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.iter().enumerate()
    {
        let value = public_launch_package_artifact_value(artifact_id, summary)?;
        write_json_artifact(&dir.join(file_name), &value, artifact_id)?;
        let artifact_root = value
            .get(*root_field)
            .and_then(Value::as_str)
            .filter(|candidate| is_hex_root(candidate))
            .map(str::to_string)
            .unwrap_or_else(|| public_launch_package_value_root(artifact_id, &value));
        let required_before_public_capture =
            public_launch_package_required_before_capture(artifact_id);
        let operator_fill_required = public_launch_package_operator_fill_required(artifact_id);
        let record_root = public_launch_package_artifact_record_root(
            &summary.manifest_id,
            artifact_id,
            file_name,
            root_field,
            &artifact_root,
            index + 1,
            required_before_public_capture,
            operator_fill_required,
        );
        package_records.push(json!({
            "order": index + 1,
            "artifact_id": artifact_id,
            "file_name": file_name,
            "root_field": root_field,
            "root": artifact_root,
            "required_before_public_capture": required_before_public_capture,
            "operator_fill_required": operator_fill_required,
            "usable_as_public_deployment_evidence": false,
            "usable_as_mainnet_custody_approval": false,
            "artifact_record_root": record_root,
        }));
    }

    let artifact_set_root = collection_root(
        "public-launch-package-artifacts",
        package_records
            .iter()
            .map(|record| {
                record["artifact_record_root"]
                    .as_str()
                    .unwrap_or("missing-artifact-record-root")
                    .to_string()
            })
            .collect(),
    );
    let public_launch_readiness_artifact_root = package_records
        .iter()
        .find(|record| record["artifact_id"].as_str() == Some("public-launch-readiness-report"))
        .and_then(|record| record["root"].as_str())
        .unwrap_or("missing-public-launch-readiness-artifact-root")
        .to_string();
    let public_launch_level = summary.public_launch_readiness.level.clone();
    let public_launch_ready = summary.public_launch_readiness.public_launch_ready;
    let blocking_gap_count = summary.public_launch_readiness.blocking_gaps.len() as u64;
    let remediation_count = summary.public_launch_readiness.remediations.len() as u64;
    let package_file_set_root =
        public_launch_package_file_set_root(&summary.manifest_id, &summary.testnet_id);
    let next_steps = public_launch_package_next_steps();
    let next_steps_root = public_deployment_capture_next_steps_root(&next_steps);
    let command_sequence = public_deployment_capture_command_sequence();
    let command_sequence_root = public_deployment_capture_command_sequence_root(&command_sequence);
    let commands = public_deployment_capture_commands();
    let commands_root = public_deployment_capture_commands_root(&commands);
    let package_manifest_root = public_launch_package_manifest_root(
        &summary.manifest_id,
        &summary.testnet_id,
        &artifact_set_root,
        &package_file_set_root,
        &public_launch_level,
        public_launch_ready,
        blocking_gap_count,
        remediation_count,
        &summary.public_launch_readiness.report_root,
        &public_launch_readiness_artifact_root,
        summary.acceptance.no_mainnet_custody,
        &commands_root,
        &next_steps_root,
        &command_sequence_root,
    );
    let manifest = json!({
        "kind": "nebula-public-launch-package",
        "schema_version": 1,
        "chain_id": CHAIN_ID,
        "version": VERSION,
        "testnet_id": &summary.testnet_id,
        "manifest_id": &summary.manifest_id,
        "public_alpha_only": true,
        "package_only": true,
        "operator_fill_required": true,
        "usable_as_public_deployment_evidence": false,
        "usable_as_mainnet_custody_approval": false,
        "custody_mode": "no-mainnet-custody",
        "public_launch_level": public_launch_level,
        "public_launch_ready": public_launch_ready,
        "blocking_gap_count": blocking_gap_count,
        "remediation_count": remediation_count,
        "public_launch_readiness_report_root": &summary.public_launch_readiness.report_root,
        "public_launch_readiness_artifact_root": public_launch_readiness_artifact_root,
        "artifact_count": package_records.len(),
        "artifacts": package_records,
        "artifact_set_root": artifact_set_root,
        "package_file_set_root": package_file_set_root,
        "package_manifest_root": package_manifest_root,
        "commands_root": commands_root,
        "commands": commands,
        "next_steps_root": next_steps_root,
        "next_steps": next_steps,
        "command_sequence_root": command_sequence_root,
        "command_sequence": command_sequence
    });
    write_json_artifact(
        &dir.join("nebula-public-launch-package.json"),
        &manifest,
        "public-launch-package",
    )?;
    Ok(())
}

fn verify_public_launch_package(path: &str, summary: &TestnetSummary) -> Result<(), String> {
    ensure_local_output_dir_path(path, "--verify-public-launch-package")?;
    let dir = PathBuf::from(path);
    ensure(
        dir.is_dir(),
        "--verify-public-launch-package must point to an existing directory",
    )?;
    ensure_public_launch_package_exact_file_set(&dir)?;
    let manifest_path = dir.join("nebula-public-launch-package.json");
    let manifest = read_json_file(&manifest_path, "public launch package manifest")?;
    ensure(
        required_str(&manifest, "kind")? == "nebula-public-launch-package",
        "public launch package manifest has the wrong kind",
    )?;
    ensure(
        required_str(&manifest, "chain_id")? == CHAIN_ID,
        "public launch package chain_id mismatch",
    )?;
    ensure(
        required_u64(&manifest, "schema_version")? == 1,
        "public launch package schema_version mismatch",
    )?;
    ensure(
        required_str(&manifest, "version")? == VERSION,
        "public launch package version mismatch",
    )?;
    ensure(
        required_str(&manifest, "manifest_id")? == summary.manifest_id,
        "public launch package manifest_id does not match this run",
    )?;
    ensure(
        required_str(&manifest, "testnet_id")? == summary.testnet_id,
        "public launch package testnet_id does not match this run",
    )?;
    ensure(
        required_bool(&manifest, "public_alpha_only")? == true,
        "public launch package must stay public-alpha only",
    )?;
    ensure(
        required_bool(&manifest, "package_only")? == true,
        "public launch package must be marked package_only",
    )?;
    ensure(
        required_bool(&manifest, "operator_fill_required")? == true,
        "public launch package must require operator-filled deployment evidence",
    )?;
    ensure(
        required_bool(&manifest, "usable_as_public_deployment_evidence")? == false,
        "public launch package must not claim to be deployment evidence",
    )?;
    ensure(
        required_bool(&manifest, "usable_as_mainnet_custody_approval")? == false,
        "public launch package must not claim mainnet custody approval",
    )?;
    ensure(
        required_str(&manifest, "custody_mode")? == "no-mainnet-custody",
        "public launch package custody_mode mismatch",
    )?;
    ensure_public_deployment_capture_command_sequence(&manifest, "public launch package", true)?;
    ensure_public_deployment_capture_next_steps(
        &manifest,
        "public launch package",
        public_launch_package_next_steps(),
    )?;
    ensure(
        required_str(&manifest, "public_launch_level")? == summary.public_launch_readiness.level,
        "public launch package launch level mismatch",
    )?;
    ensure(
        required_bool(&manifest, "public_launch_ready")?
            == summary.public_launch_readiness.public_launch_ready,
        "public launch package launch readiness mismatch",
    )?;
    ensure(
        required_u64(&manifest, "blocking_gap_count")?
            == summary.public_launch_readiness.blocking_gaps.len() as u64,
        "public launch package blocking gap count mismatch",
    )?;
    ensure(
        required_u64(&manifest, "remediation_count")?
            == summary.public_launch_readiness.remediations.len() as u64,
        "public launch package remediation count mismatch",
    )?;
    ensure(
        required_root(&manifest, "public_launch_readiness_report_root")?
            == summary.public_launch_readiness.report_root,
        "public launch package readiness report root mismatch",
    )?;
    let expected_readiness_report = public_launch_readiness_report_artifact(summary);
    let expected_readiness_artifact_root = required_root(
        &expected_readiness_report,
        "public_launch_readiness_artifact_root",
    )?;
    ensure(
        required_root(&manifest, "public_launch_readiness_artifact_root")?
            == expected_readiness_artifact_root,
        "public launch package readiness artifact root mismatch",
    )?;
    let records = manifest["artifacts"]
        .as_array()
        .ok_or_else(|| "public launch package missing artifacts".to_string())?;
    ensure(
        records.len() == PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.len(),
        "public launch package artifact count mismatch",
    )?;
    ensure(
        required_u64(&manifest, "artifact_count")? == PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.len() as u64,
        "public launch package artifact_count mismatch",
    )?;

    let mut record_roots = Vec::new();
    for (index, (artifact_id, file_name, root_field)) in
        PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.iter().enumerate()
    {
        let record = records
            .get(index)
            .ok_or_else(|| "public launch package missing artifact record".to_string())?;
        ensure(
            record["order"].as_u64() == Some((index + 1) as u64),
            "public launch package artifact order mismatch",
        )?;
        ensure(
            record["artifact_id"].as_str() == Some(*artifact_id),
            "public launch package artifact id mismatch",
        )?;
        ensure(
            record["file_name"].as_str() == Some(*file_name),
            "public launch package artifact filename mismatch",
        )?;
        ensure(
            record["root_field"].as_str() == Some(*root_field),
            "public launch package artifact root_field mismatch",
        )?;
        ensure(
            record["required_before_public_capture"].as_bool()
                == Some(public_launch_package_required_before_capture(artifact_id)),
            "public launch package artifact capture requirement mismatch",
        )?;
        ensure(
            record["operator_fill_required"].as_bool()
                == Some(public_launch_package_operator_fill_required(artifact_id)),
            "public launch package artifact operator-fill requirement mismatch",
        )?;
        ensure(
            record["usable_as_public_deployment_evidence"].as_bool() == Some(false),
            "public launch package artifact must not claim deployment evidence status",
        )?;
        ensure(
            record["usable_as_mainnet_custody_approval"].as_bool() == Some(false),
            "public launch package artifact must not claim custody approval status",
        )?;
        let artifact = read_json_file(&dir.join(file_name), artifact_id)?;
        let expected_artifact = public_launch_package_artifact_value(artifact_id, summary)?;
        let expected_root = expected_artifact
            .get(*root_field)
            .and_then(Value::as_str)
            .filter(|candidate| is_hex_root(candidate))
            .map(str::to_string)
            .unwrap_or_else(|| public_launch_package_value_root(artifact_id, &expected_artifact));
        ensure_public_launch_package_artifact_current_bindings(
            artifact_id,
            file_name,
            &artifact,
            &expected_artifact,
        )?;
        ensure(
            artifact == expected_artifact,
            &format!("public launch package artifact {file_name} does not match this run"),
        )?;
        ensure(
            record["root"].as_str() == Some(expected_root.as_str()),
            "public launch package artifact root mismatch",
        )?;
        let expected_record_root = public_launch_package_artifact_record_root(
            &summary.manifest_id,
            artifact_id,
            file_name,
            root_field,
            &expected_root,
            index + 1,
            public_launch_package_required_before_capture(artifact_id),
            public_launch_package_operator_fill_required(artifact_id),
        );
        ensure(
            record["artifact_record_root"].as_str() == Some(expected_record_root.as_str()),
            "public launch package artifact record root mismatch",
        )?;
        record_roots.push(expected_record_root);
    }

    let expected_artifact_set_root =
        collection_root("public-launch-package-artifacts", record_roots);
    ensure(
        required_root(&manifest, "artifact_set_root")? == expected_artifact_set_root,
        "public launch package artifact_set_root mismatch",
    )?;
    let expected_package_file_set_root =
        public_launch_package_file_set_root(&summary.manifest_id, &summary.testnet_id);
    ensure(
        required_root(&manifest, "package_file_set_root")? == expected_package_file_set_root,
        "public launch package file_set_root mismatch",
    )?;
    let expected_next_steps = public_deployment_capture_next_steps(
        "Run write_capture_scaffold, then replace capture.json placeholders with captured public endpoint, TLS, probe, observer, operator-registry, freshness, preflight receipt, runbook receipt, and evidence-root evidence.",
        false,
    );
    let expected_next_steps_root = public_deployment_capture_next_steps_root(&expected_next_steps);
    let expected_command_sequence = public_deployment_capture_command_sequence();
    let expected_command_sequence_root =
        public_deployment_capture_command_sequence_root(&expected_command_sequence);
    let expected_commands = public_deployment_capture_commands();
    let expected_commands_root = public_deployment_capture_commands_root(&expected_commands);
    let expected_package_manifest_root = public_launch_package_manifest_root(
        &summary.manifest_id,
        &summary.testnet_id,
        &expected_artifact_set_root,
        &expected_package_file_set_root,
        &summary.public_launch_readiness.level,
        summary.public_launch_readiness.public_launch_ready,
        summary.public_launch_readiness.blocking_gaps.len() as u64,
        summary.public_launch_readiness.remediations.len() as u64,
        &summary.public_launch_readiness.report_root,
        &expected_readiness_artifact_root,
        summary.acceptance.no_mainnet_custody,
        &expected_commands_root,
        &expected_next_steps_root,
        &expected_command_sequence_root,
    );
    ensure(
        required_root(&manifest, "package_manifest_root")? == expected_package_manifest_root,
        "public launch package manifest root mismatch",
    )
}

