fn public_testnet_certification_artifact(
    summary: &TestnetSummary,
    package_manifest: &Value,
    launch_report: &Value,
) -> Result<Value, String> {
    ensure_public_launch_readiness_report_artifact_safe(launch_report)?;
    let expected_launch_report = public_launch_readiness_report_artifact(summary);
    ensure(
        launch_report == &expected_launch_report,
        "public testnet certification launch report does not match this run",
    )?;
    ensure_public_testnet_certification_package_manifest_current(package_manifest, summary)?;
    let package_file_set_root = required_root(package_manifest, "package_file_set_root")?;
    let package_manifest_root = required_root(package_manifest, "package_manifest_root")?;
    let package_release_approval_template_root =
        public_launch_package_artifact_root(package_manifest, "release-approval-template")?;
    let package_release_authority_registry_template_root = public_launch_package_artifact_root(
        package_manifest,
        "release-authority-registry-template",
    )?;
    let package_public_deployment_evidence_template_root = public_launch_package_artifact_root(
        package_manifest,
        "public-deployment-evidence-template",
    )?;
    let package_public_deployment_capture_plan_root =
        public_launch_package_artifact_root(package_manifest, "public-deployment-capture-plan")?;
    let package_public_capture_todo_root =
        public_launch_package_artifact_root(package_manifest, "public-capture-todo")?;
    let public_launch_readiness_artifact_root =
        required_root(launch_report, "public_launch_readiness_artifact_root")?;
    let readiness_public_deployment_evidence_root =
        required_str(launch_report, "public_deployment_evidence_root")?.to_string();
    let public_deployment_evidence_root = summary
        .public_deployment
        .evidence_root
        .as_deref()
        .unwrap_or("missing-public-deployment-evidence")
        .to_string();
    let public_deployment_evidence_root_bound_to_report =
        public_deployment_evidence_root == readiness_public_deployment_evidence_root;
    let release_approval_template = release_approval_template_for_summary(summary);
    let release_approval_template_root =
        value_root("release-approval-template", &release_approval_template);
    let release_authority_registry_template = release_authority_registry_template();
    let release_authority_registry_template_root = value_root(
        "release-authority-registry-template",
        &release_authority_registry_template,
    );
    let public_deployment_evidence_template = public_deployment_evidence_template(summary);
    let public_deployment_evidence_template_root =
        required_root(&public_deployment_evidence_template, "template_root")?;
    let public_deployment_capture_plan = public_deployment_capture_plan(summary);
    let public_deployment_capture_plan_root =
        required_root(&public_deployment_capture_plan, "capture_plan_root")?;
    let public_deployment_capture_contract_root =
        required_root(&public_deployment_capture_plan, "capture_contract_root")?;
    let public_capture_todo = public_capture_todo_artifact(summary);
    let public_capture_todo_root = required_root(&public_capture_todo, "public_capture_todo_root")?;
    let deferred_repair_root_subchecks =
        public_launch_deferred_repair_root_subchecks_for_remediations(
            &summary.public_launch_readiness.remediations,
        );
    let deferred_repair_root_subcheck_root = collection_root(
        "public-capture-todo-deferred-repair-root-subchecks",
        deferred_repair_root_subchecks.clone(),
    );
    let capture_todo_deferred_repair_root_subcheck_root =
        required_root(&public_capture_todo, "deferred_repair_root_subcheck_root")?;
    let deferred_repair_root_subcheck_root_bound_to_capture_todo =
        deferred_repair_root_subcheck_root == capture_todo_deferred_repair_root_subcheck_root;
    let public_launch_package_handoff_root = public_launch_package_handoff_root_from_roots(
        &package_file_set_root,
        &package_manifest_root,
        &public_launch_readiness_artifact_root,
        &release_approval_template_root,
        &release_authority_registry_template_root,
    );
    let release_approval_template_root_bound_to_package =
        release_approval_template_root == package_release_approval_template_root;
    let release_authority_registry_template_root_bound_to_package =
        release_authority_registry_template_root
            == package_release_authority_registry_template_root;
    let public_deployment_evidence_template_root_bound_to_package =
        public_deployment_evidence_template_root
            == package_public_deployment_evidence_template_root;
    let public_deployment_capture_plan_root_bound_to_package =
        public_deployment_capture_plan_root == package_public_deployment_capture_plan_root;
    let public_capture_todo_root_bound_to_package =
        public_capture_todo_root == package_public_capture_todo_root;
    let external_capture_required = summary
        .public_launch_readiness
        .remediations
        .iter()
        .any(|remediation| remediation.external_capture_required);
    let next_steps = public_testnet_certification_next_steps();
    let next_steps_root = public_deployment_capture_next_steps_root(&next_steps);
    let command_sequence = public_deployment_capture_command_sequence();
    let command_sequence_root = public_deployment_capture_command_sequence_root(&command_sequence);
    let commands = public_deployment_capture_commands();
    let commands_root = public_deployment_capture_commands_root(&commands);
    let certification_file_set_root =
        public_testnet_certification_file_set_root(&summary.manifest_id, &summary.testnet_id);
    let mut certification = json!({
        "kind": "nebula-public-testnet-certification",
        "schema_version": 1,
        "chain_id": CHAIN_ID,
        "version": VERSION,
        "testnet_id": &summary.testnet_id,
        "manifest_id": &summary.manifest_id,
        "custody_mode": "no-mainnet-custody",
        "public_alpha_only": true,
        "local_operator_only": true,
        "usable_as_public_deployment_evidence": false,
        "usable_as_mainnet_custody_approval": false,
        "local_testnet_ready": summary.acceptance.testnet_ready,
        "public_launch_ready": summary.public_launch_readiness.public_launch_ready,
        "public_launch_level": &summary.public_launch_readiness.level,
        "public_deployment_attestation_available": summary.public_deployment.passed,
        "public_deployment_evidence_root": public_deployment_evidence_root,
        "readiness_public_deployment_evidence_root": readiness_public_deployment_evidence_root,
        "public_deployment_evidence_root_bound_to_report": public_deployment_evidence_root_bound_to_report,
        "blocking_gap_count": summary.public_launch_readiness.blocking_gaps.len(),
        "blocking_gaps": &summary.public_launch_readiness.blocking_gaps,
        "remediation_count": summary.public_launch_readiness.remediations.len(),
        "remediations": &summary.public_launch_readiness.remediations,
        "deferred_repair_root_subcheck_count": deferred_repair_root_subchecks.len(),
        "deferred_repair_root_subchecks": deferred_repair_root_subchecks,
        "deferred_repair_root_subcheck_root": deferred_repair_root_subcheck_root,
        "capture_todo_deferred_repair_root_subcheck_root": capture_todo_deferred_repair_root_subcheck_root,
        "deferred_repair_root_subcheck_root_bound_to_capture_todo": deferred_repair_root_subcheck_root_bound_to_capture_todo,
        "external_capture_required": external_capture_required,
        "certification_file_set_root": certification_file_set_root,
        "package_verified": true,
        "public_launch_package_dir": "nebula-public-launch-package",
        "public_launch_package_file_set_root": package_file_set_root,
        "public_launch_package_handoff_root": public_launch_package_handoff_root,
        "public_launch_package_manifest_root": package_manifest_root,
        "public_launch_readiness_report_file": "nebula-public-launch-readiness-report.json",
        "public_launch_readiness_report_root": &summary.public_launch_readiness.report_root,
        "public_launch_readiness_artifact_root": public_launch_readiness_artifact_root,
        "release_approval_template_file": "nebula-release-approval-template.json",
        "release_approval_template_root": release_approval_template_root,
        "package_release_approval_template_root": package_release_approval_template_root,
        "release_approval_template_root_bound_to_package": release_approval_template_root_bound_to_package,
        "release_authority_registry_template_file": "nebula-release-authority-registry-template.json",
        "release_authority_registry_template_root": release_authority_registry_template_root,
        "package_release_authority_registry_template_root": package_release_authority_registry_template_root,
        "release_authority_registry_template_root_bound_to_package": release_authority_registry_template_root_bound_to_package,
        "public_deployment_evidence_template_file": "nebula-public-launch-package/nebula-public-deployment-template.json",
        "public_deployment_evidence_template_root": public_deployment_evidence_template_root,
        "package_public_deployment_evidence_template_root": package_public_deployment_evidence_template_root,
        "public_deployment_evidence_template_root_bound_to_package": public_deployment_evidence_template_root_bound_to_package,
        "public_deployment_capture_plan_file": "nebula-public-launch-package/nebula-public-deployment-capture-plan.json",
        "public_deployment_capture_plan_root": public_deployment_capture_plan_root,
        "package_public_deployment_capture_plan_root": package_public_deployment_capture_plan_root,
        "public_deployment_capture_plan_root_bound_to_package": public_deployment_capture_plan_root_bound_to_package,
        "public_deployment_capture_contract_root": public_deployment_capture_contract_root,
        "public_capture_todo_file": "nebula-public-launch-package/nebula-public-capture-todo.json",
        "public_capture_todo_root": public_capture_todo_root,
        "package_public_capture_todo_root": package_public_capture_todo_root,
        "public_capture_todo_root_bound_to_package": public_capture_todo_root_bound_to_package,
        "commands_root": commands_root,
        "commands": commands,
        "next_steps_root": next_steps_root,
        "next_steps": next_steps,
        "command_sequence_root": command_sequence_root,
        "command_sequence": command_sequence
    });
    let certification_root = value_root("public-testnet-certification", &certification);
    certification["certification_root"] = json!(certification_root);
    Ok(certification)
}

fn ensure_public_testnet_certification_package_manifest_current(
    package_manifest: &Value,
    summary: &TestnetSummary,
) -> Result<(), String> {
    ensure(
        required_str(package_manifest, "kind")? == "nebula-public-launch-package",
        "public testnet certification package manifest has the wrong kind",
    )?;
    ensure(
        required_u64(package_manifest, "schema_version")? == 1,
        "public testnet certification package schema_version mismatch",
    )?;
    ensure(
        required_str(package_manifest, "chain_id")? == CHAIN_ID,
        "public testnet certification package chain_id mismatch",
    )?;
    ensure(
        required_str(package_manifest, "version")? == VERSION,
        "public testnet certification package version mismatch",
    )?;
    ensure(
        required_str(package_manifest, "manifest_id")? == summary.manifest_id,
        "public testnet certification package manifest_id does not match this run",
    )?;
    ensure(
        required_str(package_manifest, "testnet_id")? == summary.testnet_id,
        "public testnet certification package testnet_id does not match this run",
    )?;
    ensure(
        required_bool(package_manifest, "public_alpha_only")?,
        "public testnet certification package must stay public-alpha only",
    )?;
    ensure(
        required_bool(package_manifest, "package_only")?,
        "public testnet certification package must be marked package_only",
    )?;
    ensure(
        required_bool(package_manifest, "operator_fill_required")?,
        "public testnet certification package must require operator-filled deployment evidence",
    )?;
    ensure(
        !required_bool(package_manifest, "usable_as_public_deployment_evidence")?,
        "public testnet certification package must not claim deployment evidence status",
    )?;
    ensure(
        !required_bool(package_manifest, "usable_as_mainnet_custody_approval")?,
        "public testnet certification package must not claim mainnet custody approval",
    )?;
    ensure(
        required_str(package_manifest, "custody_mode")? == "no-mainnet-custody",
        "public testnet certification package custody_mode mismatch",
    )?;
    ensure_public_deployment_capture_command_sequence(
        package_manifest,
        "public testnet certification package",
        true,
    )?;
    ensure_public_deployment_capture_next_steps(
        package_manifest,
        "public testnet certification package",
        public_launch_package_next_steps(),
    )?;
    ensure(
        required_str(package_manifest, "public_launch_level")?
            == summary.public_launch_readiness.level,
        "public testnet certification package launch level mismatch",
    )?;
    ensure(
        required_bool(package_manifest, "public_launch_ready")?
            == summary.public_launch_readiness.public_launch_ready,
        "public testnet certification package launch readiness mismatch",
    )?;
    ensure(
        required_u64(package_manifest, "blocking_gap_count")?
            == summary.public_launch_readiness.blocking_gaps.len() as u64,
        "public testnet certification package blocking gap count mismatch",
    )?;
    ensure(
        required_u64(package_manifest, "remediation_count")?
            == summary.public_launch_readiness.remediations.len() as u64,
        "public testnet certification package remediation count mismatch",
    )?;
    ensure(
        required_root(package_manifest, "public_launch_readiness_report_root")?
            == summary.public_launch_readiness.report_root,
        "public testnet certification package readiness report root mismatch",
    )?;
    let expected_readiness_report = public_launch_readiness_report_artifact(summary);
    let expected_readiness_artifact_root = required_root(
        &expected_readiness_report,
        "public_launch_readiness_artifact_root",
    )?;
    ensure(
        required_root(package_manifest, "public_launch_readiness_artifact_root")?
            == expected_readiness_artifact_root,
        "public testnet certification package readiness artifact root mismatch",
    )?;
    let records = package_manifest
        .get("artifacts")
        .and_then(Value::as_array)
        .ok_or_else(|| "public testnet certification package missing artifacts".to_string())?;
    ensure(
        records.len() == PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.len(),
        "public testnet certification package artifact count mismatch",
    )?;
    ensure(
        required_u64(package_manifest, "artifact_count")?
            == PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.len() as u64,
        "public testnet certification package artifact_count mismatch",
    )?;
    let mut record_roots = Vec::new();
    for (index, (artifact_id, file_name, root_field)) in
        PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.iter().enumerate()
    {
        let record = records.get(index).ok_or_else(|| {
            "public testnet certification package missing artifact record".to_string()
        })?;
        ensure(
            record.get("order").and_then(Value::as_u64) == Some((index + 1) as u64),
            "public testnet certification package artifact order mismatch",
        )?;
        ensure(
            record.get("artifact_id").and_then(Value::as_str) == Some(*artifact_id),
            "public testnet certification package artifact id mismatch",
        )?;
        ensure(
            record.get("file_name").and_then(Value::as_str) == Some(*file_name),
            "public testnet certification package artifact filename mismatch",
        )?;
        ensure(
            record.get("root_field").and_then(Value::as_str) == Some(*root_field),
            "public testnet certification package artifact root_field mismatch",
        )?;
        ensure(
            record
                .get("required_before_public_capture")
                .and_then(Value::as_bool)
                == Some(public_launch_package_required_before_capture(artifact_id)),
            "public testnet certification package artifact capture requirement mismatch",
        )?;
        ensure(
            record
                .get("operator_fill_required")
                .and_then(Value::as_bool)
                == Some(public_launch_package_operator_fill_required(artifact_id)),
            "public testnet certification package artifact operator-fill requirement mismatch",
        )?;
        ensure(
            record
                .get("usable_as_public_deployment_evidence")
                .and_then(Value::as_bool)
                == Some(false),
            "public testnet certification package artifact must not claim deployment evidence status",
        )?;
        ensure(
            record
                .get("usable_as_mainnet_custody_approval")
                .and_then(Value::as_bool)
                == Some(false),
            "public testnet certification package artifact must not claim custody approval status",
        )?;
        let expected_artifact = public_launch_package_artifact_value(artifact_id, summary)?;
        let expected_root = expected_artifact
            .get(*root_field)
            .and_then(Value::as_str)
            .filter(|candidate| is_hex_root(candidate))
            .map(str::to_string)
            .unwrap_or_else(|| public_launch_package_value_root(artifact_id, &expected_artifact));
        ensure(
            record.get("root").and_then(Value::as_str) == Some(expected_root.as_str()),
            "public testnet certification package artifact root mismatch",
        )?;
        let expected_record_root = public_launch_package_artifact_record_root(
            &summary.manifest_id,
            artifact_id,
            file_name,
            root_field,
            &expected_root,
            index + 1,
            public_launch_package_required_before_capture(artifact_id),
            public_launch_package_operator_fill_required(artifact_id),
        );
        ensure(
            record.get("artifact_record_root").and_then(Value::as_str)
                == Some(expected_record_root.as_str()),
            "public testnet certification package artifact record root mismatch",
        )?;
        record_roots.push(expected_record_root);
    }
    let expected_artifact_set_root =
        collection_root("public-launch-package-artifacts", record_roots);
    ensure(
        required_root(package_manifest, "artifact_set_root")? == expected_artifact_set_root,
        "public testnet certification package artifact_set_root mismatch",
    )?;
    let expected_package_file_set_root =
        public_launch_package_file_set_root(&summary.manifest_id, &summary.testnet_id);
    ensure(
        required_root(package_manifest, "package_file_set_root")? == expected_package_file_set_root,
        "public testnet certification package file_set_root mismatch",
    )?;
    let expected_commands = public_deployment_capture_commands();
    let expected_commands_root = public_deployment_capture_commands_root(&expected_commands);
    let expected_next_steps = public_launch_package_next_steps();
    let expected_next_steps_root = public_deployment_capture_next_steps_root(&expected_next_steps);
    let expected_command_sequence = public_deployment_capture_command_sequence();
    let expected_command_sequence_root =
        public_deployment_capture_command_sequence_root(&expected_command_sequence);
    let expected_package_manifest_root = public_launch_package_manifest_root(
        &summary.manifest_id,
        &summary.testnet_id,
        &expected_artifact_set_root,
        &expected_package_file_set_root,
        &summary.public_launch_readiness.level,
        summary.public_launch_readiness.public_launch_ready,
        summary.public_launch_readiness.blocking_gaps.len() as u64,
        summary.public_launch_readiness.remediations.len() as u64,
        &summary.public_launch_readiness.report_root,
        &expected_readiness_artifact_root,
        summary.acceptance.no_mainnet_custody,
        &expected_commands_root,
        &expected_next_steps_root,
        &expected_command_sequence_root,
    );
    ensure(
        required_root(package_manifest, "package_manifest_root")? == expected_package_manifest_root,
        "public testnet certification package manifest root mismatch",
    )
}

fn public_launch_package_artifact_root(
    package_manifest: &Value,
    artifact_id: &str,
) -> Result<String, String> {
    let artifacts = package_manifest
        .get("artifacts")
        .and_then(Value::as_array)
        .ok_or_else(|| "public launch package manifest missing artifacts".to_string())?;
    let record = artifacts
        .iter()
        .find(|record| record.get("artifact_id").and_then(Value::as_str) == Some(artifact_id))
        .ok_or_else(|| {
            format!("public launch package manifest missing artifact '{artifact_id}'")
        })?;
    let artifact_root = record
        .get("root")
        .and_then(Value::as_str)
        .ok_or_else(|| format!("public launch package artifact '{artifact_id}' missing root"))?;
    ensure(
        is_hex_root(artifact_root),
        &format!(
            "public launch package artifact '{artifact_id}' root must be a 64-character hex root"
        ),
    )?;
    Ok(artifact_root.to_string())
}

fn ensure_public_testnet_certification_exact_file_set(dir: &PathBuf) -> Result<(), String> {
    let expected_files = public_testnet_certification_expected_file_names();
    let expected_dirs = public_testnet_certification_expected_dir_names();

    let entries = fs::read_dir(dir).map_err(|error| {
        format!("failed to list public testnet certification directory: {error}")
    })?;
    let mut actual_files = BTreeSet::new();
    let mut actual_dirs = BTreeSet::new();
    for entry in entries {
        let entry = entry.map_err(|error| {
            format!("failed to inspect public testnet certification entry: {error}")
        })?;
        let path = entry.path();
        let file_name = entry
            .file_name()
            .into_string()
            .map_err(|_| "public testnet certification contains non-utf8 entry".to_string())?;
        if path.is_file() {
            ensure(
                expected_files.iter().any(|expected| *expected == file_name),
                &format!("public testnet certification contains unexpected file '{file_name}'"),
            )?;
            actual_files.insert(file_name);
        } else if path.is_dir() {
            ensure(
                expected_dirs.iter().any(|expected| *expected == file_name),
                &format!(
                    "public testnet certification contains unexpected directory '{file_name}'"
                ),
            )?;
            actual_dirs.insert(file_name);
        } else {
            return Err(format!(
                "public testnet certification contains unexpected entry '{file_name}'"
            ));
        }
    }

    for expected in expected_files {
        ensure(
            actual_files.contains(expected),
            &format!("public testnet certification missing expected file '{expected}'"),
        )?;
    }
    for expected in expected_dirs {
        ensure(
            actual_dirs.contains(expected),
            &format!("public testnet certification missing expected directory '{expected}'"),
        )?;
    }
    Ok(())
}

fn public_testnet_certification_expected_file_names() -> Vec<&'static str> {
    vec![
        "nebula-public-launch-readiness-report.json",
        "nebula-public-testnet-certification.json",
        "nebula-release-approval-template.json",
        "nebula-release-authority-registry-template.json",
    ]
}

fn public_testnet_certification_expected_dir_names() -> Vec<&'static str> {
    vec!["nebula-public-launch-package"]
}

fn public_testnet_certification_file_set_root(manifest_id: &str, testnet_id: &str) -> String {
    let mut entry_roots = Vec::new();
    for (index, file_name) in public_testnet_certification_expected_file_names()
        .iter()
        .enumerate()
    {
        entry_roots.push(root(&[
            "public-testnet-certification-entry",
            CHAIN_ID,
            manifest_id,
            testnet_id,
            "file",
            file_name,
            &(index + 1).to_string(),
        ]));
    }
    let file_count = entry_roots.len();
    for (index, dir_name) in public_testnet_certification_expected_dir_names()
        .iter()
        .enumerate()
    {
        entry_roots.push(root(&[
            "public-testnet-certification-entry",
            CHAIN_ID,
            manifest_id,
            testnet_id,
            "directory",
            dir_name,
            &(file_count + index + 1).to_string(),
        ]));
    }
    collection_root("public-testnet-certification-file-set", entry_roots)
}

fn ensure_public_launch_package_exact_file_set(dir: &PathBuf) -> Result<(), String> {
    let expected_files = public_launch_package_expected_file_names();

    let entries = fs::read_dir(dir)
        .map_err(|error| format!("failed to list public launch package directory: {error}"))?;
    let mut actual_files = BTreeSet::new();
    for entry in entries {
        let entry = entry
            .map_err(|error| format!("failed to inspect public launch package entry: {error}"))?;
        let path = entry.path();
        let file_name = entry
            .file_name()
            .into_string()
            .map_err(|_| "public launch package contains non-utf8 filename".to_string())?;
        ensure(
            path.is_file(),
            &format!("public launch package contains unexpected entry '{file_name}'"),
        )?;
        ensure(
            expected_files.iter().any(|expected| *expected == file_name),
            &format!("public launch package contains unexpected file '{file_name}'"),
        )?;
        actual_files.insert(file_name);
    }

    for expected in expected_files {
        ensure(
            actual_files.contains(expected),
            &format!("public launch package missing expected file '{expected}'"),
        )?;
    }
    Ok(())
}

