fn public_launch_readiness_artifact_root_for_summary(summary: &TestnetSummary) -> String {
    let handoff_summary = public_launch_precapture_handoff_summary(summary);
    let readiness_report = public_launch_readiness_report_artifact(&handoff_summary);
    readiness_report["public_launch_readiness_artifact_root"]
        .as_str()
        .unwrap_or("missing-public-launch-readiness-artifact-root")
        .to_string()
}

fn public_launch_package_manifest_root_for_summary(summary: &TestnetSummary) -> String {
    let handoff_summary = public_launch_precapture_handoff_summary(summary);
    let mut record_roots = Vec::new();
    for (index, (artifact_id, file_name, root_field)) in
        PUBLIC_LAUNCH_PACKAGE_ARTIFACTS.iter().enumerate()
    {
        let value = public_launch_package_artifact_value(artifact_id, &handoff_summary)
            .expect("known public launch package artifact id");
        let artifact_root = value
            .get(*root_field)
            .and_then(Value::as_str)
            .filter(|candidate| is_hex_root(candidate))
            .map(str::to_string)
            .unwrap_or_else(|| public_launch_package_value_root(artifact_id, &value));
        let record_root = public_launch_package_artifact_record_root(
            &summary.manifest_id,
            artifact_id,
            file_name,
            root_field,
            &artifact_root,
            index + 1,
            public_launch_package_required_before_capture(artifact_id),
            public_launch_package_operator_fill_required(artifact_id),
        );
        record_roots.push(record_root);
    }
    let artifact_set_root = collection_root("public-launch-package-artifacts", record_roots);
    let package_file_set_root = public_launch_package_file_set_root(
        &handoff_summary.manifest_id,
        &handoff_summary.testnet_id,
    );
    let public_launch_readiness_artifact_root =
        public_launch_readiness_artifact_root_for_summary(&handoff_summary);
    let next_steps = public_deployment_capture_next_steps(
        "Run write_capture_scaffold, then replace capture.json placeholders with captured public endpoint, TLS, probe, observer, operator-registry, freshness, preflight receipt, runbook receipt, and evidence-root evidence.",
        false,
    );
    let next_steps_root = public_deployment_capture_next_steps_root(&next_steps);
    let command_sequence = public_deployment_capture_command_sequence();
    let command_sequence_root = public_deployment_capture_command_sequence_root(&command_sequence);
    let commands = public_deployment_capture_commands();
    let commands_root = public_deployment_capture_commands_root(&commands);
    public_launch_package_manifest_root(
        &handoff_summary.manifest_id,
        &handoff_summary.testnet_id,
        &artifact_set_root,
        &package_file_set_root,
        &handoff_summary.public_launch_readiness.level,
        handoff_summary.public_launch_readiness.public_launch_ready,
        handoff_summary.public_launch_readiness.blocking_gaps.len() as u64,
        handoff_summary.public_launch_readiness.remediations.len() as u64,
        &handoff_summary.public_launch_readiness.report_root,
        &public_launch_readiness_artifact_root,
        handoff_summary.acceptance.no_mainnet_custody,
        &commands_root,
        &next_steps_root,
        &command_sequence_root,
    )
}

fn public_launch_precapture_handoff_summary(summary: &TestnetSummary) -> TestnetSummary {
    let mut handoff = summary.clone();
    handoff.public_deployment = missing_public_deployment_report(&handoff.manifest_id);
    handoff.public_launch_readiness = public_launch_readiness_report(&handoff);
    handoff
}

fn public_launch_package_required_before_capture(artifact_id: &str) -> bool {
    matches!(
        artifact_id,
        "public-status-manifest"
            | "public-bootstrap-profile-template"
            | "public-deployment-runbook"
            | "public-launch-artifact-manifest"
            | "public-launch-bundle"
            | "public-launch-readiness-report"
            | "release-approval-template"
            | "release-authority-registry-template"
            | "public-deployment-evidence-template"
            | "public-deployment-capture-plan"
            | "public-capture-todo"
    )
}

fn public_launch_package_operator_fill_required(artifact_id: &str) -> bool {
    matches!(
        artifact_id,
        "public-deployment-evidence-template"
            | "public-deployment-capture-plan"
            | "public-capture-todo"
    )
}

fn public_launch_package_value_root(artifact_id: &str, value: &Value) -> String {
    value_root(artifact_id, value)
}

fn public_launch_package_artifact_value(
    artifact_id: &str,
    summary: &TestnetSummary,
) -> Result<Value, String> {
    match artifact_id {
        "public-status-manifest" => Ok(public_status_manifest(summary)),
        "public-bootstrap-profile-template" => Ok(public_bootstrap_profile_template(summary)),
        "public-deployment-runbook" => Ok(public_deployment_runbook(summary)),
        "public-launch-artifact-manifest" => Ok(public_launch_artifact_manifest(summary)),
        "public-launch-bundle" => Ok(public_launch_bundle(summary)),
        "public-launch-readiness-report" => Ok(public_launch_readiness_report_artifact(summary)),
        "release-approval-template" => Ok(release_approval_template_for_summary(summary)),
        "release-authority-registry-template" => Ok(release_authority_registry_template()),
        "public-deployment-evidence-template" => Ok(public_deployment_evidence_template(summary)),
        "public-deployment-capture-plan" => {
            let plan = public_deployment_capture_plan(summary);
            ensure_public_deployment_capture_plan_redacted(&plan)?;
            Ok(plan)
        }
        "public-capture-todo" => {
            let todo = public_capture_todo_artifact(summary);
            ensure_public_capture_todo_artifact(&todo)?;
            Ok(todo)
        }
        other => Err(format!("unknown public launch package artifact '{other}'")),
    }
}

fn read_json_file(path: &PathBuf, description: &str) -> Result<Value, String> {
    let bytes = fs::read(path).map_err(|error| format!("failed to read {description}: {error}"))?;
    serde_json::from_slice(&bytes)
        .map_err(|error| format!("failed to parse {description}: {error}"))
}

fn write_json_artifact(path: &PathBuf, value: &Value, description: &str) -> Result<(), String> {
    let encoded = serde_json::to_string_pretty(value)
        .map_err(|error| format!("failed to encode {description} json: {error}"))?;
    fs::write(path, format!("{encoded}\n"))
        .map_err(|error| format!("failed to write {description}: {error}"))
}

