fn verify_public_deployment_capture(
    capture_path: &str,
    summary: &TestnetSummary,
) -> Result<PublicDeploymentEvidence, String> {
    ensure_local_json_path(capture_path, "--verify-public-deployment-capture")?;
    let output_path = env::temp_dir().join(format!(
        "nebula-public-deployment-capture-verify-{}.json",
        root(&[
            "public-deployment-capture-verify",
            &summary.manifest_id,
            capture_path,
        ])
    ));
    let output_path_string = output_path.to_string_lossy().into_owned();
    let result =
        write_public_deployment_evidence_from_capture(capture_path, &output_path_string, summary);
    let _ = fs::remove_file(&output_path);
    result
}

fn ensure_public_deployment_capture_sections(value: &Value) -> Result<(), String> {
    for key in REQUIRED_PUBLIC_DEPLOYMENT_CAPTURE_FIELDS {
        ensure(
            value.get(key).is_some(),
            &format!("public deployment capture missing '{key}'"),
        )?;
    }
    Ok(())
}

fn set_public_deployment_section_field(
    value: &mut Value,
    section: &str,
    key: &str,
    field_value: Value,
) -> Result<(), String> {
    let section_map = value
        .get_mut(section)
        .and_then(Value::as_object_mut)
        .ok_or_else(|| format!("public deployment capture missing object '{section}'"))?;
    section_map.insert(key.to_string(), field_value);
    Ok(())
}

fn set_public_deployment_probe_root(
    value: &mut Value,
    body_key: &str,
    status_key: &str,
    root_key: &str,
    body_root_domain: &str,
    probe_root_domain: &str,
    endpoint: &str,
) -> Result<(), String> {
    let body = required_section(value, body_key)?.clone();
    let http_status = required_u64(value, status_key)?;
    let body_root = value_root(body_root_domain, &body);
    value[root_key] = json!(root(&[
        probe_root_domain,
        endpoint,
        &http_status.to_string(),
        &body_root,
    ]));
    Ok(())
}

