fn ensure_public_deployment_evidence_top_level_fields(value: &Value) -> Result<(), String> {
    let Some(map) = value.as_object() else {
        return Err("public deployment evidence must be a JSON object".to_string());
    };
    for key in map.keys() {
        ensure(
            PUBLIC_DEPLOYMENT_EVIDENCE_TOP_LEVEL_FIELDS.contains(&key.as_str()),
            &format!("public deployment evidence contains unexpected top-level field '{key}'"),
        )?;
    }
    for key in PUBLIC_DEPLOYMENT_EVIDENCE_TOP_LEVEL_FIELDS {
        ensure(
            map.contains_key(*key),
            &format!("public deployment evidence missing top-level field '{key}'"),
        )?;
    }
    Ok(())
}

fn verify_public_deployment_evidence(path: &str, summary: &TestnetSummary) -> Result<(), String> {
    ensure_local_json_path(path, "--verify-public-deployment-evidence")?;
    let evidence = load_public_deployment_evidence(path)?;
    ensure(
        summary.public_deployment.evidence_root.as_deref() == Some(evidence.evidence_root.as_str()),
        "public deployment evidence is not the attestation loaded for this run",
    )?;
    ensure(
        summary.public_deployment.passed,
        "public deployment evidence does not satisfy this run",
    )?;
    ensure_public_launch_gates(summary)
}

fn load_release_approval_bundle(path: &str) -> Result<ReleaseApproval, String> {
    ensure(
        !path.starts_with("http://") && !path.starts_with("https://"),
        "--release-approval must be a local JSON file path, not a URL",
    )?;
    let bytes =
        fs::read(path).map_err(|error| format!("failed to read release approval: {error}"))?;
    ensure(
        bytes.len() <= MAX_RELEASE_APPROVAL_BYTES,
        "release approval bundle is too large",
    )?;
    let value: Value = serde_json::from_slice(&bytes)
        .map_err(|error| format!("failed to parse release approval json: {error}"))?;
    reject_sensitive_fields(&value, "$")?;

    let schema_version = required_u64(&value, "schema_version")?;
    ensure(
        schema_version == 1,
        "unsupported release approval schema version",
    )?;
    ensure(
        required_str(&value, "chain_id")? == CHAIN_ID,
        "release approval chain_id mismatch",
    )?;
    ensure(
        required_str(&value, "approval_kind")? == "nebula-mainnet-release-approval",
        "release approval_kind mismatch",
    )?;
    let target_network = required_str(&value, "target_network")?;
    ensure(
        target_network == "mainnet",
        "release approval target_network must be mainnet",
    )?;
    ensure(
        required_str(&value, "custody_mode")? == "external-mainnet-process-required",
        "release approval custody_mode must be external-mainnet-process-required",
    )?;
    ensure(
        required_bool(&value, "approved")?,
        "release approval approved must be true",
    )?;

    let testnet_manifest_id = required_root(&value, "testnet_manifest_id")?;
    let testnet_run_checkpoint_root = required_root(&value, "testnet_run_checkpoint_root")?;
    let readiness_evidence_bundle_root = required_root(&value, "readiness_evidence_bundle_root")?;
    let local_adversarial_self_test_root =
        required_root(&value, "local_adversarial_self_test_root")?;
    let release_authority_registry_root = optional_root(&value, "release_authority_registry_root")?;
    let report = required_section(&value, "production_readiness_report")?;
    ensure(
        required_bool(report, "release_candidate")?,
        "release approval report release_candidate must be true",
    )?;
    let open_blockers = required_u64(report, "open_blockers")?;
    ensure(
        open_blockers == 0,
        "release approval report open_blockers must be zero",
    )?;
    let release_score_bps = required_u64(report, "release_score_bps")?;
    ensure(
        release_score_bps >= 9_500,
        "release approval release_score_bps must be at least 9500",
    )?;
    let critical_score_bps = required_u64(report, "critical_score_bps")?;
    ensure(
        critical_score_bps == 10_000,
        "release approval critical_score_bps must be 10000",
    )?;
    let production_readiness_report_root = required_root(report, "report_root")?;
    let production_readiness_signoff_root = required_root(report, "signoff_root")?;
    let signoff_quorum =
        validate_release_signoff_quorum(required_section(&value, "signoff_quorum")?)?;
    ensure(
        signoff_quorum.signoff_root == production_readiness_signoff_root,
        "release approval signoff_root does not match signoff_quorum",
    )?;
    let signed_at_height = required_u64(&value, "signed_at_height")?;
    let expires_at_height = required_u64(&value, "expires_at_height")?;
    ensure(
        expires_at_height > signed_at_height,
        "release approval expires_at_height must follow signed_at_height",
    )?;
    let approval_root = required_root(&value, "approval_root")?;
    let computed_approval_root = release_approval_root(
        target_network,
        &testnet_manifest_id,
        &testnet_run_checkpoint_root,
        &readiness_evidence_bundle_root,
        &local_adversarial_self_test_root,
        &production_readiness_report_root,
        &signoff_quorum.signoff_root,
        signed_at_height,
        expires_at_height,
        signoff_quorum.threshold,
        signoff_quorum.count,
    );
    ensure(
        approval_root == computed_approval_root,
        "release approval_root mismatch",
    )?;

    Ok(ReleaseApproval {
        schema_version,
        approval_root,
        target_network: target_network.to_string(),
        testnet_manifest_id,
        testnet_run_checkpoint_root,
        readiness_evidence_bundle_root,
        local_adversarial_self_test_root,
        release_authority_registry_root,
        production_readiness_report_root,
        production_readiness_signoff_root,
        signed_at_height,
        expires_at_height,
        release_score_bps,
        critical_score_bps,
        open_blockers,
        signoff_threshold: signoff_quorum.threshold,
        signoff_count: signoff_quorum.count,
        accepted_signoff_roles: signoff_quorum.accepted_roles,
        signoffs: signoff_quorum.signoffs,
    })
}

fn load_release_authority_registry(path: &str) -> Result<ReleaseAuthorityRegistry, String> {
    ensure(
        !path.starts_with("http://") && !path.starts_with("https://"),
        "--release-authority-registry must be a local JSON file path, not a URL",
    )?;
    let bytes = fs::read(path)
        .map_err(|error| format!("failed to read release authority registry: {error}"))?;
    ensure(
        bytes.len() <= MAX_RELEASE_AUTHORITY_REGISTRY_BYTES,
        "release authority registry is too large",
    )?;
    let value: Value = serde_json::from_slice(&bytes)
        .map_err(|error| format!("failed to parse release authority registry json: {error}"))?;
    reject_sensitive_fields(&value, "$")?;

    let schema_version = required_u64(&value, "schema_version")?;
    ensure(
        schema_version == 1,
        "unsupported release authority registry schema version",
    )?;
    ensure(
        required_str(&value, "chain_id")? == CHAIN_ID,
        "release authority registry chain_id mismatch",
    )?;
    ensure(
        required_str(&value, "registry_kind")? == "nebula-release-authority-registry",
        "release authority registry_kind mismatch",
    )?;
    ensure(
        required_str(&value, "custody_mode")? == "external-mainnet-process-required",
        "release authority registry custody_mode must be external-mainnet-process-required",
    )?;
    let threshold = required_u64(&value, "threshold")?;
    let authorities = value
        .get("authorities")
        .and_then(Value::as_array)
        .ok_or_else(|| "release authority registry missing authorities array".to_string())?;
    ensure(
        authorities.len() == REQUIRED_RELEASE_SIGNOFF_ROLES.len(),
        "release authority registry must contain exactly the required roles",
    )?;
    ensure(
        threshold >= REQUIRED_RELEASE_SIGNOFF_ROLES.len() as u64,
        "release authority registry threshold must cover all required roles",
    )?;
    ensure(
        authorities.len() as u64 >= threshold,
        "release authority registry authority count is below threshold",
    )?;

    let mut accepted_roles = BTreeSet::new();
    let mut parsed_authorities = Vec::new();
    let mut authority_roots = Vec::new();
    for (index, authority) in authorities.iter().enumerate() {
        ensure(
            authority.is_object(),
            &format!("release authority {index} must be an object"),
        )?;
        let role = required_str(authority, "role")?;
        ensure(
            REQUIRED_RELEASE_SIGNOFF_ROLES.contains(&role),
            &format!("release authority role '{role}' is not required"),
        )?;
        ensure(
            accepted_roles.insert(role.to_string()),
            &format!("release authority duplicate role '{role}'"),
        )?;
        let active = required_bool(authority, "active")?;
        ensure(
            active,
            &format!("release authority role '{role}' is inactive"),
        )?;
        let signer_commitment = required_root(authority, "signer_commitment")?;
        let pq_public_key_root = required_root(authority, "pq_public_key_root")?;
        let authority_id = required_root(authority, "authority_id")?;
        let parsed = ReleaseAuthority {
            role: role.to_string(),
            signer_commitment,
            pq_public_key_root,
            authority_id,
            active,
        };
        authority_roots.push(release_authority_root(&parsed));
        parsed_authorities.push(parsed);
    }
    for required_role in REQUIRED_RELEASE_SIGNOFF_ROLES {
        ensure(
            accepted_roles.contains(required_role),
            &format!("release authority registry missing required role '{required_role}'"),
        )?;
    }
    let registry_root = required_root(&value, "registry_root")?;
    let computed_registry_root = release_authority_registry_root(
        threshold,
        parsed_authorities.len() as u64,
        authority_roots,
    );
    ensure(
        registry_root == computed_registry_root,
        "release authority registry_root mismatch",
    )?;

    Ok(ReleaseAuthorityRegistry {
        schema_version,
        registry_root,
        threshold,
        authority_count: parsed_authorities.len() as u64,
        accepted_roles: accepted_roles.into_iter().collect(),
        authorities: parsed_authorities,
    })
}

struct ReleaseSignoffQuorum {
    threshold: u64,
    count: u64,
    signoff_root: String,
    accepted_roles: Vec<String>,
    signoffs: Vec<ReleaseApprovalSignoff>,
}

fn validate_release_signoff_quorum(section: &Value) -> Result<ReleaseSignoffQuorum, String> {
    let threshold = required_u64(section, "threshold")?;
    let signoffs = section
        .get("signoffs")
        .and_then(Value::as_array)
        .ok_or_else(|| "release approval missing signoff_quorum.signoffs array".to_string())?;
    ensure(
        !signoffs.is_empty(),
        "release approval signoff_quorum.signoffs cannot be empty",
    )?;
    ensure(
        signoffs.len() <= REQUIRED_RELEASE_SIGNOFF_ROLES.len(),
        "release approval contains too many signoffs",
    )?;
    let mut accepted_roles = BTreeSet::new();
    let mut signoff_roots = Vec::new();
    let mut parsed_signoffs = Vec::new();
    for (index, signoff) in signoffs.iter().enumerate() {
        ensure(
            signoff.is_object(),
            &format!("release approval signoff {index} must be an object"),
        )?;
        ensure(
            required_bool(signoff, "accepted")?,
            &format!("release approval signoff {index} must be accepted"),
        )?;
        let role = required_str(signoff, "role")?;
        ensure(
            REQUIRED_RELEASE_SIGNOFF_ROLES.contains(&role),
            &format!("release approval signoff role '{role}' is not required"),
        )?;
        ensure(
            accepted_roles.insert(role.to_string()),
            &format!("release approval duplicate signoff role '{role}'"),
        )?;
        let signer_commitment = required_root(signoff, "signer_commitment")?;
        let pq_signature_root = required_root(signoff, "pq_signature_root")?;
        let signoff_id = required_root(signoff, "signoff_id")?;
        parsed_signoffs.push(ReleaseApprovalSignoff {
            role: role.to_string(),
            signer_commitment: signer_commitment.clone(),
            pq_signature_root: pq_signature_root.clone(),
            signoff_id: signoff_id.clone(),
        });
        signoff_roots.push(root(&[
            "release-approval-signoff",
            role,
            &signer_commitment,
            &pq_signature_root,
            &signoff_id,
        ]));
    }
    for required_role in REQUIRED_RELEASE_SIGNOFF_ROLES {
        ensure(
            accepted_roles.contains(required_role),
            &format!("release approval missing required signoff role '{required_role}'"),
        )?;
    }
    ensure(
        threshold >= REQUIRED_RELEASE_SIGNOFF_ROLES.len() as u64,
        "release approval signoff threshold must cover all required roles",
    )?;
    ensure(
        signoffs.len() as u64 >= threshold,
        "release approval signoff count is below threshold",
    )?;
    Ok(ReleaseSignoffQuorum {
        threshold,
        count: signoffs.len() as u64,
        signoff_root: collection_root("release-approval-signoff-quorum", signoff_roots),
        accepted_roles: accepted_roles.into_iter().collect(),
        signoffs: parsed_signoffs,
    })
}

fn live_monero_rpc_run_binding_root(
    testnet_manifest_id: &str,
    run_profile_report_root: &str,
    local_bridge_signer_set_root: &str,
    local_reserve_report_root: &str,
    latest_block_height: u64,
    synthetic_observed_height: u64,
    network: &str,
    finality_depth: u64,
) -> String {
    root(&[
        "live-monero-rpc-run-binding",
        CHAIN_ID,
        testnet_manifest_id,
        run_profile_report_root,
        local_bridge_signer_set_root,
        local_reserve_report_root,
        &latest_block_height.to_string(),
        &synthetic_observed_height.to_string(),
        network,
        &finality_depth.to_string(),
    ])
}

fn validate_live_monero_rpc_section(section: &Value) -> Result<LiveMoneroRpcEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "live_monero_rpc.passed must be true",
    )?;
    let network = required_str(section, "network")?;
    ensure(
        network == "stagenet" || network == "regtest",
        "live_monero_rpc.network must be stagenet or regtest",
    )?;
    let finality_depth = required_u64(section, "monero_finality_depth")?;
    ensure(
        finality_depth > 0,
        "live_monero_rpc.monero_finality_depth must be positive",
    )?;
    let tip_height = required_u64(section, "monero_tip_height")?;
    ensure(
        tip_height >= finality_depth,
        "live_monero_rpc.monero_tip_height must cover finality depth",
    )?;
    let rpc_endpoint_commitment = required_root(section, "rpc_endpoint_commitment")?;
    let wallet_rpc_endpoint_commitment = required_root(section, "wallet_rpc_endpoint_commitment")?;
    let signer_set_root = required_root(section, "signer_set_root")?;
    let reorg_observation_root = required_root(section, "reorg_observation_root")?;
    let testnet_manifest_id = required_root(section, "testnet_manifest_id")?;
    let run_profile_report_root = required_root(section, "run_profile_report_root")?;
    let local_bridge_signer_set_root = required_root(section, "local_bridge_signer_set_root")?;
    let local_reserve_report_root = required_root(section, "local_reserve_report_root")?;
    let latest_block_height = required_u64(section, "latest_block_height")?;
    let synthetic_observed_height = required_u64(section, "synthetic_observed_height")?;
    ensure(
        latest_block_height > 0,
        "live_monero_rpc.latest_block_height must be positive",
    )?;
    ensure(
        synthetic_observed_height >= DEFAULT_MONERO_HEIGHT + latest_block_height,
        "live_monero_rpc.synthetic_observed_height must cover latest block height",
    )?;
    ensure(
        tip_height >= synthetic_observed_height,
        "live_monero_rpc.monero_tip_height must cover synthetic observed height",
    )?;
    ensure(
        local_bridge_signer_set_root == signer_set_root,
        "live_monero_rpc.local_bridge_signer_set_root must match signer_set_root",
    )?;
    let computed_run_binding_root = live_monero_rpc_run_binding_root(
        &testnet_manifest_id,
        &run_profile_report_root,
        &local_bridge_signer_set_root,
        &local_reserve_report_root,
        latest_block_height,
        synthetic_observed_height,
        network,
        finality_depth,
    );
    let run_binding_root = required_root(section, "run_binding_root")?;
    ensure(
        run_binding_root == computed_run_binding_root,
        "live_monero_rpc.run_binding_root mismatch",
    )?;
    let observations = section
        .get("observations")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'observations'".to_string())?;
    ensure(
        observations.len() == REQUIRED_LIVE_MONERO_OBSERVATIONS.len(),
        "live_monero_rpc.observations must contain exactly the required transcript set",
    )?;
    let mut observed = BTreeSet::new();
    let mut observation_roots = Vec::new();
    for (index, observation) in observations.iter().enumerate() {
        let (kind, evidence_root) = validate_live_monero_observation(
            observation,
            index,
            network,
            finality_depth,
            tip_height,
        )?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("live_monero_rpc duplicate observation '{kind}'"),
        )?;
        observation_roots.push(evidence_root);
    }
    for required in REQUIRED_LIVE_MONERO_OBSERVATIONS {
        ensure(
            observed.contains(required),
            &format!("live_monero_rpc missing observation '{required}'"),
        )?;
    }
    let metadata_root = root(&[
        "live-monero-rpc-metadata",
        CHAIN_ID,
        network,
        &tip_height.to_string(),
        &finality_depth.to_string(),
        &rpc_endpoint_commitment,
        &wallet_rpc_endpoint_commitment,
        &signer_set_root,
        &reorg_observation_root,
    ]);
    let mut transcript_roots = vec![metadata_root];
    transcript_roots.extend(observation_roots);
    let computed_evidence_root = collection_root("live-monero-rpc-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "live_monero_rpc.evidence_root does not match transcript roots",
    )?;
    Ok(LiveMoneroRpcEvidence {
        evidence_root,
        network: network.to_string(),
        observation_count: observations.len() as u64,
        finality_depth,
        tip_height,
        signer_set_root,
        run_binding_root,
        testnet_manifest_id,
        run_profile_report_root,
        local_bridge_signer_set_root,
        local_reserve_report_root,
        latest_block_height,
        synthetic_observed_height,
    })
}

fn validate_live_monero_observation<'a>(
    observation: &'a Value,
    index: usize,
    network: &str,
    finality_depth: u64,
    tip_height: u64,
) -> Result<(&'a str, String), String> {
    ensure(
        observation.is_object(),
        &format!("live_monero_rpc observation {index} must be an object"),
    )?;
    let kind = required_str(observation, "kind")?;
    ensure(
        REQUIRED_LIVE_MONERO_OBSERVATIONS.contains(&kind),
        &format!("live_monero_rpc observation kind '{kind}' is not required"),
    )?;
    let observed_height = required_u64(observation, "observed_height")?;
    ensure(
        observed_height > 0 && observed_height <= tip_height,
        &format!("live_monero_rpc observation '{kind}' height is outside the tip"),
    )?;
    let confirmations = required_u64(observation, "confirmations")?;
    if kind == "deposit_address_derivation" {
        ensure(
            confirmations == 0,
            "deposit_address_derivation confirmations must be zero",
        )?;
    } else {
        ensure(
            confirmations >= finality_depth,
            &format!("live_monero_rpc observation '{kind}' is below finality depth"),
        )?;
        ensure(
            tip_height.saturating_sub(observed_height).saturating_add(1) >= finality_depth,
            &format!("live_monero_rpc observation '{kind}' is not final at the reported tip"),
        )?;
    }
    let signer_threshold = required_u64(observation, "signer_threshold")?;
    let signer_count = required_u64(observation, "signer_count")?;
    ensure(
        quorum_reaches_threshold(signer_threshold, signer_count),
        &format!("live_monero_rpc observation '{kind}' signer quorum is below threshold"),
    )?;
    let command_root = required_root(observation, "command_root")?;
    let result_root = required_root(observation, "result_root")?;
    let artifact_root = required_root(observation, "artifact_root")?;
    let privacy_root = required_root(observation, "privacy_root")?;
    let signer_quorum_root = required_root(observation, "signer_quorum_root")?;
    let evidence_root = required_root(observation, "evidence_root")?;
    let computed_evidence_root = root(&[
        "live-monero-observation",
        CHAIN_ID,
        network,
        kind,
        &observed_height.to_string(),
        &confirmations.to_string(),
        &signer_threshold.to_string(),
        &signer_count.to_string(),
        &command_root,
        &result_root,
        &artifact_root,
        &privacy_root,
        &signer_quorum_root,
    ]);
    ensure(
        evidence_root == computed_evidence_root,
        &format!("live_monero_rpc observation '{kind}' evidence_root mismatch"),
    )?;
    Ok((kind, evidence_root))
}

fn distributed_finality_run_binding_root(
    testnet_manifest_id: &str,
    run_profile_report_root: &str,
    local_validator_count: u64,
    local_validator_threshold: u64,
    local_region_count: u64,
    local_target_finality_micros: u64,
    latest_block_height: u64,
) -> String {
    root(&[
        "distributed-finality-run-binding",
        CHAIN_ID,
        testnet_manifest_id,
        run_profile_report_root,
        &local_validator_count.to_string(),
        &local_validator_threshold.to_string(),
        &local_region_count.to_string(),
        &local_target_finality_micros.to_string(),
        &latest_block_height.to_string(),
    ])
}

fn validate_distributed_finality_section(
    section: &Value,
) -> Result<DistributedFinalityEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "distributed_finality.passed must be true",
    )?;
    let validator_count = required_u64(section, "validator_count")?;
    let validator_threshold = required_u64(section, "validator_threshold")?;
    let region_count = required_u64(section, "region_count")?;
    let sample_count = required_u64(section, "sample_count")?;
    let target_finality_micros = required_u64(section, "target_finality_micros")?;
    let max_quorum_certificate_micros = required_u64(section, "max_quorum_certificate_micros")?;
    let p95_quorum_certificate_micros = required_u64(section, "p95_quorum_certificate_micros")?;
    ensure(
        quorum_reaches_threshold(validator_threshold, validator_count),
        "distributed_finality validator threshold must reach quorum",
    )?;
    ensure(
        region_count >= 2,
        "distributed_finality.region_count must be at least 2",
    )?;
    ensure(
        sample_count > 0,
        "distributed_finality.sample_count must be positive",
    )?;
    ensure(
        target_finality_micros > 0 && target_finality_micros <= 200_000,
        "distributed_finality.target_finality_micros must be in 1..=200000",
    )?;
    ensure(
        p95_quorum_certificate_micros <= max_quorum_certificate_micros,
        "distributed_finality p95 latency must be <= max latency",
    )?;
    ensure(
        max_quorum_certificate_micros <= target_finality_micros,
        "distributed_finality max quorum-certificate latency exceeds target",
    )?;
    let benchmark_root = required_root(section, "benchmark_root")?;
    let network_profile_root = required_root(section, "network_profile_root")?;
    let clock_sync_root = required_root(section, "clock_sync_root")?;
    let sample_set_root = required_root(section, "sample_set_root")?;
    let testnet_manifest_id = required_root(section, "testnet_manifest_id")?;
    let run_profile_report_root = required_root(section, "run_profile_report_root")?;
    let local_validator_count = required_u64(section, "local_validator_count")?;
    let local_validator_threshold = required_u64(section, "local_validator_threshold")?;
    let local_region_count = required_u64(section, "local_region_count")?;
    let local_target_micros = required_u64(section, "local_target_finality_micros")?;
    let latest_block_height = required_u64(section, "latest_block_height")?;
    ensure(
        quorum_reaches_threshold(local_validator_threshold, local_validator_count),
        "distributed_finality local validator threshold must reach quorum",
    )?;
    ensure(
        local_region_count >= 2,
        "distributed_finality.local_region_count must be at least 2",
    )?;
    ensure(
        local_target_micros > 0 && local_target_micros <= 200_000,
        "distributed_finality.local_target_finality_micros must be in 1..=200000",
    )?;
    ensure(
        latest_block_height > 0,
        "distributed_finality.latest_block_height must be positive",
    )?;
    let computed_run_binding_root = distributed_finality_run_binding_root(
        &testnet_manifest_id,
        &run_profile_report_root,
        local_validator_count,
        local_validator_threshold,
        local_region_count,
        local_target_micros,
        latest_block_height,
    );
    let run_binding_root = required_root(section, "run_binding_root")?;
    ensure(
        run_binding_root == computed_run_binding_root,
        "distributed_finality.run_binding_root mismatch",
    )?;
    let evidence_root = required_root(section, "evidence_root")?;
    let computed_evidence_root = distributed_finality_evidence_root(
        validator_count,
        validator_threshold,
        region_count,
        sample_count,
        target_finality_micros,
        max_quorum_certificate_micros,
        p95_quorum_certificate_micros,
        &benchmark_root,
        &network_profile_root,
        &clock_sync_root,
        &sample_set_root,
    );
    ensure(
        evidence_root == computed_evidence_root,
        "distributed_finality.evidence_root mismatch",
    )?;
    Ok(DistributedFinalityEvidence {
        evidence_root,
        sample_count,
        validator_count,
        validator_threshold,
        region_count,
        target_finality_micros,
        max_quorum_certificate_micros,
        run_binding_root,
        testnet_manifest_id,
        run_profile_report_root,
        local_validator_count,
        local_validator_threshold,
        local_region_count,
        local_target_micros,
        latest_block_height,
    })
}

fn validate_anchor_capacity_section(section: &Value) -> Result<AnchorCapacityEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "anchor_capacity.passed must be true",
    )?;
    let max_transactions_per_anchor = required_u64(section, "max_transactions_per_anchor")?;
    let observed_epoch_count = required_u64(section, "observed_epoch_count")?;
    let fixed_format_payload = required_bool(section, "fixed_format_payload")?;
    let anchor_payload_bytes = required_u64(section, "anchor_payload_bytes")?;
    ensure(
        max_transactions_per_anchor >= DEFAULT_ANCHOR_CAPACITY_TX,
        "anchor_capacity.max_transactions_per_anchor must be at least 10000",
    )?;
    ensure(
        observed_epoch_count > 0,
        "anchor_capacity.observed_epoch_count must be positive",
    )?;
    ensure(
        fixed_format_payload,
        "anchor_capacity.fixed_format_payload must be true",
    )?;
    ensure(
        anchor_payload_bytes > 0,
        "anchor_capacity.anchor_payload_bytes must be positive",
    )?;
    let capacity_policy_root = required_root(section, "capacity_policy_root")?;
    let fixed_format_payload_root = required_root(section, "fixed_format_payload_root")?;
    let capacity_root = required_root(section, "capacity_root")?;
    let computed_capacity_root = anchor_capacity_claim_root(
        max_transactions_per_anchor,
        fixed_format_payload,
        anchor_payload_bytes,
        &capacity_policy_root,
        &fixed_format_payload_root,
    );
    ensure(
        capacity_root == computed_capacity_root,
        "anchor_capacity.capacity_root mismatch",
    )?;
    let benchmark_root = required_root(section, "benchmark_root")?;
    let evidence_root = required_root(section, "evidence_root")?;
    let computed_evidence_root = anchor_capacity_evidence_root(
        max_transactions_per_anchor,
        observed_epoch_count,
        fixed_format_payload,
        anchor_payload_bytes,
        &capacity_root,
        &benchmark_root,
    );
    ensure(
        evidence_root == computed_evidence_root,
        "anchor_capacity.evidence_root mismatch",
    )?;
    Ok(AnchorCapacityEvidence {
        evidence_root,
        max_transactions_per_anchor,
        observed_epoch_count,
        fixed_format_payload,
        anchor_payload_bytes,
    })
}

fn validate_adversarial_section(section: &Value) -> Result<AdversarialEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "adversarial_tests.passed must be true",
    )?;
    let performance_root = required_root(section, "adversarial_performance_root")?;
    let calibration_root = required_root(section, "adversarial_calibration_root")?;
    let max_block_count = required_u64(section, "max_block_count")?;
    let max_validator_count = required_u64(section, "max_validator_count")?;
    let covered_finality_target_micros = required_u64(section, "covered_finality_target_micros")?;
    ensure(
        max_block_count > 0,
        "adversarial_tests.max_block_count must be greater than zero",
    )?;
    ensure(
        max_validator_count > 0,
        "adversarial_tests.max_validator_count must be greater than zero",
    )?;
    ensure(
        covered_finality_target_micros > 0,
        "adversarial_tests.covered_finality_target_micros must be greater than zero",
    )?;
    let coverage_root = required_root(section, "coverage_root")?;
    let computed_coverage_root = adversarial_coverage_root(
        max_block_count,
        max_validator_count,
        covered_finality_target_micros,
        &performance_root,
        &calibration_root,
    );
    ensure(
        coverage_root == computed_coverage_root,
        "adversarial_tests.coverage_root mismatch",
    )?;
    let scenarios = section
        .get("scenarios")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'scenarios'".to_string())?;
    ensure(
        scenarios.len() == REQUIRED_ADVERSARIAL_SCENARIOS.len(),
        "adversarial_tests.scenarios must contain exactly the required transcript set",
    )?;
    let mut observed = BTreeSet::new();
    let mut scenario_roots = Vec::new();
    for (index, scenario) in scenarios.iter().enumerate() {
        let (kind, evidence_root) = validate_adversarial_scenario(scenario, index)?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("adversarial_tests duplicate scenario '{kind}'"),
        )?;
        scenario_roots.push(evidence_root);
    }
    for required in REQUIRED_ADVERSARIAL_SCENARIOS {
        ensure(
            observed.contains(required),
            &format!("adversarial_tests missing scenario '{required}'"),
        )?;
    }
    let mut transcript_roots = vec![
        performance_root.clone(),
        calibration_root.clone(),
        coverage_root.clone(),
    ];
    transcript_roots.extend(scenario_roots);
    let computed_evidence_root = collection_root("adversarial-tests-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "adversarial_tests.evidence_root does not match transcript roots",
    )?;
    Ok(AdversarialEvidence {
        evidence_root,
        scenario_count: scenarios.len() as u64,
        performance_root,
        calibration_root,
        coverage_root,
        max_block_count,
        max_validator_count,
        covered_finality_target_micros,
    })
}

fn validate_adversarial_scenario<'a>(
    scenario: &'a Value,
    index: usize,
) -> Result<(&'a str, String), String> {
    ensure(
        scenario.is_object(),
        &format!("adversarial_tests scenario {index} must be an object"),
    )?;
    ensure(
        required_bool(scenario, "passed")?,
        &format!("adversarial_tests scenario {index} must be passed"),
    )?;
    let kind = required_str(scenario, "kind")?;
    ensure(
        REQUIRED_ADVERSARIAL_SCENARIOS.contains(&kind),
        &format!("adversarial_tests scenario kind '{kind}' is not required"),
    )?;
    let injected_at_height = required_u64(scenario, "injected_at_height")?;
    let detected_at_height = required_u64(scenario, "detected_at_height")?;
    ensure(
        injected_at_height > 0 && detected_at_height >= injected_at_height,
        &format!("adversarial_tests scenario '{kind}' detection height is invalid"),
    )?;
    let fault_root = required_root(scenario, "fault_root")?;
    let command_root = required_root(scenario, "command_root")?;
    let expected_rejection_root = required_root(scenario, "expected_rejection_root")?;
    let observed_rejection_root = required_root(scenario, "observed_rejection_root")?;
    let invariant_root = required_root(scenario, "invariant_root")?;
    let performance_sample_root = required_root(scenario, "performance_sample_root")?;
    let evidence_root = required_root(scenario, "evidence_root")?;
    let computed_evidence_root = root(&[
        "adversarial-test-scenario",
        CHAIN_ID,
        kind,
        &injected_at_height.to_string(),
        &detected_at_height.to_string(),
        &fault_root,
        &command_root,
        &expected_rejection_root,
        &observed_rejection_root,
        &invariant_root,
        &performance_sample_root,
    ]);
    ensure(
        evidence_root == computed_evidence_root,
        &format!("adversarial_tests scenario '{kind}' evidence_root mismatch"),
    )?;
    Ok((kind, evidence_root))
}

