fn validate_privacy_policy_section(section: &Value) -> Result<PrivacyPolicyEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "privacy_policy.passed must be true",
    )?;
    let policy_root = required_root(section, "policy_root")?;
    let threat_model_root = required_root(section, "threat_model_root")?;
    let testnet_manifest_id = required_root(section, "testnet_manifest_id")?;
    let local_privacy_surface_report_root =
        required_root(section, "local_privacy_surface_report_root")?;
    let wallet_recovery_audit_report_root =
        required_root(section, "wallet_recovery_audit_report_root")?;
    let latest_block_height = required_u64(section, "latest_block_height")?;
    ensure(
        latest_block_height > 0,
        "privacy_policy.latest_block_height must be positive",
    )?;
    let computed_run_binding_root = privacy_policy_run_binding_root(
        &testnet_manifest_id,
        &local_privacy_surface_report_root,
        &wallet_recovery_audit_report_root,
        latest_block_height,
    );
    let run_binding_root = required_root(section, "run_binding_root")?;
    ensure(
        run_binding_root == computed_run_binding_root,
        "privacy_policy.run_binding_root mismatch",
    )?;
    let components = section
        .get("components")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'components'".to_string())?;
    ensure(
        components.len() == REQUIRED_PRIVACY_POLICY_COMPONENTS.len(),
        "privacy_policy.components must contain exactly the required privacy profile set",
    )?;
    let mut observed = BTreeSet::new();
    let mut component_roots = Vec::new();
    for (index, component) in components.iter().enumerate() {
        let (kind, evidence_root) = validate_privacy_policy_component(component, index)?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("privacy_policy duplicate component '{kind}'"),
        )?;
        component_roots.push(evidence_root);
    }
    for required in REQUIRED_PRIVACY_POLICY_COMPONENTS {
        ensure(
            observed.contains(required),
            &format!("privacy_policy missing component '{required}'"),
        )?;
    }
    let mut transcript_roots = vec![policy_root.clone(), threat_model_root];
    transcript_roots.extend(component_roots);
    let computed_evidence_root = collection_root("privacy-policy-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "privacy_policy.evidence_root does not match transcript roots",
    )?;
    Ok(PrivacyPolicyEvidence {
        evidence_root,
        component_count: components.len() as u64,
        policy_root,
        run_binding_root,
        testnet_manifest_id,
        local_privacy_surface_report_root,
        wallet_recovery_audit_report_root,
        latest_block_height,
    })
}

fn validate_privacy_policy_component<'a>(
    component: &'a Value,
    index: usize,
) -> Result<(&'a str, String), String> {
    ensure(
        component.is_object(),
        &format!("privacy_policy component {index} must be an object"),
    )?;
    ensure(
        required_bool(component, "passed")?,
        &format!("privacy_policy component {index} must be passed"),
    )?;
    let kind = required_str(component, "kind")?;
    ensure(
        REQUIRED_PRIVACY_POLICY_COMPONENTS.contains(&kind),
        &format!("privacy_policy component kind '{kind}' is not required"),
    )?;
    let reviewed_at_height = required_u64(component, "reviewed_at_height")?;
    ensure(
        reviewed_at_height > 0,
        &format!("privacy_policy component '{kind}' reviewed_at_height is invalid"),
    )?;
    let reviewer_commitment = required_root(component, "reviewer_commitment")?;
    let scope_root = required_root(component, "scope_root")?;
    let implementation_evidence_root = required_root(component, "implementation_evidence_root")?;
    let negative_test_root = required_root(component, "negative_test_root")?;
    let mitigation_root = required_root(component, "mitigation_root")?;
    let claims = privacy_policy_component_claims(component, kind)?;
    let evidence_root = required_root(component, "evidence_root")?;
    let computed_evidence_root = privacy_policy_component_root(
        kind,
        reviewed_at_height,
        &reviewer_commitment,
        &scope_root,
        &implementation_evidence_root,
        &negative_test_root,
        &mitigation_root,
        &claims,
    );
    ensure(
        evidence_root == computed_evidence_root,
        &format!("privacy_policy component '{kind}' evidence_root mismatch"),
    )?;
    Ok((kind, evidence_root))
}

fn privacy_policy_component_claims(component: &Value, kind: &str) -> Result<Value, String> {
    match kind {
        "anchor_privacy_profile" => {
            let constant_size_payload = required_bool(component, "constant_size_payload")?;
            let bounded_cadence_jitter = required_bool(component, "bounded_cadence_jitter")?;
            let unique_amounts_avoided = required_bool(component, "unique_amounts_avoided")?;
            let raw_identifiers_excluded = required_bool(component, "raw_identifiers_excluded")?;
            let independent_submitter_count =
                required_u64(component, "independent_submitter_count")?;
            ensure(
                constant_size_payload
                    && bounded_cadence_jitter
                    && unique_amounts_avoided
                    && raw_identifiers_excluded,
                "anchor_privacy_profile must assert constant-size payloads, bounded cadence jitter, amount smoothing, and raw identifier exclusion",
            )?;
            ensure(
                independent_submitter_count >= 2,
                "anchor_privacy_profile requires at least two independent submitters",
            )?;
            Ok(json!({
                "constant_size_payload": constant_size_payload,
                "bounded_cadence_jitter": bounded_cadence_jitter,
                "unique_amounts_avoided": unique_amounts_avoided,
                "raw_identifiers_excluded": raw_identifiers_excluded,
                "independent_submitter_count": independent_submitter_count,
            }))
        }
        "deposit_privacy_profile" => {
            let one_time_addresses = required_bool(component, "one_time_addresses")?;
            let batched_attestations = required_bool(component, "batched_attestations")?;
            let amount_address_mapping_excluded =
                required_bool(component, "amount_address_mapping_excluded")?;
            let user_mint_delay_supported = required_bool(component, "user_mint_delay_supported")?;
            let minimum_batch_size = required_u64(component, "minimum_batch_size")?;
            ensure(
                one_time_addresses
                    && batched_attestations
                    && amount_address_mapping_excluded
                    && user_mint_delay_supported,
                "deposit_privacy_profile must assert one-time addresses, batched attestations, mapping exclusion, and user mint delay support",
            )?;
            ensure(
                minimum_batch_size >= 2,
                "deposit_privacy_profile requires minimum_batch_size >= 2",
            )?;
            Ok(json!({
                "one_time_addresses": one_time_addresses,
                "batched_attestations": batched_attestations,
                "amount_address_mapping_excluded": amount_address_mapping_excluded,
                "user_mint_delay_supported": user_mint_delay_supported,
                "minimum_batch_size": minimum_batch_size,
            }))
        }
        "withdrawal_privacy_profile" => {
            let batching_enabled = required_bool(component, "batching_enabled")?;
            let randomized_delay_window = required_bool(component, "randomized_delay_window")?;
            let amount_bucket_policy = required_bool(component, "amount_bucket_policy")?;
            let raw_recipient_excluded = required_bool(component, "raw_recipient_excluded")?;
            let challenge_hold_supported = required_bool(component, "challenge_hold_supported")?;
            let minimum_delay_window_blocks =
                required_u64(component, "minimum_delay_window_blocks")?;
            ensure(
                batching_enabled
                    && randomized_delay_window
                    && amount_bucket_policy
                    && raw_recipient_excluded
                    && challenge_hold_supported,
                "withdrawal_privacy_profile must assert batching, randomized delay, amount buckets, recipient redaction, and challenge holds",
            )?;
            ensure(
                minimum_delay_window_blocks > 0,
                "withdrawal_privacy_profile requires a nonzero delay window",
            )?;
            Ok(json!({
                "batching_enabled": batching_enabled,
                "randomized_delay_window": randomized_delay_window,
                "amount_bucket_policy": amount_bucket_policy,
                "raw_recipient_excluded": raw_recipient_excluded,
                "challenge_hold_supported": challenge_hold_supported,
                "minimum_delay_window_blocks": minimum_delay_window_blocks,
            }))
        }
        "wallet_recovery_privacy_profile" => {
            let scoped_history_recovery_supported =
                required_bool(component, "scoped_history_recovery_supported")?;
            let da_payload_audit_supported =
                required_bool(component, "da_payload_audit_supported")?;
            let transparent_balance_mode_disabled =
                required_bool(component, "transparent_balance_mode_disabled")?;
            let scoped_disclosure_supported =
                required_bool(component, "scoped_disclosure_supported")?;
            let relay_path_commitments_verified =
                required_bool(component, "relay_path_commitments_verified")?;
            let wallet_recovery_vector_count =
                required_u64(component, "wallet_recovery_vector_count")?;
            ensure(
                scoped_history_recovery_supported
                    && da_payload_audit_supported
                    && transparent_balance_mode_disabled
                    && scoped_disclosure_supported
                    && relay_path_commitments_verified,
                "wallet_recovery_privacy_profile must assert view-key recovery, DA audit, transparent-mode denial, scoped disclosure, and relay commitment verification",
            )?;
            ensure(
                wallet_recovery_vector_count >= 3,
                "wallet_recovery_privacy_profile requires at least three recovery vectors",
            )?;
            Ok(json!({
                "scoped_history_recovery_supported": scoped_history_recovery_supported,
                "da_payload_audit_supported": da_payload_audit_supported,
                "transparent_balance_mode_disabled": transparent_balance_mode_disabled,
                "scoped_disclosure_supported": scoped_disclosure_supported,
                "relay_path_commitments_verified": relay_path_commitments_verified,
                "wallet_recovery_vector_count": wallet_recovery_vector_count,
            }))
        }
        _ => Err(format!(
            "privacy_policy component kind '{kind}' is not required"
        )),
    }
}

