fn validate_operations_readiness_section(
    section: &Value,
) -> Result<OperationsReadinessEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "operations_readiness.passed must be true",
    )?;
    let policy_root = required_root(section, "operations_policy_root")?;
    let runbook_set_root = required_root(section, "runbook_set_root")?;
    let testnet_manifest_id = required_root(section, "testnet_manifest_id")?;
    let local_report_root = required_root(section, "local_operations_readiness_report_root")?;
    let reserve_monitoring_report_root = required_root(section, "reserve_monitoring_report_root")?;
    let latest_block_height = required_u64(section, "latest_block_height")?;
    ensure(
        latest_block_height > 0,
        "operations_readiness.latest_block_height must be positive",
    )?;
    let computed_run_binding_root = operations_readiness_run_binding_root(
        &testnet_manifest_id,
        &local_report_root,
        &reserve_monitoring_report_root,
        latest_block_height,
    );
    let run_binding_root = required_root(section, "run_binding_root")?;
    ensure(
        run_binding_root == computed_run_binding_root,
        "operations_readiness.run_binding_root mismatch",
    )?;
    let components = section
        .get("components")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'components'".to_string())?;
    ensure(
        components.len() == REQUIRED_OPERATIONS_READINESS_COMPONENTS.len(),
        "operations_readiness.components must contain exactly the required operations set",
    )?;
    let mut observed = BTreeSet::new();
    let mut component_roots = Vec::new();
    for (index, component) in components.iter().enumerate() {
        let (kind, evidence_root) = validate_operations_readiness_component(component, index)?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("operations_readiness duplicate component '{kind}'"),
        )?;
        component_roots.push(evidence_root);
    }
    for required in REQUIRED_OPERATIONS_READINESS_COMPONENTS {
        ensure(
            observed.contains(required),
            &format!("operations_readiness missing component '{required}'"),
        )?;
    }
    let mut transcript_roots = vec![
        policy_root.clone(),
        runbook_set_root,
        run_binding_root.clone(),
    ];
    transcript_roots.extend(component_roots);
    let computed_evidence_root =
        collection_root("operations-readiness-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "operations_readiness.evidence_root does not match transcript roots",
    )?;
    Ok(OperationsReadinessEvidence {
        evidence_root,
        component_count: components.len() as u64,
        policy_root,
        run_binding_root,
        testnet_manifest_id,
        local_report_root,
        reserve_monitoring_report_root,
        latest_block_height,
    })
}

