fn operations_readiness_component_claims(component: &Value, kind: &str) -> Result<Value, String> {
    match kind {
        "incident_response_runbook" => {
            let incident_handoff_tested = required_bool(component, "incident_handoff_tested")?;
            let escalation_quorum_verified =
                required_bool(component, "escalation_quorum_verified")?;
            let public_status_template_ready =
                required_bool(component, "public_status_template_ready")?;
            let postmortem_owner_assigned = required_bool(component, "postmortem_owner_assigned")?;
            ensure(
                incident_handoff_tested
                    && escalation_quorum_verified
                    && public_status_template_ready
                    && postmortem_owner_assigned,
                "incident_response_runbook must assert handoff, escalation quorum, status template, and postmortem owner",
            )?;
            Ok(json!({
                "incident_handoff_tested": incident_handoff_tested,
                "escalation_quorum_verified": escalation_quorum_verified,
                "public_status_template_ready": public_status_template_ready,
                "postmortem_owner_assigned": postmortem_owner_assigned,
            }))
        }
        "rollback_drill" => {
            let checkpoint_replay_verified =
                required_bool(component, "checkpoint_replay_verified")?;
            let state_restore_verified = required_bool(component, "state_restore_verified")?;
            let release_guard_reenabled = required_bool(component, "release_guard_reenabled")?;
            let max_recovery_time_minutes = required_u64(component, "max_recovery_time_minutes")?;
            ensure(
                checkpoint_replay_verified && state_restore_verified && release_guard_reenabled,
                "rollback_drill must assert checkpoint replay, state restore, and release guard re-enable",
            )?;
            ensure(
                (1..=60).contains(&max_recovery_time_minutes),
                "rollback_drill requires max_recovery_time_minutes between 1 and 60",
            )?;
            Ok(json!({
                "checkpoint_replay_verified": checkpoint_replay_verified,
                "state_restore_verified": state_restore_verified,
                "release_guard_reenabled": release_guard_reenabled,
                "max_recovery_time_minutes": max_recovery_time_minutes,
            }))
        }
        "withdrawal_queue_drain_drill" => {
            let rate_limit_enforced = required_bool(component, "rate_limit_enforced")?;
            let large_exit_slowdown_verified =
                required_bool(component, "large_exit_slowdown_verified")?;
            let pending_release_reconciled =
                required_bool(component, "pending_release_reconciled")?;
            let queue_drain_vector_count = required_u64(component, "queue_drain_vector_count")?;
            ensure(
                rate_limit_enforced && large_exit_slowdown_verified && pending_release_reconciled,
                "withdrawal_queue_drain_drill must assert rate limit, large-exit slowdown, and pending release reconciliation",
            )?;
            ensure(
                queue_drain_vector_count >= 2,
                "withdrawal_queue_drain_drill requires at least two queue-drain vectors",
            )?;
            Ok(json!({
                "rate_limit_enforced": rate_limit_enforced,
                "large_exit_slowdown_verified": large_exit_slowdown_verified,
                "pending_release_reconciled": pending_release_reconciled,
                "queue_drain_vector_count": queue_drain_vector_count,
            }))
        }
        "bridge_pause_resume_drill" => {
            let pause_blocks_mints = required_bool(component, "pause_blocks_mints")?;
            let pause_blocks_releases = required_bool(component, "pause_blocks_releases")?;
            let resume_requires_quorum = required_bool(component, "resume_requires_quorum")?;
            let challenge_holds_preserved = required_bool(component, "challenge_holds_preserved")?;
            let pause_resume_vector_count = required_u64(component, "pause_resume_vector_count")?;
            ensure(
                pause_blocks_mints
                    && pause_blocks_releases
                    && resume_requires_quorum
                    && challenge_holds_preserved,
                "bridge_pause_resume_drill must assert paused mint/release blocking, quorum resume, and preserved holds",
            )?;
            ensure(
                pause_resume_vector_count >= 2,
                "bridge_pause_resume_drill requires at least two pause/resume vectors",
            )?;
            Ok(json!({
                "pause_blocks_mints": pause_blocks_mints,
                "pause_blocks_releases": pause_blocks_releases,
                "resume_requires_quorum": resume_requires_quorum,
                "challenge_holds_preserved": challenge_holds_preserved,
                "pause_resume_vector_count": pause_resume_vector_count,
            }))
        }
        "reserve_reconciliation_monitoring" => {
            let reserve_liability_reconciled =
                required_bool(component, "reserve_liability_reconciled")?;
            let completed_withdrawals_excluded =
                required_bool(component, "completed_withdrawals_excluded")?;
            let underreserve_alert_tested = required_bool(component, "underreserve_alert_tested")?;
            let independent_reporter_count = required_u64(component, "independent_reporter_count")?;
            let monitoring_cadence_minutes = required_u64(component, "monitoring_cadence_minutes")?;
            ensure(
                reserve_liability_reconciled
                    && completed_withdrawals_excluded
                    && underreserve_alert_tested,
                "reserve_reconciliation_monitoring must assert reserve reconciliation, completed-withdrawal exclusion, and underreserve alerts",
            )?;
            ensure(
                independent_reporter_count >= 2,
                "reserve_reconciliation_monitoring requires at least two independent reporters",
            )?;
            ensure(
                (1..=1440).contains(&monitoring_cadence_minutes),
                "reserve_reconciliation_monitoring requires monitoring_cadence_minutes between 1 and 1440",
            )?;
            Ok(json!({
                "reserve_liability_reconciled": reserve_liability_reconciled,
                "completed_withdrawals_excluded": completed_withdrawals_excluded,
                "underreserve_alert_tested": underreserve_alert_tested,
                "independent_reporter_count": independent_reporter_count,
                "monitoring_cadence_minutes": monitoring_cadence_minutes,
            }))
        }
        _ => Err(format!(
            "operations_readiness component kind '{kind}' is not required"
        )),
    }
}

fn validate_fee_efficiency_section(section: &Value) -> Result<FeeEfficiencyEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "fee_efficiency.passed must be true",
    )?;
    let sample_count = required_u64(section, "sample_count")?;
    let normal_load_tps = required_u64(section, "normal_load_tps")?;
    let l2_p95_fee_piconero = required_u64(section, "l2_p95_fee_piconero")?;
    let monero_l1_reference_fee_piconero =
        required_u64(section, "monero_l1_reference_fee_piconero")?;
    let fee_ratio_bps_value = required_u64(section, "fee_ratio_bps")?;
    ensure(
        sample_count > 0,
        "fee_efficiency.sample_count must be positive",
    )?;
    ensure(
        normal_load_tps > 0,
        "fee_efficiency.normal_load_tps must be positive",
    )?;
    ensure(
        l2_p95_fee_piconero > 0,
        "fee_efficiency.l2_p95_fee_piconero must be positive",
    )?;
    ensure(
        monero_l1_reference_fee_piconero > 0,
        "fee_efficiency.monero_l1_reference_fee_piconero must be positive",
    )?;
    ensure(
        fee_ratio_bps_value == fee_ratio_bps(l2_p95_fee_piconero, monero_l1_reference_fee_piconero),
        "fee_efficiency.fee_ratio_bps mismatch",
    )?;
    ensure(
        fee_ratio_bps_value <= MAX_L2_TO_MONERO_L1_FEE_RATIO_BPS,
        "fee_efficiency.fee_ratio_bps exceeds one-tenth Monero L1 threshold",
    )?;
    ensure(
        l2_p95_fee_piconero.saturating_mul(10) <= monero_l1_reference_fee_piconero,
        "fee_efficiency l2 p95 fee must be below one-tenth Monero L1 reference fee",
    )?;
    let fee_policy_root = required_root(section, "fee_policy_root")?;
    let normal_load_profile_root = required_root(section, "normal_load_profile_root")?;
    let monero_l1_fee_reference_root = required_root(section, "monero_l1_fee_reference_root")?;
    let fee_curve_root = required_root(section, "fee_curve_root")?;
    let evidence_root = required_root(section, "evidence_root")?;
    let computed_evidence_root = fee_efficiency_evidence_root(
        sample_count,
        normal_load_tps,
        l2_p95_fee_piconero,
        monero_l1_reference_fee_piconero,
        fee_ratio_bps_value,
        &fee_policy_root,
        &normal_load_profile_root,
        &monero_l1_fee_reference_root,
        &fee_curve_root,
    );
    ensure(
        evidence_root == computed_evidence_root,
        "fee_efficiency.evidence_root mismatch",
    )?;
    Ok(FeeEfficiencyEvidence {
        evidence_root,
        sample_count,
        normal_load_tps,
        l2_p95_fee_piconero,
        monero_l1_reference_fee_piconero,
        fee_ratio_bps: fee_ratio_bps_value,
    })
}

fn crypto_policy_run_binding_root(
    testnet_manifest_id: &str,
    local_crypto_inventory_report_root: &str,
    local_dependency_inventory_root: &str,
    crypto_policy_root: &str,
    latest_block_height: u64,
) -> String {
    root(&[
        "crypto-policy-run-binding",
        CHAIN_ID,
        testnet_manifest_id,
        local_crypto_inventory_report_root,
        local_dependency_inventory_root,
        crypto_policy_root,
        &latest_block_height.to_string(),
    ])
}

fn validate_crypto_policy_section(section: &Value) -> Result<CryptoPolicyEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "crypto_policy.passed must be true",
    )?;
    let crypto_policy_root = required_root(section, "crypto_policy_root")?;
    ensure(
        crypto_policy_root == pq_crypto_policy_root(),
        "crypto_policy.crypto_policy_root does not match the runner PQ policy",
    )?;
    let dependency_tree_root = required_root(section, "dependency_tree_root")?;
    let production_feature_set_root = required_root(section, "production_feature_set_root")?;
    let denylist_scan_root = required_root(section, "denylist_scan_root")?;
    let allowed_exception_root = required_root(section, "allowed_exception_root")?;
    let testnet_manifest_id = required_root(section, "testnet_manifest_id")?;
    let local_report_root = required_root(section, "local_crypto_inventory_report_root")?;
    let local_dependency_inventory_root =
        required_root(section, "local_dependency_inventory_root")?;
    let latest_block_height = required_u64(section, "latest_block_height")?;
    ensure(
        latest_block_height > 0,
        "crypto_policy.latest_block_height must be positive",
    )?;
    let computed_run_binding_root = crypto_policy_run_binding_root(
        &testnet_manifest_id,
        &local_report_root,
        &local_dependency_inventory_root,
        &crypto_policy_root,
        latest_block_height,
    );
    let run_binding_root = required_root(section, "run_binding_root")?;
    ensure(
        run_binding_root == computed_run_binding_root,
        "crypto_policy.run_binding_root mismatch",
    )?;
    let components = section
        .get("components")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'components'".to_string())?;
    ensure(
        components.len() == REQUIRED_CRYPTO_POLICY_COMPONENTS.len(),
        "crypto_policy.components must contain exactly the required crypto policy set",
    )?;
    let mut observed = BTreeSet::new();
    let mut component_roots = Vec::new();
    for (index, component) in components.iter().enumerate() {
        let (kind, evidence_root) = validate_crypto_policy_component(component, index)?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("crypto_policy duplicate component '{kind}'"),
        )?;
        component_roots.push(evidence_root);
    }
    for required in REQUIRED_CRYPTO_POLICY_COMPONENTS {
        ensure(
            observed.contains(required),
            &format!("crypto_policy missing component '{required}'"),
        )?;
    }
    let mut transcript_roots = vec![
        crypto_policy_root.clone(),
        dependency_tree_root,
        production_feature_set_root,
        denylist_scan_root.clone(),
        allowed_exception_root,
    ];
    transcript_roots.extend(component_roots);
    let computed_evidence_root = collection_root("crypto-policy-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "crypto_policy.evidence_root does not match transcript roots",
    )?;
    Ok(CryptoPolicyEvidence {
        evidence_root,
        component_count: components.len() as u64,
        policy_root: crypto_policy_root,
        denylist_scan_root,
        run_binding_root,
        testnet_manifest_id,
        local_report_root,
        local_dependency_inventory_root,
        latest_block_height,
    })
}

fn validate_crypto_policy_component<'a>(
    component: &'a Value,
    index: usize,
) -> Result<(&'a str, String), String> {
    ensure(
        component.is_object(),
        &format!("crypto_policy component {index} must be an object"),
    )?;
    ensure(
        required_bool(component, "passed")?,
        &format!("crypto_policy component {index} must be passed"),
    )?;
    let kind = required_str(component, "kind")?;
    ensure(
        REQUIRED_CRYPTO_POLICY_COMPONENTS.contains(&kind),
        &format!("crypto_policy component kind '{kind}' is not required"),
    )?;
    let reviewed_at_height = required_u64(component, "reviewed_at_height")?;
    ensure(
        reviewed_at_height > 0,
        &format!("crypto_policy component '{kind}' reviewed_at_height is invalid"),
    )?;
    let reviewer_commitment = required_root(component, "reviewer_commitment")?;
    let scope_root = required_root(component, "scope_root")?;
    let implementation_evidence_root = required_root(component, "implementation_evidence_root")?;
    let test_vector_root = required_root(component, "test_vector_root")?;
    let signoff_root = required_root(component, "signoff_root")?;
    let claims = crypto_policy_component_claims(component, kind)?;
    let evidence_root = required_root(component, "evidence_root")?;
    let computed_evidence_root = crypto_policy_component_root(
        kind,
        reviewed_at_height,
        &reviewer_commitment,
        &scope_root,
        &implementation_evidence_root,
        &test_vector_root,
        &signoff_root,
        &claims,
    );
    ensure(
        evidence_root == computed_evidence_root,
        &format!("crypto_policy component '{kind}' evidence_root mismatch"),
    )?;
    Ok((kind, evidence_root))
}

fn crypto_policy_component_claims(component: &Value, kind: &str) -> Result<Value, String> {
    match kind {
        "ml_dsa_65_authorization_profile" => {
            let account_authorizations_ml_dsa_65 =
                required_bool(component, "account_authorizations_ml_dsa_65")?;
            let validator_votes_ml_dsa_65 = required_bool(component, "validator_votes_ml_dsa_65")?;
            let bridge_actions_pq_bound = required_bool(component, "bridge_actions_pq_bound")?;
            let classical_keys_hybrid_only =
                required_bool(component, "classical_keys_hybrid_only")?;
            let authorization_vector_count = required_u64(component, "authorization_vector_count")?;
            ensure(
                account_authorizations_ml_dsa_65
                    && validator_votes_ml_dsa_65
                    && bridge_actions_pq_bound
                    && classical_keys_hybrid_only,
                "ml_dsa_65_authorization_profile must assert ML-DSA account/validator authorization, PQ bridge binding, and hybrid-only classical keys",
            )?;
            ensure(
                authorization_vector_count >= 3,
                "ml_dsa_65_authorization_profile requires at least three authorization vectors",
            )?;
            Ok(json!({
                "account_authorizations_ml_dsa_65": account_authorizations_ml_dsa_65,
                "validator_votes_ml_dsa_65": validator_votes_ml_dsa_65,
                "bridge_actions_pq_bound": bridge_actions_pq_bound,
                "classical_keys_hybrid_only": classical_keys_hybrid_only,
                "authorization_vector_count": authorization_vector_count,
            }))
        }
        "slh_dsa_recovery_profile" => {
            let recovery_signatures_slh_dsa =
                required_bool(component, "recovery_signatures_slh_dsa")?;
            let recovery_rotation_vectors = required_bool(component, "recovery_rotation_vectors")?;
            let long_lived_recovery_policy_reviewed =
                required_bool(component, "long_lived_recovery_policy_reviewed")?;
            let recovery_vector_count = required_u64(component, "recovery_vector_count")?;
            ensure(
                recovery_signatures_slh_dsa
                    && recovery_rotation_vectors
                    && long_lived_recovery_policy_reviewed,
                "slh_dsa_recovery_profile must assert SLH-DSA recovery signatures, rotation vectors, and long-lived recovery policy review",
            )?;
            ensure(
                recovery_vector_count >= 2,
                "slh_dsa_recovery_profile requires at least two recovery vectors",
            )?;
            Ok(json!({
                "recovery_signatures_slh_dsa": recovery_signatures_slh_dsa,
                "recovery_rotation_vectors": recovery_rotation_vectors,
                "long_lived_recovery_policy_reviewed": long_lived_recovery_policy_reviewed,
                "recovery_vector_count": recovery_vector_count,
            }))
        }
        "ml_kem_768_session_profile" => {
            let wallet_node_sessions_ml_kem_768 =
                required_bool(component, "wallet_node_sessions_ml_kem_768")?;
            let node_node_sessions_ml_kem_768 =
                required_bool(component, "node_node_sessions_ml_kem_768")?;
            let hybrid_x25519_ml_kem_only = required_bool(component, "hybrid_x25519_ml_kem_only")?;
            let kem_transcript_bound = required_bool(component, "kem_transcript_bound")?;
            let session_vector_count = required_u64(component, "session_vector_count")?;
            ensure(
                wallet_node_sessions_ml_kem_768
                    && node_node_sessions_ml_kem_768
                    && hybrid_x25519_ml_kem_only
                    && kem_transcript_bound,
                "ml_kem_768_session_profile must assert ML-KEM wallet/node and node/node sessions, hybrid-only migration, and transcript binding",
            )?;
            ensure(
                session_vector_count >= 2,
                "ml_kem_768_session_profile requires at least two session vectors",
            )?;
            Ok(json!({
                "wallet_node_sessions_ml_kem_768": wallet_node_sessions_ml_kem_768,
                "node_node_sessions_ml_kem_768": node_node_sessions_ml_kem_768,
                "hybrid_x25519_ml_kem_only": hybrid_x25519_ml_kem_only,
                "kem_transcript_bound": kem_transcript_bound,
                "session_vector_count": session_vector_count,
            }))
        }
        "sha3_transcript_domain_profile" => {
            let cshake256_domains = required_bool(component, "cshake256_domains")?;
            let kmac256_tags = required_bool(component, "kmac256_tags")?;
            let tuplehash256_transcripts = required_bool(component, "tuplehash256_transcripts")?;
            let parallelhash256_batch_roots =
                required_bool(component, "parallelhash256_batch_roots")?;
            let domain_collision_tests = required_bool(component, "domain_collision_tests")?;
            let transcript_vector_count = required_u64(component, "transcript_vector_count")?;
            ensure(
                cshake256_domains
                    && kmac256_tags
                    && tuplehash256_transcripts
                    && parallelhash256_batch_roots
                    && domain_collision_tests,
                "sha3_transcript_domain_profile must assert SHA-3 transcript domains, tags, batch roots, and collision tests",
            )?;
            ensure(
                transcript_vector_count >= 4,
                "sha3_transcript_domain_profile requires at least four transcript vectors",
            )?;
            Ok(json!({
                "cshake256_domains": cshake256_domains,
                "kmac256_tags": kmac256_tags,
                "tuplehash256_transcripts": tuplehash256_transcripts,
                "parallelhash256_batch_roots": parallelhash256_batch_roots,
                "domain_collision_tests": domain_collision_tests,
                "transcript_vector_count": transcript_vector_count,
            }))
        }
        "no_pairing_kzg_bls_profile" => {
            let no_bls_signatures = required_bool(component, "no_bls_signatures")?;
            let no_kzg_commitments = required_bool(component, "no_kzg_commitments")?;
            let no_pairing_snarks = required_bool(component, "no_pairing_snarks")?;
            let no_pairing_dependencies = required_bool(component, "no_pairing_dependencies")?;
            let hash_based_da_commitments = required_bool(component, "hash_based_da_commitments")?;
            let non_hybrid_ec_only_auth_rejected =
                required_bool(component, "non_hybrid_ec_only_auth_rejected")?;
            let allowed_exception_count = required_u64(component, "allowed_exception_count")?;
            ensure(
                no_bls_signatures
                    && no_kzg_commitments
                    && no_pairing_snarks
                    && no_pairing_dependencies
                    && hash_based_da_commitments
                    && non_hybrid_ec_only_auth_rejected,
                "no_pairing_kzg_bls_profile must assert no BLS, KZG, pairing SNARKs, pairing dependencies, or non-hybrid EC-only authentication",
            )?;
            ensure(
                allowed_exception_count == 0,
                "no_pairing_kzg_bls_profile requires allowed_exception_count == 0",
            )?;
            Ok(json!({
                "no_bls_signatures": no_bls_signatures,
                "no_kzg_commitments": no_kzg_commitments,
                "no_pairing_snarks": no_pairing_snarks,
                "no_pairing_dependencies": no_pairing_dependencies,
                "hash_based_da_commitments": hash_based_da_commitments,
                "non_hybrid_ec_only_auth_rejected": non_hybrid_ec_only_auth_rejected,
                "allowed_exception_count": allowed_exception_count,
            }))
        }
        _ => Err(format!(
            "crypto_policy component kind '{kind}' is not required"
        )),
    }
}

fn external_review_run_binding_root(
    testnet_manifest_id: &str,
    run_profile_report_root: &str,
    wasm_runtime_report_root: &str,
    crypto_inventory_report_root: &str,
    privacy_surface_report_root: &str,
    operations_readiness_local_report_root: &str,
    latest_block_height: u64,
) -> String {
    root(&[
        "external-review-run-binding",
        CHAIN_ID,
        testnet_manifest_id,
        run_profile_report_root,
        wasm_runtime_report_root,
        crypto_inventory_report_root,
        privacy_surface_report_root,
        operations_readiness_local_report_root,
        &latest_block_height.to_string(),
    ])
}

fn validate_external_review_section(section: &Value) -> Result<ExternalReviewEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "external_review.passed must be true",
    )?;
    let policy_root = required_root(section, "review_policy_root")?;
    let production_readiness_state_root =
        required_root(section, "production_readiness_state_root")?;
    let testnet_manifest_id = required_root(section, "testnet_manifest_id")?;
    let run_profile_report_root = required_root(section, "run_profile_report_root")?;
    let wasm_runtime_report_root = required_root(section, "wasm_runtime_report_root")?;
    let crypto_inventory_report_root = required_root(section, "crypto_inventory_report_root")?;
    let privacy_surface_report_root = required_root(section, "privacy_surface_report_root")?;
    let operations_readiness_local_report_root =
        required_root(section, "operations_readiness_local_report_root")?;
    let latest_block_height = required_u64(section, "latest_block_height")?;
    ensure(
        latest_block_height > 0,
        "external_review.latest_block_height must be positive",
    )?;
    let computed_run_binding_root = external_review_run_binding_root(
        &testnet_manifest_id,
        &run_profile_report_root,
        &wasm_runtime_report_root,
        &crypto_inventory_report_root,
        &privacy_surface_report_root,
        &operations_readiness_local_report_root,
        latest_block_height,
    );
    let run_binding_root = required_root(section, "run_binding_root")?;
    ensure(
        run_binding_root == computed_run_binding_root,
        "external_review.run_binding_root mismatch",
    )?;
    let reviews = section
        .get("reviews")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'reviews'".to_string())?;
    ensure(
        reviews.len() == REQUIRED_EXTERNAL_REVIEW_COMPONENTS.len(),
        "external_review.reviews must contain exactly the required review set",
    )?;
    let mut observed = BTreeSet::new();
    let mut review_roots = Vec::new();
    for (index, review) in reviews.iter().enumerate() {
        let (kind, evidence_root) = validate_external_review_component(review, index)?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("external_review duplicate component '{kind}'"),
        )?;
        review_roots.push(evidence_root);
    }
    for required in REQUIRED_EXTERNAL_REVIEW_COMPONENTS {
        ensure(
            observed.contains(required),
            &format!("external_review missing component '{required}'"),
        )?;
    }
    let mut transcript_roots = vec![policy_root.clone(), production_readiness_state_root];
    transcript_roots.extend(review_roots);
    let computed_evidence_root = collection_root("external-review-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "external_review.evidence_root does not match transcript roots",
    )?;
    Ok(ExternalReviewEvidence {
        evidence_root,
        component_count: reviews.len() as u64,
        policy_root,
        run_binding_root,
        testnet_manifest_id,
        run_profile_report_root,
        wasm_runtime_report_root,
        crypto_inventory_report_root,
        privacy_surface_report_root,
        operations_readiness_local_report_root,
        latest_block_height,
    })
}

fn validate_external_review_component<'a>(
    review: &'a Value,
    index: usize,
) -> Result<(&'a str, String), String> {
    ensure(
        review.is_object(),
        &format!("external_review component {index} must be an object"),
    )?;
    ensure(
        required_bool(review, "passed")?,
        &format!("external_review component {index} must be passed"),
    )?;
    let kind = required_str(review, "kind")?;
    ensure(
        REQUIRED_EXTERNAL_REVIEW_COMPONENTS.contains(&kind),
        &format!("external_review component kind '{kind}' is not required"),
    )?;
    let opened_at_height = required_u64(review, "opened_at_height")?;
    let accepted_at_height = required_u64(review, "accepted_at_height")?;
    ensure(
        opened_at_height > 0 && accepted_at_height >= opened_at_height,
        &format!("external_review component '{kind}' height window is invalid"),
    )?;
    let reviewer_commitment = required_root(review, "reviewer_commitment")?;
    let scope_root = required_root(review, "scope_root")?;
    let report_root = required_root(review, "report_root")?;
    let finding_root = required_root(review, "finding_root")?;
    let remediation_root = required_root(review, "remediation_root")?;
    let signoff_root = required_root(review, "signoff_root")?;
    let evidence_root = required_root(review, "evidence_root")?;
    let computed_evidence_root = root(&[
        "external-review-component",
        CHAIN_ID,
        kind,
        &opened_at_height.to_string(),
        &accepted_at_height.to_string(),
        &reviewer_commitment,
        &scope_root,
        &report_root,
        &finding_root,
        &remediation_root,
        &signoff_root,
    ]);
    ensure(
        evidence_root == computed_evidence_root,
        &format!("external_review component '{kind}' evidence_root mismatch"),
    )?;
    Ok((kind, evidence_root))
}

fn validate_proof_system_audit_section(
    section: &Value,
) -> Result<ProofSystemAuditEvidence, String> {
    ensure(
        required_bool(section, "passed")?,
        "proof_system_audit.passed must be true",
    )?;
    let policy_root = required_root(section, "audit_policy_root")?;
    let proof_system_root = required_root(section, "proof_system_root")?;
    let max_block_count = required_u64(section, "max_block_count")?;
    let max_transaction_count = required_u64(section, "max_transaction_count")?;
    ensure(
        max_block_count > 0,
        "proof_system_audit.max_block_count must be positive",
    )?;
    ensure(
        max_transaction_count > 0,
        "proof_system_audit.max_transaction_count must be positive",
    )?;
    let capacity_root = required_root(section, "capacity_root")?;
    let computed_capacity_root = proof_system_audit_capacity_root(
        max_block_count,
        max_transaction_count,
        &policy_root,
        &proof_system_root,
    );
    ensure(
        capacity_root == computed_capacity_root,
        "proof_system_audit.capacity_root mismatch",
    )?;
    let proof_family = required_str(section, "proof_family")?;
    let commitment_scheme = required_str(section, "commitment_scheme")?;
    let setup_trust_model = required_str(section, "setup_trust_model")?;
    let transparent_or_pq_proof_system = required_bool(section, "transparent_or_pq_proof_system")?;
    let pairing_assumption_used = required_bool(section, "pairing_assumption_used")?;
    ensure(
        proof_family == "transparent-pq-recursive",
        "proof_system_audit.proof_family must be transparent-pq-recursive",
    )?;
    ensure(
        commitment_scheme == "hash-based-merkle",
        "proof_system_audit.commitment_scheme must be hash-based-merkle",
    )?;
    ensure(
        setup_trust_model == "transparent-no-trusted-setup",
        "proof_system_audit.setup_trust_model must be transparent-no-trusted-setup",
    )?;
    ensure(
        transparent_or_pq_proof_system,
        "proof_system_audit.transparent_or_pq_proof_system must be true",
    )?;
    ensure(
        !pairing_assumption_used,
        "proof_system_audit.pairing_assumption_used must be false",
    )?;
    let assumption_root = required_root(section, "assumption_root")?;
    let computed_assumption_root = proof_system_audit_assumption_root(
        proof_family,
        commitment_scheme,
        setup_trust_model,
        transparent_or_pq_proof_system,
        pairing_assumption_used,
        &policy_root,
        &proof_system_root,
    );
    ensure(
        assumption_root == computed_assumption_root,
        "proof_system_audit.assumption_root mismatch",
    )?;
    let components = section
        .get("components")
        .and_then(Value::as_array)
        .ok_or_else(|| "readiness evidence missing array 'components'".to_string())?;
    ensure(
        components.len() == REQUIRED_PROOF_AUDIT_COMPONENTS.len(),
        "proof_system_audit.components must contain exactly the required proof audit set",
    )?;
    let mut observed = BTreeSet::new();
    let mut component_roots = Vec::new();
    for (index, component) in components.iter().enumerate() {
        let (kind, evidence_root) = validate_proof_audit_component(component, index)?;
        ensure(
            observed.insert(kind.to_string()),
            &format!("proof_system_audit duplicate component '{kind}'"),
        )?;
        component_roots.push(evidence_root);
    }
    for required in REQUIRED_PROOF_AUDIT_COMPONENTS {
        ensure(
            observed.contains(required),
            &format!("proof_system_audit missing component '{required}'"),
        )?;
    }
    let mut transcript_roots = vec![
        policy_root.clone(),
        proof_system_root,
        capacity_root.clone(),
        assumption_root,
    ];
    transcript_roots.extend(component_roots);
    let computed_evidence_root = collection_root("proof-system-audit-transcript", transcript_roots);
    let evidence_root = required_root(section, "evidence_root")?;
    ensure(
        evidence_root == computed_evidence_root,
        "proof_system_audit.evidence_root does not match transcript roots",
    )?;
    Ok(ProofSystemAuditEvidence {
        evidence_root,
        component_count: components.len() as u64,
        policy_root,
        capacity_root,
        max_block_count,
        max_transaction_count,
    })
}

fn validate_proof_audit_component<'a>(
    component: &'a Value,
    index: usize,
) -> Result<(&'a str, String), String> {
    ensure(
        component.is_object(),
        &format!("proof_system_audit component {index} must be an object"),
    )?;
    ensure(
        required_bool(component, "passed")?,
        &format!("proof_system_audit component {index} must be passed"),
    )?;
    let kind = required_str(component, "kind")?;
    ensure(
        REQUIRED_PROOF_AUDIT_COMPONENTS.contains(&kind),
        &format!("proof_system_audit component kind '{kind}' is not required"),
    )?;
    let audit_height = required_u64(component, "audit_height")?;
    ensure(
        audit_height > 0,
        &format!("proof_system_audit component '{kind}' audit_height must be positive"),
    )?;
    let auditor_commitment = required_root(component, "auditor_commitment")?;
    let circuit_manifest_root = required_root(component, "circuit_manifest_root")?;
    let public_input_schema_root = required_root(component, "public_input_schema_root")?;
    let test_vector_root = required_root(component, "test_vector_root")?;
    let negative_test_root = required_root(component, "negative_test_root")?;
    let parameter_root = required_root(component, "parameter_root")?;
    let report_root = required_root(component, "report_root")?;
    let evidence_root = required_root(component, "evidence_root")?;
    let computed_evidence_root = root(&[
        "proof-system-audit-component",
        CHAIN_ID,
        kind,
        &audit_height.to_string(),
        &auditor_commitment,
        &circuit_manifest_root,
        &public_input_schema_root,
        &test_vector_root,
        &negative_test_root,
        &parameter_root,
        &report_root,
    ]);
    ensure(
        evidence_root == computed_evidence_root,
        &format!("proof_system_audit component '{kind}' evidence_root mismatch"),
    )?;
    Ok((kind, evidence_root))
}

fn required_section<'a>(value: &'a Value, key: &str) -> Result<&'a Value, String> {
    value
        .get(key)
        .filter(|section| section.is_object())
        .ok_or_else(|| format!("readiness evidence missing object section '{key}'"))
}

fn required_str<'a>(value: &'a Value, key: &str) -> Result<&'a str, String> {
    value
        .get(key)
        .and_then(Value::as_str)
        .filter(|text| !text.trim().is_empty())
        .ok_or_else(|| format!("readiness evidence missing string '{key}'"))
}

fn required_u64(value: &Value, key: &str) -> Result<u64, String> {
    value
        .get(key)
        .and_then(Value::as_u64)
        .ok_or_else(|| format!("readiness evidence missing u64 '{key}'"))
}

fn required_bool(value: &Value, key: &str) -> Result<bool, String> {
    value
        .get(key)
        .and_then(Value::as_bool)
        .ok_or_else(|| format!("readiness evidence missing bool '{key}'"))
}

fn required_root(value: &Value, key: &str) -> Result<String, String> {
    let root = required_str(value, key)?;
    ensure(
        is_hex_root(root),
        &format!("readiness evidence '{key}' must be a 64-character hex root"),
    )?;
    Ok(root.to_string())
}

fn optional_root(value: &Value, key: &str) -> Result<Option<String>, String> {
    match value.get(key) {
        Some(Value::String(root)) => {
            ensure(
                is_hex_root(root),
                &format!("readiness evidence '{key}' must be a 64-character hex root"),
            )?;
            Ok(Some(root.clone()))
        }
        Some(_) => Err(format!("readiness evidence '{key}' must be a string")),
        None => Ok(None),
    }
}

fn public_https_endpoint(endpoint: &str) -> bool {
    endpoint.starts_with("https://") && public_endpoint(endpoint)
}

fn public_endpoint(endpoint: &str) -> bool {
    let trimmed = endpoint.trim();
    if trimmed.is_empty()
        || trimmed != endpoint
        || trimmed.contains('<')
        || trimmed.contains('>')
        || trimmed.chars().any(char::is_whitespace)
    {
        return false;
    }
    let Some(host) = endpoint_host(trimmed) else {
        return false;
    };
    let lowered = host.trim_end_matches('.').to_ascii_lowercase();
    if lowered.is_empty()
        || lowered == "localhost"
        || lowered.ends_with(".localhost")
        || lowered.ends_with(".local")
        || lowered.contains('%')
    {
        return false;
    }
    match lowered.parse::<IpAddr>() {
        Ok(ip) => ip_addr_publicly_routable(ip),
        Err(_) => true,
    }
}

fn endpoint_host(endpoint: &str) -> Option<String> {
    for prefix in ["/dns4/", "/dns6/", "/ip4/", "/ip6/"] {
        if let Some(rest) = endpoint.strip_prefix(prefix) {
            let host = rest.split('/').next().unwrap_or_default();
            if host.is_empty() {
                return None;
            }
            return Some(host.to_string());
        }
    }
    let without_scheme = endpoint
        .find("://")
        .map(|index| &endpoint[index + 3..])
        .unwrap_or(endpoint);
    let authority = without_scheme
        .split(['/', '?', '#'])
        .next()
        .unwrap_or_default();
    if authority.is_empty() || authority.contains('@') {
        return None;
    }
    if let Some(rest) = authority.strip_prefix('[') {
        let end = rest.find(']')?;
        return Some(rest[..end].to_string());
    }
    if authority.matches(':').count() == 1 {
        let (host, _) = authority.split_once(':')?;
        return Some(host.to_string());
    }
    Some(authority.to_string())
}

fn ip_addr_publicly_routable(ip: IpAddr) -> bool {
    match ip {
        IpAddr::V4(ip) => ipv4_addr_publicly_routable(ip),
        IpAddr::V6(ip) => ipv6_addr_publicly_routable(ip),
    }
}

fn ipv4_addr_publicly_routable(ip: Ipv4Addr) -> bool {
    let [a, b, c, _] = ip.octets();
    if a == 0
        || a == 10
        || a == 127
        || (a == 100 && (64..=127).contains(&b))
        || (a == 169 && b == 254)
        || (a == 172 && (16..=31).contains(&b))
        || (a == 192 && b == 168)
        || (a == 192 && b == 0 && c == 0)
        || (a == 192 && b == 0 && c == 2)
        || (a == 198 && (b == 18 || b == 19))
        || (a == 198 && b == 51 && c == 100)
        || (a == 203 && b == 0 && c == 113)
        || a >= 224
    {
        return false;
    }
    true
}

fn ipv6_addr_publicly_routable(ip: Ipv6Addr) -> bool {
    let segments = ip.segments();
    if ip.is_unspecified()
        || ip.is_loopback()
        || segments[0] & 0xfe00 == 0xfc00
        || segments[0] & 0xffc0 == 0xfe80
        || segments[0] & 0xff00 == 0xff00
        || (segments[0] == 0x2001 && segments[1] == 0x0db8)
    {
        return false;
    }
    if segments[..6] == [0, 0, 0, 0, 0, 0] {
        return false;
    }
    if segments[..5] == [0, 0, 0, 0, 0] && segments[5] == 0xffff {
        let a = (segments[6] >> 8) as u8;
        let b = segments[6] as u8;
        let c = (segments[7] >> 8) as u8;
        let d = segments[7] as u8;
        return ipv4_addr_publicly_routable(Ipv4Addr::new(a, b, c, d));
    }
    true
}

#[derive(Clone, Debug)]
struct PublicTlsPinValidation {
    tls_spki_pin_root: String,
    tls_endpoint_pin_set_root: String,
    tls_endpoint_pin_count: u64,
}

fn public_tls_endpoint_specs(
    public_rpc_url: &str,
    status_page_url: &str,
    health_check_url: &str,
    metrics_url: &str,
    incident_contact_url: &str,
    faucet_url: &str,
    reset_runbook_url: &str,
) -> Vec<(&'static str, String)> {
    vec![
        ("public_rpc_url", public_rpc_url.to_string()),
        ("status_page_url", status_page_url.to_string()),
        ("health_check_url", health_check_url.to_string()),
        ("metrics_url", metrics_url.to_string()),
        ("incident_contact_url", incident_contact_url.to_string()),
        ("faucet_url", faucet_url.to_string()),
        ("reset_runbook_url", reset_runbook_url.to_string()),
    ]
}

fn derive_public_tls_endpoint_pin_fields(
    value: &mut Value,
    expected_endpoints: &[(&str, String)],
    public_launch_bundle_root: &str,
    deployment_run_id: &str,
    observed_at_unix_ms: u64,
    expires_at_unix_ms: u64,
) -> Result<PublicTlsPinValidation, String> {
    let pins = value
        .get_mut("tls_endpoint_pins")
        .and_then(Value::as_array_mut)
        .ok_or_else(|| "public deployment capture missing array 'tls_endpoint_pins'".to_string())?;
    for pin in pins {
        let endpoint_role = required_str(pin, "endpoint_role")?.to_string();
        let expected_url = expected_endpoints
            .iter()
            .find(|(role, _)| *role == endpoint_role)
            .map(|(_, endpoint)| endpoint.clone())
            .ok_or_else(|| {
                format!("public deployment TLS pin endpoint_role '{endpoint_role}' is not expected")
            })?;
        {
            let map = pin
                .as_object_mut()
                .ok_or_else(|| "public deployment TLS pin record must be an object".to_string())?;
            if let Some(existing_url) = map.get("url").and_then(Value::as_str) {
                ensure(
                    existing_url == expected_url,
                    "public deployment TLS pin url mismatch",
                )?;
            }
            map.insert("chain_id".to_string(), json!(CHAIN_ID));
            map.insert(
                "public_launch_bundle_root".to_string(),
                json!(public_launch_bundle_root),
            );
            if let Some(existing_run_id) = map.get("deployment_run_id").and_then(Value::as_str) {
                ensure(
                    existing_run_id == deployment_run_id,
                    "public deployment TLS pin deployment_run_id mismatch",
                )?;
            }
            map.insert("deployment_run_id".to_string(), json!(deployment_run_id));
            map.insert("url".to_string(), json!(expected_url));
            map.entry("observed_at_unix_ms".to_string())
                .or_insert_with(|| json!(observed_at_unix_ms));
        }
        let pin_record_root = public_tls_endpoint_pin_record_root(pin)?;
        pin.as_object_mut()
            .ok_or_else(|| "public deployment TLS pin record must be an object".to_string())?
            .insert("pin_record_root".to_string(), json!(pin_record_root));
    }
    validate_public_tls_endpoint_pins(
        value
            .get("tls_endpoint_pins")
            .ok_or_else(|| "public deployment evidence missing tls_endpoint_pins".to_string())?,
        expected_endpoints,
        public_launch_bundle_root,
        deployment_run_id,
        observed_at_unix_ms,
        expires_at_unix_ms,
    )
}

fn validate_public_tls_endpoint_pins(
    value: &Value,
    expected_endpoints: &[(&str, String)],
    public_launch_bundle_root: &str,
    deployment_run_id: &str,
    observed_at_unix_ms: u64,
    expires_at_unix_ms: u64,
) -> Result<PublicTlsPinValidation, String> {
    let pins = value
        .as_array()
        .ok_or_else(|| "public deployment tls_endpoint_pins must be an array".to_string())?;
    ensure(
        pins.len() == expected_endpoints.len(),
        "public deployment TLS pin evidence must cover every HTTPS endpoint",
    )?;
    let mut roles = BTreeSet::new();
    let mut urls = BTreeSet::new();
    let mut spki_pin_roots = Vec::new();
    let mut pin_record_roots = Vec::new();
    for pin in pins {
        ensure_allowed_object_fields(
            pin,
            PUBLIC_TLS_ENDPOINT_PIN_FIELDS,
            "public deployment TLS endpoint pin",
        )?;
        ensure(
            required_str(pin, "chain_id")? == CHAIN_ID,
            "public deployment TLS pin chain_id mismatch",
        )?;
        ensure(
            required_root(pin, "public_launch_bundle_root")? == public_launch_bundle_root,
            "public deployment TLS pin launch bundle root mismatch",
        )?;
        ensure(
            required_str(pin, "deployment_run_id")? == deployment_run_id,
            "public deployment TLS pin deployment_run_id mismatch",
        )?;
        let endpoint_role = required_str(pin, "endpoint_role")?;
        let expected_url = expected_endpoints
            .iter()
            .find(|(role, _)| *role == endpoint_role)
            .map(|(_, endpoint)| endpoint.as_str())
            .ok_or_else(|| {
                format!("public deployment TLS pin endpoint_role '{endpoint_role}' is not expected")
            })?;
        ensure(
            roles.insert(endpoint_role.to_string()),
            "public deployment TLS pin endpoint_role values must be unique",
        )?;
        ensure(
            required_str(pin, "url")? == expected_url,
            "public deployment TLS pin url mismatch",
        )?;
        ensure(
            public_https_endpoint(required_str(pin, "url")?),
            "public deployment TLS pin url must be HTTPS and publicly routable",
        )?;
        ensure(
            urls.insert(required_str(pin, "url")?.to_string()),
            "public deployment TLS pin urls must be unique",
        )?;
        ensure(
            required_str(pin, "tls_version")? == "TLS1.3"
                && required_bool(pin, "hostname_verified")?
                && required_bool(pin, "spki_pin_matched")?
                && required_bool(pin, "certificate_not_expired")?,
            "public deployment TLS pin record must assert TLS1.3, hostname verification, SPKI match, and non-expired certificate",
        )?;
        let observed_at = required_u64(pin, "observed_at_unix_ms")?;
        ensure(
            observed_at >= observed_at_unix_ms && observed_at <= expires_at_unix_ms,
            "public deployment TLS pin observation time is outside freshness window",
        )?;
        let spki_pin_root = required_root(pin, "spki_pin_root")?;
        spki_pin_roots.push(spki_pin_root);
        ensure(
            is_hex_root(&required_root(pin, "certificate_chain_root")?)
                && is_hex_root(&required_root(pin, "issuer_root")?),
            "public deployment TLS pin record must bind certificate chain and issuer roots",
        )?;
        let pin_record_root = public_tls_endpoint_pin_record_root(pin)?;
        ensure(
            required_root(pin, "pin_record_root")? == pin_record_root,
            "public deployment TLS pin record root mismatch",
        )?;
        pin_record_roots.push(pin_record_root);
    }
    ensure(
        roles.len() == expected_endpoints.len() && urls.len() == expected_endpoints.len(),
        "public deployment TLS pin evidence must have unique endpoint coverage",
    )?;
    let tls_endpoint_pin_set_root =
        collection_root("public-deployment-tls-endpoint-pin-set", pin_record_roots);
    let spki_pin_set_root = collection_root("public-deployment-tls-spki-pins", spki_pin_roots);
    let tls_endpoint_pin_count = pins.len() as u64;
    Ok(PublicTlsPinValidation {
        tls_spki_pin_root: root(&[
            "public-deployment-tls-spki-pin-root",
            CHAIN_ID,
            &tls_endpoint_pin_set_root,
            &spki_pin_set_root,
            &tls_endpoint_pin_count.to_string(),
        ]),
        tls_endpoint_pin_set_root,
        tls_endpoint_pin_count,
    })
}

fn expected_tls_pin_validation_for_evidence(
    evidence: &PublicDeploymentEvidence,
) -> Result<PublicTlsPinValidation, String> {
    let endpoint_specs = public_tls_endpoint_specs(
        &evidence.public_rpc_url,
        &evidence.status_page_url,
        &evidence.health_check_url,
        &evidence.metrics_url,
        &evidence.incident_contact_url,
        &evidence.faucet_url,
        &evidence.reset_runbook_url,
    );
    validate_public_tls_endpoint_pins(
        &evidence.tls_endpoint_pins,
        &endpoint_specs,
        &evidence.public_launch_bundle_root,
        &evidence.deployment_run_id,
        evidence.observed_at_unix_ms,
        evidence.expires_at_unix_ms,
    )
}

fn public_tls_endpoint_pin_record_root(pin: &Value) -> Result<String, String> {
    Ok(root(&[
        "public-deployment-tls-endpoint-pin",
        CHAIN_ID,
        required_root(pin, "public_launch_bundle_root")?.as_str(),
        required_str(pin, "deployment_run_id")?,
        required_str(pin, "endpoint_role")?,
        required_str(pin, "url")?,
        required_root(pin, "spki_pin_root")?.as_str(),
        required_root(pin, "certificate_chain_root")?.as_str(),
        required_root(pin, "issuer_root")?.as_str(),
        required_str(pin, "tls_version")?,
        bool_str(required_bool(pin, "hostname_verified")?),
        bool_str(required_bool(pin, "spki_pin_matched")?),
        bool_str(required_bool(pin, "certificate_not_expired")?),
        &required_u64(pin, "observed_at_unix_ms")?.to_string(),
    ]))
}

fn value_contains_placeholder(value: &Value) -> bool {
    match value {
        Value::String(text) => {
            text.contains("<fill-in") || text == ROOT_PLACEHOLDER || text.contains("<64-hex-root>")
        }
        Value::Object(map) => map.values().any(value_contains_placeholder),
        Value::Array(values) => values.iter().any(value_contains_placeholder),
        _ => false,
    }
}

fn validate_public_status_manifest_payload(value: &Value) -> Result<String, String> {
    ensure(
        value.get("kind").and_then(Value::as_str) == Some("nebula-public-status-manifest"),
        "public deployment evidence status manifest kind mismatch",
    )?;
    ensure(
        value.get("chain_id").and_then(Value::as_str) == Some(CHAIN_ID),
        "public deployment evidence status manifest chain_id mismatch",
    )?;
    ensure(
        value.get("version").and_then(Value::as_str) == Some(VERSION),
        "public deployment evidence status manifest version mismatch",
    )?;
    ensure_public_status_manifest_redacted(value)?;
    let declared_root = required_root(value, "public_status_manifest_root")?;
    let mut root_payload = value.clone();
    let Some(map) = root_payload.as_object_mut() else {
        return Err("public deployment evidence status manifest must be an object".to_string());
    };
    map.remove("public_status_manifest_root");
    let computed_root = value_root("public-status-manifest", &root_payload);
    ensure(
        declared_root == computed_root,
        "public deployment evidence embedded public_status_manifest_root mismatch",
    )?;
    Ok(computed_root)
}

