fn validate_public_metrics_probe(
    value: &Value,
    public_status_manifest: &Value,
    public_status_manifest_root: &str,
    public_launch_bundle_root: &str,
) -> Result<(), String> {
    let finality = required_section(public_status_manifest, "finality")?;
    let acceptance = required_section(public_status_manifest, "acceptance")?;
    let target_finality_micros = required_u64(finality, "target_finality_micros")?;
    let p95_finality_micros =
        required_u64(finality, "p95_local_quorum_certificate_latency_micros")?;
    ensure_allowed_object_fields(
        value,
        PUBLIC_METRICS_PROBE_FIELDS,
        "public deployment metrics probe",
    )?;
    ensure(
        required_str(value, "status")? == "ok",
        "public deployment metrics probe status must be ok",
    )?;
    ensure(
        required_str(value, "chain_id")? == CHAIN_ID,
        "public deployment metrics probe chain_id mismatch",
    )?;
    ensure(
        required_root(value, "public_status_manifest_root")? == public_status_manifest_root,
        "public deployment metrics probe status manifest root mismatch",
    )?;
    ensure(
        required_root(value, "public_launch_bundle_root")? == public_launch_bundle_root,
        "public deployment metrics probe launch bundle root mismatch",
    )?;
    ensure(
        required_u64(value, "target_finality_micros")? == target_finality_micros,
        "public deployment metrics probe target finality mismatch",
    )?;
    ensure(
        required_u64(value, "p95_local_quorum_certificate_latency_micros")? == p95_finality_micros,
        "public deployment metrics probe p95 finality mismatch",
    )?;
    ensure(
        target_finality_micros <= 200_000 && p95_finality_micros <= target_finality_micros,
        "public deployment metrics probe finality exceeds 200ms target",
    )?;
    ensure(
        required_bool(value, "finality_target_met")?
            == required_bool(acceptance, "finality_target_met")?,
        "public deployment metrics probe finality target flag mismatch",
    )?;
    ensure(
        required_bool(value, "reserve_covered")? == required_bool(acceptance, "reserve_covered")?,
        "public deployment metrics probe reserve flag mismatch",
    )?;
    ensure(
        required_bool(value, "no_mainnet_custody")?,
        "public deployment metrics probe must assert no-mainnet-custody",
    )
}

fn validate_public_deployed_finality_probe(
    value: &Value,
    public_status_manifest: &Value,
    public_status_manifest_root: &str,
    public_launch_bundle_root: &str,
) -> Result<(), String> {
    let finality = required_section(public_status_manifest, "finality")?;
    let public_manifest_id = required_root(public_status_manifest, "manifest_id")?;
    let latest_block_height = required_u64(public_status_manifest, "latest_block_height")?;
    let target_finality_micros = required_u64(finality, "target_finality_micros")?;
    let required_sample_count =
        required_u64(finality, "loopback_distributed_finality_sample_count")?;
    let required_validator_count =
        required_u64(finality, "loopback_distributed_finality_validator_count")?;
    let required_validator_threshold = required_u64(
        finality,
        "loopback_distributed_finality_validator_threshold",
    )?;
    let required_region_count =
        required_u64(finality, "loopback_distributed_finality_region_count")?;
    ensure_allowed_object_fields(
        value,
        PUBLIC_DEPLOYED_FINALITY_PROBE_FIELDS,
        "public deployment deployed finality probe",
    )?;
    ensure(
        required_str(value, "status")? == "ok",
        "public deployment deployed finality probe status must be ok",
    )?;
    ensure(
        required_str(value, "chain_id")? == CHAIN_ID,
        "public deployment deployed finality probe chain_id mismatch",
    )?;
    ensure(
        required_root(value, "public_status_manifest_root")? == public_status_manifest_root,
        "public deployment deployed finality probe status manifest root mismatch",
    )?;
    ensure(
        required_root(value, "public_launch_bundle_root")? == public_launch_bundle_root,
        "public deployment deployed finality probe launch bundle root mismatch",
    )?;
    ensure(
        required_root(value, "testnet_manifest_id")? == public_manifest_id,
        "public deployment deployed finality probe manifest id mismatch",
    )?;
    ensure(
        required_u64(value, "latest_block_height")? == latest_block_height,
        "public deployment deployed finality probe latest height mismatch",
    )?;
    ensure(
        required_u64(value, "sample_count")? >= required_sample_count,
        "public deployment deployed finality probe sample count below public manifest",
    )?;
    let validator_count = required_u64(value, "validator_count")?;
    let validator_threshold = required_u64(value, "validator_threshold")?;
    ensure(
        validator_count >= required_validator_count,
        "public deployment deployed finality probe validator count below public manifest",
    )?;
    ensure(
        validator_threshold >= required_validator_threshold
            && validator_threshold <= validator_count
            && quorum_reaches_threshold(validator_threshold, validator_count),
        "public deployment deployed finality probe validator threshold below public manifest",
    )?;
    ensure(
        required_u64(value, "region_count")? >= required_region_count,
        "public deployment deployed finality probe region count below public manifest",
    )?;
    ensure(
        required_u64(value, "target_finality_micros")? == target_finality_micros
            && target_finality_micros <= 200_000,
        "public deployment deployed finality probe target finality mismatch",
    )?;
    let p95_quorum_certificate_micros = required_u64(value, "p95_quorum_certificate_micros")?;
    let max_quorum_certificate_micros = required_u64(value, "max_quorum_certificate_micros")?;
    ensure(
        p95_quorum_certificate_micros <= max_quorum_certificate_micros
            && p95_quorum_certificate_micros <= target_finality_micros
            && max_quorum_certificate_micros <= target_finality_micros
            && required_bool(value, "all_samples_under_target")?,
        "public deployment deployed finality probe exceeds <=200ms target",
    )?;
    ensure(
        is_hex_root(&required_root(value, "network_profile_root")?)
            && is_hex_root(&required_root(value, "clock_sync_root")?)
            && is_hex_root(&required_root(value, "sample_set_root")?),
        "public deployment deployed finality probe roots must be bound",
    )
}

