fn required_string_list(value: &Value, key: &str) -> Result<Vec<String>, String> {
    let list = value
        .get(key)
        .and_then(Value::as_array)
        .ok_or_else(|| format!("readiness evidence missing string array '{key}'"))?;
    let mut out = Vec::with_capacity(list.len());
    for item in list {
        let text = item
            .as_str()
            .ok_or_else(|| format!("readiness evidence '{key}' must contain only strings"))?;
        out.push(text.to_string());
    }
    Ok(out)
}

