fn value_root<T: Serialize>(label: &str, value: &T) -> String {
    let encoded = serde_json::to_string(value).unwrap_or_else(|error| {
        json!({
            "encoding_error": error.to_string(),
            "timestamp": unix_time_ms(),
        })
        .to_string()
    });
    root(&[label, &encoded])
}

fn root(parts: &[&str]) -> String {
    let mut hasher = Sha3_256::new();
    for part in parts {
        hasher.update((part.len() as u64).to_le_bytes());
        hasher.update(part.as_bytes());
    }
    hex::encode(hasher.finalize())
}

fn ensure(condition: bool, message: &str) -> Result<(), String> {
    if condition {
        Ok(())
    } else {
        Err(message.to_string())
    }
}

fn readiness_check(id: &str, passed: bool, detail: &str, evidence_root: &str) -> ReadinessCheck {
    ReadinessCheck {
        id: id.to_string(),
        status: if passed { "pass" } else { "blocked" }.to_string(),
        detail: detail.to_string(),
        evidence_root: evidence_root.to_string(),
    }
}

