    #[test]
    fn run_profile_local_fails_unsafe_profiles() {
        let base = Cli::default();
        let mut mainnet_network = base.clone();
        mainnet_network.monero_network = "mainnet".to_string();
        let report = run_profile_report_from_cli(&mainnet_network);
        assert!(!report.passed);
        assert!(!report.no_mainnet_network);
        assert!(!report.network_profile_allowed);

        let mut public_rpc = base.clone();
        public_rpc.rpc_bind = "0.0.0.0:58480".to_string();
        let report = run_profile_report_from_cli(&public_rpc);
        assert!(!report.passed);
        assert!(!report.rpc_bind_loopback);

        let mut weak_watchtowers = base.clone();
        weak_watchtowers.watchtower_count = 1;
        let report = run_profile_report_from_cli(&weak_watchtowers);
        assert!(!report.passed);
        assert!(!report.watchtower_quorum_valid);

        let mut no_release_delay = base.clone();
        no_release_delay.release_delay_blocks = 0;
        let report = run_profile_report_from_cli(&no_release_delay);
        assert!(!report.passed);
        assert!(!report.release_window_valid);

        let mut undersized_anchor = base.clone();
        undersized_anchor.anchor_capacity_tx = DEFAULT_ANCHOR_CAPACITY_TX - 1;
        let report = run_profile_report_from_cli(&undersized_anchor);
        assert!(!report.passed);
        assert!(!report.anchor_capacity_valid);
    }

    #[test]
    fn run_checkpoint_root_changes_when_run_profile_changes() {
        let baseline = test_run_checkpoint_root(Cli::default());
        let variants = vec![
            Cli {
                deposit_piconero: Cli::default().deposit_piconero + 1,
                ..Cli::default()
            },
            Cli {
                withdraw_piconero: Cli::default().withdraw_piconero + 1,
                ..Cli::default()
            },
            Cli {
                release_delay_blocks: Cli::default().release_delay_blocks + 1,
                ..Cli::default()
            },
            Cli {
                release_rate_limit_piconero: Cli::default().release_rate_limit_piconero + 1,
                ..Cli::default()
            },
            Cli {
                anchor_capacity_tx: DEFAULT_ANCHOR_CAPACITY_TX * 2,
                ..Cli::default()
            },
        ];
        for variant in variants {
            assert_ne!(baseline, test_run_checkpoint_root(variant));
        }
    }

