    #[test]
    fn public_endpoint_rejects_private_or_reserved_ip_literals() {
        for endpoint in [
            "10.0.0.1:58481",
            "100.64.0.1:58481",
            "127.0.0.1:58481",
            "169.254.1.10:58481",
            "172.16.0.1:58481",
            "192.168.1.10:58481",
            "192.0.2.10:58481",
            "198.51.100.10:58481",
            "203.0.113.10:58481",
            "224.0.0.1:58481",
            "[::1]:58481",
            "[fc00::1]:58481",
            "[fe80::1]:58481",
            "[2001:db8::1]:58481",
            "/ip4/10.0.0.1/tcp/58481",
            "/ip6/fc00::1/tcp/58481",
            "https://node.local/status",
            "https://localhost/status",
        ] {
            assert!(
                !public_endpoint(endpoint),
                "endpoint should not be public: {endpoint}"
            );
        }
        assert!(public_endpoint("node-a.public.nebula.example:58481"));
        assert!(public_endpoint("/dns4/p2p.public.nebula.example/tcp/58481"));
        assert!(public_endpoint("/ip4/8.8.8.8/tcp/58481"));
        assert!(public_https_endpoint(
            "https://rpc.public.nebula.example/status"
        ));
        assert!(public_endpoint("8.8.8.8:58481"));
        assert!(public_https_endpoint(
            "https://[2606:4700:4700::1111]/status"
        ));
    }

