    #[test]
    fn probe_validation_rejects_malformed_status_surfaces() {
        let cli = Cli::default();
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        let status_json =
            serde_json::to_string(&public_status_manifest(&summary)).expect("status json");
        validate_probe_response("rpc", &status_json, &status_json).expect("valid rpc status");
        validate_probe_response(
            "p2p",
            &format!("nebula-testnet {}", root(&["p2p", CHAIN_ID, &status_json])),
            &status_json,
        )
        .expect("valid p2p status");

        let rpc_error = validate_probe_response("rpc", "not-json", &status_json)
            .expect_err("malformed rpc response must fail");
        assert!(rpc_error.contains("not valid json"));
        let p2p_error = validate_probe_response("p2p", "nebula-testnet bad-root", &status_json)
            .expect_err("wrong p2p root must fail");
        assert!(p2p_error.contains("handshake root mismatch"));
    }

    #[test]
    fn public_status_manifest_is_redacted_and_probe_valid() {
        let cli = Cli::default();
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        let manifest = public_status_manifest(&summary);
        ensure_public_status_manifest_redacted(&manifest).expect("redacted public status");
        assert_eq!(manifest["kind"], "nebula-public-status-manifest");
        assert_eq!(manifest["chain_id"], CHAIN_ID);
        assert_eq!(manifest["version"], VERSION);
        assert_eq!(manifest["custody_mode"], "no-mainnet-custody");
        assert_eq!(
            manifest["public_bootstrap"]["public_bind_not_enabled_by_runner"],
            true
        );
        assert_eq!(
            manifest["public_bootstrap"]["endpoint_commitments_only"],
            true
        );
        for forbidden in PUBLIC_STATUS_FORBIDDEN_KEYS {
            assert!(
                !value_contains_exact_key(&manifest, forbidden),
                "public status leaked forbidden key {forbidden}"
            );
        }
        let status_json = serde_json::to_string(&manifest).expect("public status json");
        validate_probe_response("rpc", &status_json, &status_json).expect("valid public rpc");
    }

    #[test]
    fn adversarial_self_test_reports_local_fault_injection() {
        let cli = parse_cli(vec!["--adversarial-self-test".to_string()])
            .expect("adversarial self-test flag should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        let report = summary
            .fault_injection
            .as_ref()
            .expect("fault injection report");
        assert!(report.passed);
        assert_eq!(report.scenario_count, 4);
        assert!(summary.acceptance.local_adversarial_self_test);
        assert!(summary
            .mainnet_readiness
            .checks
            .iter()
            .any(|check| check.id == "local-adversarial-self-test" && check.status == "pass"));
        for required in [
            "validator_fault_injection",
            "bridge_fault_injection",
            "da_fault_injection",
            "solver_fault_injection",
        ] {
            assert!(report
                .scenarios
                .iter()
                .any(|scenario| scenario.id == required && scenario.passed));
        }
    }

