    #[test]
    fn public_bootstrap_profile_export_is_redacted_template() {
        let path = temp_json_path("nebula-public-bootstrap-profile");
        let cli = parse_cli(vec![
            "--mainnet-readiness".to_string(),
            "--write-public-bootstrap-profile".to_string(),
            path.clone(),
        ])
        .expect("public bootstrap profile flag should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_bootstrap_profile(&path, &summary).expect("write public bootstrap profile");
        let value: Value = serde_json::from_slice(&fs::read(&path).expect("read profile"))
            .expect("public bootstrap profile json");
        assert_eq!(value["kind"], "nebula-public-testnet-bootstrap-profile");
        assert_eq!(value["template_only"], true);
        assert_eq!(value["usable_as_mainnet_custody_approval"], false);
        assert_eq!(
            value["public_bootstrap_profile"]["report_root"],
            summary.public_bootstrap_profile.report_root
        );
        assert_eq!(
            value["endpoint_policy"]["public_rpc_url"],
            "<fill-in-deployment-tooling>"
        );
        assert_eq!(
            value["endpoint_policy"]["public_bind_not_enabled_by_runner"],
            true
        );
        assert_eq!(
            value["bootnodes"]["bootstrap_node_set_root"],
            summary.public_bootstrap_profile.bootstrap_node_set_root
        );
        assert_eq!(
            value["bootnodes"]["bootstrap_operator_set_root"],
            summary.public_bootstrap_profile.bootstrap_operator_set_root
        );
        assert_eq!(
            value["bootnodes"]["bootstrap_operator_count"],
            summary.public_bootstrap_profile.bootstrap_operator_count
        );
        assert_eq!(
            value["bootnodes"]["minimum_bootstrap_operator_count"],
            MIN_PUBLIC_DEPLOYMENT_OPERATOR_COUNT
        );
        assert_eq!(
            value["bootnodes"]["bootstrap_region_set_root"],
            summary.public_bootstrap_profile.bootstrap_region_set_root
        );
        assert_eq!(
            value["bootnodes"]["bootstrap_node_commitments"]
                .as_array()
                .expect("bootstrap node commitments")
                .len(),
            summary.public_bootstrap_profile.bootstrap_node_count as usize
        );
        assert_eq!(
            value["operator_registry"]["operator_set_root"],
            summary.public_bootstrap_profile.bootstrap_operator_set_root
        );
        assert_eq!(
            value["operator_registry"]["operator_count"],
            summary.public_bootstrap_profile.bootstrap_operator_count
        );
        assert_eq!(
            value["operator_registry"]["coverage_rule"],
            "exactly-one-registry-record-per-committed-operator"
        );
        assert_eq!(
            value["operator_registry"]["independence_verified_required"],
            true
        );
        assert_eq!(value["operator_registry"]["signature_scheme"], "ML-DSA-65");
        assert_eq!(
            value["operator_registry"]["registry_template"]
                .as_array()
                .expect("operator registry template")
                .len(),
            summary.public_bootstrap_profile.bootstrap_operator_count as usize
        );
        assert_eq!(
            value["acceptance_snapshot"]["public_bootstrap_profile_available"],
            true
        );
        assert!(is_hex_root(
            value["template_root"].as_str().expect("template root")
        ));
        ensure_public_bootstrap_profile_template_redacted(&value)
            .expect("redacted public bootstrap profile");
        let _ = fs::remove_file(path);
    }

    #[test]
    fn public_bootstrap_profile_rejects_re_rooted_wrong_version() {
        let cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet-readiness CLI should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        let mut value = public_bootstrap_profile_template(&summary);
        value["version"] = json!("nebula-testnet-wrong-version");
        let mut rootless = value.clone();
        if let Some(map) = rootless.as_object_mut() {
            map.remove("template_root");
        }
        value["template_root"] = json!(value_root("public-bootstrap-profile-template", &rootless));

        let error = ensure_public_bootstrap_profile_template_redacted(&value)
            .expect_err("re-rooted wrong-version profile should fail identity guard");
        assert!(error.contains("public bootstrap profile version mismatch"));
    }

