    #[test]
    fn public_status_manifest_verifier_rejects_re_rooted_stale_manifest() {
        let path = temp_json_path("nebula-public-status-manifest-stale");
        let cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet-readiness CLI should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_status_manifest(&path, &summary).expect("write public status manifest");
        verify_public_status_manifest(&path, &summary)
            .expect("fresh public status manifest should verify");

        let mut stale: Value = serde_json::from_slice(&fs::read(&path).expect("read status"))
            .expect("public status manifest json");
        stale["latest_block_height"] = json!(summary.latest_block_height + 1);
        let mut rootless = stale.clone();
        if let Some(map) = rootless.as_object_mut() {
            map.remove("public_status_manifest_root");
        }
        stale["public_status_manifest_root"] =
            json!(value_root("public-status-manifest", &rootless));
        ensure_public_status_manifest_redacted(&stale)
            .expect("re-rooted status manifest should still be redacted");
        fs::write(
            &path,
            format!(
                "{}\n",
                serde_json::to_string_pretty(&stale).expect("encode stale status manifest")
            ),
        )
        .expect("write stale status manifest");

        let error = verify_public_status_manifest(&path, &summary)
            .expect_err("re-rooted stale status manifest should fail exact verification");
        assert!(error.contains("latest_block_height mismatch"));
        let _ = fs::remove_file(path);
    }

    #[test]
    fn public_deployment_runbook_export_is_redacted_handoff() {
        let path = temp_json_path("nebula-public-deployment-runbook");
        let cli = parse_cli(vec![
            "--mainnet-readiness".to_string(),
            "--write-public-deployment-runbook".to_string(),
            path.clone(),
        ])
        .expect("public deployment runbook flag should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_deployment_runbook(&path, &summary).expect("write public deployment runbook");
        let value: Value = serde_json::from_slice(&fs::read(&path).expect("read runbook"))
            .expect("public deployment runbook json");
        let expected_status = public_status_manifest(&summary);
        let expected_status_root = expected_status["public_status_manifest_root"]
            .as_str()
            .expect("expected status root");
        assert_eq!(value["kind"], "nebula-public-deployment-runbook");
        assert_eq!(value["schema_version"], 1);
        assert_eq!(value["template_only"], true);
        assert_eq!(value["operator_fill_required"], true);
        assert_eq!(value["public_alpha_only"], true);
        assert_eq!(value["usable_as_public_deployment_evidence"], false);
        assert_eq!(value["usable_as_mainnet_custody_approval"], false);
        assert_eq!(value["custody_mode"], "no-mainnet-custody");
        assert_eq!(value["public_status_manifest_root"], expected_status_root);
        assert_eq!(
            value["public_bootstrap_profile_root"],
            summary.public_bootstrap_profile.profile_root
        );
        assert_eq!(
            value["deployment_runbook_root"],
            summary.public_bootstrap_profile.deployment_runbook_root
        );
        assert_eq!(
            value["source_roots"]["operations_runbook_set_root"],
            summary.operations_readiness_local.runbook_set_root
        );
        assert_eq!(
            value["source_roots"]["operations_incident_handoff_root"],
            summary.operations_readiness_local.incident_handoff_root
        );
        assert_eq!(
            value["runbook_contract"]["runner_public_listener_allowed"],
            false
        );
        assert_eq!(
            value["runbook_contract"]["serve_public_status_manifest_only"],
            true
        );
        assert_eq!(
            value["runbook_contract"]["full_operator_summary_publication_allowed"],
            false
        );
        assert_eq!(
            value["runbook_contract"]["mainnet_custody_enablement_allowed"],
            false
        );
        assert_eq!(value["mainnet_boundary"]["mainnet_value_ready"], false);
        assert_eq!(
            value["mainnet_boundary"]["mainnet_custody_enablement_allowed"],
            false
        );
        let ordered_step_ids = value["ordered_step_ids"]
            .as_array()
            .expect("ordered step ids")
            .iter()
            .map(|step| step.as_str().expect("step id"))
            .collect::<Vec<_>>();
        assert_eq!(ordered_step_ids, PUBLIC_DEPLOYMENT_RUNBOOK_STEPS.to_vec());
        let contract_step_ids = value["runbook_contract"]["ordered_steps_required"]
            .as_array()
            .expect("contract step ids")
            .iter()
            .map(|step| step.as_str().expect("contract step id"))
            .collect::<Vec<_>>();
        assert_eq!(contract_step_ids, PUBLIC_DEPLOYMENT_RUNBOOK_STEPS.to_vec());
        let steps = value["steps"].as_array().expect("runbook steps");
        assert_eq!(steps.len(), PUBLIC_DEPLOYMENT_RUNBOOK_STEPS.len());
        for (index, step) in steps.iter().enumerate() {
            assert_eq!(
                step["order"].as_u64().expect("step order"),
                (index + 1) as u64
            );
            assert_eq!(step["step_id"], PUBLIC_DEPLOYMENT_RUNBOOK_STEPS[index]);
            assert_eq!(step["required"], true);
            assert_eq!(step["blocks_public_launch"], true);
            assert_eq!(step["operator_fill_required"], true);
            assert_eq!(step["usable_as_public_deployment_evidence"], false);
            assert_eq!(step["usable_as_mainnet_custody_approval"], false);
            assert_eq!(step["mainnet_custody_allowed"], false);
            assert!(is_hex_root(
                step["source_root"].as_str().expect("step source root")
            ));
            assert!(is_hex_root(step["step_root"].as_str().expect("step root")));
        }
        assert!(is_hex_root(
            value["runbook_contract"]["runbook_contract_root"]
                .as_str()
                .expect("runbook contract root")
        ));
        assert!(is_hex_root(
            value["step_set_root"].as_str().expect("step set root")
        ));
        assert!(is_hex_root(
            value["public_deployment_runbook_root"]
                .as_str()
                .expect("runbook root")
        ));
        assert!(!value_contains_exact_key(&value, "mainnet_readiness"));
        assert!(!value_contains_exact_key(&value, "public_launch_readiness"));
        ensure_public_deployment_runbook_redacted(&value).expect("redacted runbook");
        let _ = fs::remove_file(path);
    }

