    #[test]
    fn public_launch_artifact_manifest_export_freezes_precapture_handoff_roots() {
        let path = temp_json_path("nebula-public-launch-artifacts");
        let cli = parse_cli(vec![
            "--mainnet-readiness".to_string(),
            "--write-public-launch-artifact-manifest".to_string(),
            path.clone(),
        ])
        .expect("public launch artifact manifest flag should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_launch_artifact_manifest(&path, &summary)
            .expect("write public launch artifact manifest");
        let value: Value = serde_json::from_slice(&fs::read(&path).expect("read manifest"))
            .expect("public launch artifact manifest json");
        let expected_status = public_status_manifest(&summary);
        let expected_profile = public_bootstrap_profile_template(&summary);
        let expected_runbook = public_deployment_runbook(&summary);
        let expected_bundle = public_launch_bundle(&summary);
        let expected_release_approval = release_approval_template_for_summary(&summary);
        let expected_release_approval_root =
            value_root("release-approval-template", &expected_release_approval);
        let expected_release_registry = release_authority_registry_template();
        let expected_release_registry_root = value_root(
            "release-authority-registry-template",
            &expected_release_registry,
        );
        assert_eq!(value["kind"], "nebula-public-launch-artifact-manifest");
        assert_eq!(value["schema_version"], 1);
        assert_eq!(value["operator_fill_required"], false);
        assert_eq!(value["pre_capture_handoff_manifest"], true);
        assert_eq!(value["usable_as_public_deployment_evidence"], false);
        assert_eq!(value["usable_as_mainnet_custody_approval"], false);
        assert_eq!(value["custody_mode"], "no-mainnet-custody");
        assert_eq!(value["artifact_count"], 6);
        assert_eq!(
            value["source_roots"]["public_status_manifest_root"],
            expected_status["public_status_manifest_root"]
        );
        assert_eq!(
            value["source_roots"]["public_bootstrap_profile_root"],
            summary.public_bootstrap_profile.profile_root
        );
        assert_eq!(
            value["source_roots"]["public_bootstrap_profile_template_root"],
            expected_profile["template_root"]
        );
        assert_eq!(
            value["source_roots"]["public_deployment_runbook_root"],
            expected_runbook["public_deployment_runbook_root"]
        );
        assert_eq!(
            value["source_roots"]["public_deployment_runbook_step_set_root"],
            expected_runbook["step_set_root"]
        );
        assert_eq!(
            value["source_roots"]["public_launch_bundle_root"],
            expected_bundle["public_launch_bundle_root"]
        );
        assert_eq!(
            value["source_roots"]["release_approval_template_root"],
            expected_release_approval_root
        );
        assert_eq!(
            value["source_roots"]["release_authority_registry_template_root"],
            expected_release_registry_root
        );
        let artifacts = value["artifacts"]
            .as_array()
            .expect("public launch artifacts");
        let artifact_ids = artifacts
            .iter()
            .map(|artifact| artifact["artifact_id"].as_str().expect("artifact id"))
            .collect::<Vec<_>>();
        assert_eq!(
            artifact_ids,
            vec![
                "public-status-manifest",
                "public-bootstrap-profile-template",
                "public-deployment-runbook",
                "public-launch-bundle",
                "release-approval-template",
                "release-authority-registry-template"
            ]
        );
        assert_eq!(
            artifacts[0]["root"],
            expected_status["public_status_manifest_root"]
        );
        assert_eq!(artifacts[1]["root"], expected_profile["template_root"]);
        assert_eq!(
            artifacts[2]["root"],
            expected_runbook["public_deployment_runbook_root"]
        );
        assert_eq!(
            artifacts[3]["root"],
            expected_bundle["public_launch_bundle_root"]
        );
        assert_eq!(artifacts[4]["root"], expected_release_approval_root);
        assert_eq!(artifacts[5]["root"], expected_release_registry_root);
        let mut expected_record_roots = Vec::new();
        for (index, artifact) in artifacts.iter().enumerate() {
            assert_eq!(artifact["order"], index + 1);
            assert_eq!(artifact["required_before_capture"], true);
            assert_eq!(artifact["usable_as_public_deployment_evidence"], false);
            assert_eq!(artifact["usable_as_mainnet_custody_approval"], false);
            assert!(is_hex_root(
                artifact["artifact_record_root"]
                    .as_str()
                    .expect("artifact record root")
            ));
            let expected_record_root = public_launch_artifact_record_root(
                &summary.manifest_id,
                artifact["artifact_id"].as_str().expect("artifact id"),
                artifact["kind"].as_str().expect("artifact kind"),
                artifact["export_flag"].as_str().expect("export flag"),
                artifact["root_field"].as_str().expect("root field"),
                artifact["root"].as_str().expect("artifact root"),
                index + 1,
                artifact["operator_private"]
                    .as_bool()
                    .expect("operator private"),
                artifact["publishable"].as_bool().expect("publishable"),
                true,
                false,
                false,
            );
            assert_eq!(artifact["artifact_record_root"], expected_record_root);
            let metadata_tampered_record_root = public_launch_artifact_record_root(
                &summary.manifest_id,
                artifact["artifact_id"].as_str().expect("artifact id"),
                artifact["kind"].as_str().expect("artifact kind"),
                artifact["export_flag"].as_str().expect("export flag"),
                artifact["root_field"].as_str().expect("root field"),
                artifact["root"].as_str().expect("artifact root"),
                index + 1,
                artifact["operator_private"]
                    .as_bool()
                    .expect("operator private"),
                artifact["publishable"].as_bool().expect("publishable"),
                false,
                false,
                false,
            );
            assert_ne!(expected_record_root, metadata_tampered_record_root);
            expected_record_roots.push(expected_record_root);
        }
        assert!(is_hex_root(
            value["artifact_set_root"]
                .as_str()
                .expect("artifact set root")
        ));
        assert_eq!(
            value["artifact_set_root"],
            collection_root("public-launch-artifact-set", expected_record_roots)
        );
        assert!(is_hex_root(
            value["public_launch_artifact_manifest_root"]
                .as_str()
                .expect("artifact manifest root")
        ));
        assert_eq!(
            value["capture_binding"]["capture_plan_must_bind_artifact_manifest"],
            true
        );
        assert_eq!(
            value["capture_binding"]["freeze_before_public_probe_capture"],
            true
        );
        assert_eq!(value["mainnet_boundary"]["mainnet_value_ready"], false);
        assert_eq!(value["mainnet_boundary"]["mainnet_custody_disabled"], true);
        assert!(!value_contains_exact_key(&value, "mainnet_readiness"));
        assert!(!value_contains_exact_key(&value, "public_launch_readiness"));
        ensure_public_launch_artifact_manifest_redacted(&value)
            .expect("redacted public launch artifact manifest");
        let mut metadata_tampered = value.clone();
        let original_operator_private = metadata_tampered["artifacts"][0]["operator_private"]
            .as_bool()
            .expect("operator private");
        metadata_tampered["artifacts"][0]["operator_private"] = json!(!original_operator_private);
        let error = ensure_public_launch_artifact_manifest_redacted(&metadata_tampered)
            .expect_err("metadata-tampered artifact manifest should fail");
        assert!(error.contains("artifact record root mismatch"));
        let _ = fs::remove_file(path);
    }

