    #[test]
    fn public_launch_bundle_verifier_rejects_re_rooted_stale_bundle() {
        let path = temp_json_path("nebula-public-launch-bundle-stale");
        let cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet-readiness CLI should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_launch_bundle(&path, &summary).expect("write public launch bundle");
        verify_public_launch_bundle(&path, &summary)
            .expect("fresh public launch bundle should verify");

        let mut stale: Value = serde_json::from_slice(&fs::read(&path).expect("read bundle"))
            .expect("launch bundle json");
        stale["source_roots"]["run_checkpoint_root"] = json!(root(&[
            "tampered-public-launch-bundle",
            &summary.manifest_id
        ]));
        let mut rootless = stale.clone();
        if let Some(map) = rootless.as_object_mut() {
            map.remove("public_launch_bundle_root");
        }
        stale["public_launch_bundle_root"] = json!(value_root("public-launch-bundle", &rootless));
        ensure_public_launch_bundle_redacted(&stale)
            .expect("re-rooted bundle should still be structurally redacted");
        fs::write(
            &path,
            format!(
                "{}\n",
                serde_json::to_string_pretty(&stale).expect("encode stale bundle")
            ),
        )
        .expect("write stale bundle");

        let error = verify_public_launch_bundle(&path, &summary)
            .expect_err("re-rooted stale bundle should fail exact verification");
        assert!(error.contains("source_roots/run_checkpoint_root mismatch"));
        let _ = fs::remove_file(path);
    }

    #[test]
    fn public_launch_readiness_report_exports_blocked_operator_gate() {
        let cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        let value = public_launch_readiness_report_artifact(&summary);
        let public_status = public_status_manifest(&summary);
        let public_bundle = public_launch_bundle(&summary);
        let capture_plan = public_deployment_capture_plan(&summary);
        assert_eq!(value["kind"], "nebula-public-launch-readiness-report");
        assert_eq!(value["local_operator_only"], true);
        assert_eq!(value["usable_as_public_deployment_evidence"], false);
        assert_eq!(value["usable_as_mainnet_custody_approval"], false);
        assert_eq!(value["level"], "public-launch-blocked");
        assert_eq!(value["public_launch_ready"], false);
        assert_eq!(
            value["public_status_manifest_root"],
            public_status["public_status_manifest_root"]
        );
        assert_eq!(
            value["public_launch_bundle_root"],
            public_bundle["public_launch_bundle_root"]
        );
        assert_eq!(
            value["capture_plan_root"],
            capture_plan["capture_plan_root"]
        );
        assert_eq!(
            value["capture_contract_root"],
            capture_plan["capture_contract_root"]
        );
        assert_eq!(
            value["public_deployment_evidence_template_root"],
            capture_plan["public_deployment_evidence_template_root"]
        );
        assert_eq!(
            value["deployment_preflight_checklist_root"],
            capture_plan["deployment_preflight"]["checklist_root"]
        );
        assert_eq!(
            value["public_launch_package_file_set_root"],
            public_launch_package_file_set_root(&summary.manifest_id, &summary.testnet_id)
        );
        assert_eq!(
            value["public_deployment_evidence_root"],
            "missing-public-deployment-evidence"
        );
        assert_eq!(
            value["public_launch_readiness"]["blocking_gaps"][0],
            "public-launch-deployment-attestation"
        );
        assert_eq!(
            value["blocking_gap_count"],
            value["public_launch_readiness"]["blocking_gaps"]
                .as_array()
                .expect("blocking gaps")
                .len()
        );
        assert!(is_hex_root(
            value["public_launch_readiness_artifact_root"]
                .as_str()
                .expect("artifact root")
        ));
        ensure_public_launch_readiness_report_artifact_safe(&value)
            .expect("safe public launch readiness report");
    }

