    #[test]
    fn public_deployment_capture_plan_rejects_re_rooted_wrong_schema_version() {
        let cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        let mut value = public_deployment_capture_plan(&summary);
        value["schema_version"] = json!(2);
        value
            .as_object_mut()
            .expect("capture plan object")
            .remove("capture_plan_root");
        let plan_root = value_root("public-deployment-capture-plan", &value);
        value["capture_plan_root"] = json!(plan_root);

        let error = ensure_public_deployment_capture_plan_redacted(&value)
            .expect_err("re-rooted capture plan with wrong schema should fail safety checks");
        assert!(error.contains("public deployment capture plan schema_version mismatch"));
    }

    #[test]
    fn public_deployment_capture_plan_verifier_rejects_stale_or_tampered_plan() {
        let path = temp_json_path("nebula-public-deployment-capture-plan-verify");
        let cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness cli should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_deployment_capture_plan(&path, &summary)
            .expect("write public deployment capture plan");
        verify_public_deployment_capture_plan(&path, &summary)
            .expect("verify public deployment capture plan");

        let mut plan: Value = serde_json::from_slice(&fs::read(&path).expect("read capture plan"))
            .expect("capture plan json");
        plan["capture_contract"]["freshness_window_ms"] =
            json!(MAX_PUBLIC_DEPLOYMENT_FRESHNESS_MS + 1);
        fs::write(
            &path,
            serde_json::to_string_pretty(&plan).expect("capture plan json"),
        )
        .expect("write tampered capture plan");
        let error = verify_public_deployment_capture_plan(&path, &summary)
            .expect_err("contract-tampered capture plan should fail verification");
        assert!(error.contains("capture contract root mismatch"));

        write_public_deployment_capture_plan(&path, &summary)
            .expect("rewrite public deployment capture plan");
        let mut plan: Value = serde_json::from_slice(&fs::read(&path).expect("read capture plan"))
            .expect("capture plan json");
        plan["public_launch_bundle_root"] = json!(root(&["stale-launch-bundle-root"]));
        if let Some(object) = plan.as_object_mut() {
            object.remove("capture_plan_root");
        }
        let plan_root = value_root("public-deployment-capture-plan", &plan);
        plan["capture_plan_root"] = json!(plan_root);
        fs::write(
            &path,
            serde_json::to_string_pretty(&plan).expect("capture plan json"),
        )
        .expect("write stale capture plan");
        let error = verify_public_deployment_capture_plan(&path, &summary)
            .expect_err("stale capture plan should fail verification");
        assert!(error.contains("public_launch_bundle_root mismatch"));
        let _ = fs::remove_file(path);
    }

    #[test]
    fn public_deployment_capture_scaffold_fills_verified_package_roots_without_evidence_claim() {
        let counter = TEST_FILE_COUNTER.fetch_add(1, AtomicOrdering::SeqCst);
        let package_dir = env::temp_dir().join(format!(
            "nebula-public-launch-package-scaffold-{}",
            root(&["test-public-capture-scaffold-package", &counter.to_string()])
        ));
        let package_dir_string = package_dir.to_string_lossy().into_owned();
        let scaffold_path = temp_json_path("nebula-public-deployment-capture-scaffold");
        let cli = parse_cli(vec![
            "--mainnet-readiness".to_string(),
            "--write-public-launch-package".to_string(),
            package_dir_string.clone(),
            "--write-public-deployment-capture-scaffold".to_string(),
            scaffold_path.clone(),
            "--verify-public-deployment-capture-scaffold".to_string(),
            scaffold_path.clone(),
            "--public-deployment-capture-scaffold-package".to_string(),
            package_dir_string.clone(),
        ])
        .expect("public deployment capture scaffold flags should parse");
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let summary = testnet.summary(Vec::new());
        write_public_launch_package(&package_dir_string, &summary)
            .expect("write public launch package");
        write_public_deployment_capture_scaffold(&scaffold_path, &package_dir_string, &summary)
            .expect("write public deployment capture scaffold");
        verify_public_deployment_capture_scaffold(&scaffold_path, &package_dir_string, &summary)
            .expect("verify public deployment capture scaffold");

        let scaffold: Value =
            serde_json::from_slice(&fs::read(&scaffold_path).expect("read scaffold"))
                .expect("scaffold json");
        let capture_plan = public_deployment_capture_plan(&summary);
        let package_manifest: Value = serde_json::from_slice(
            &fs::read(package_dir.join("nebula-public-launch-package.json"))
                .expect("read package manifest"),
        )
        .expect("package manifest json");
        let launch_report: Value = serde_json::from_slice(
            &fs::read(package_dir.join("nebula-public-launch-readiness-report.json"))
                .expect("read launch report"),
        )
        .expect("launch report json");
        let release_approval_template: Value = serde_json::from_slice(
            &fs::read(package_dir.join("nebula-release-approval-template.json"))
                .expect("read release approval template"),
        )
        .expect("release approval template json");
        let release_authority_registry_template: Value = serde_json::from_slice(
            &fs::read(package_dir.join("nebula-release-authority-registry-template.json"))
                .expect("read release authority registry template"),
        )
        .expect("release authority registry template json");

        assert_eq!(
            scaffold["kind"],
            "nebula-public-deployment-capture-scaffold"
        );
        assert_eq!(scaffold["template_only"], true);
        assert_eq!(scaffold["operator_fill_required"], true);
        assert_eq!(scaffold["usable_as_public_deployment_evidence"], false);
        assert_eq!(
            scaffold["capture_plan_root"],
            capture_plan["capture_plan_root"]
        );
        assert_eq!(
            scaffold["capture_contract_root"],
            capture_plan["capture_contract_root"]
        );
        assert_eq!(
            scaffold["deployment_preflight_checklist_root"],
            capture_plan["deployment_preflight"]["checklist_root"]
        );
        assert_eq!(
            scaffold["public_launch_package_file_set_root"],
            package_manifest["package_file_set_root"]
        );
        let expected_package_handoff_root = public_launch_package_handoff_root_from_roots(
            package_manifest["package_file_set_root"]
                .as_str()
                .expect("package file-set root"),
            package_manifest["package_manifest_root"]
                .as_str()
                .expect("package manifest root"),
            launch_report["public_launch_readiness_artifact_root"]
                .as_str()
                .expect("launch readiness artifact root"),
            &value_root("release-approval-template", &release_approval_template),
            &value_root(
                "release-authority-registry-template",
                &release_authority_registry_template,
            ),
        );
        assert_eq!(
            scaffold["public_launch_package_handoff_root"],
            expected_package_handoff_root
        );
        assert_eq!(
            scaffold["public_launch_package_manifest_root"],
            package_manifest["package_manifest_root"]
        );
        assert_eq!(scaffold["public_launch_package_schema_version"], 1);
        assert_eq!(scaffold["public_launch_package_chain_id"], CHAIN_ID);
        assert_eq!(scaffold["public_launch_package_version"], VERSION);
        assert_eq!(
            scaffold["public_launch_package_manifest_id"],
            package_manifest["manifest_id"]
        );
        assert_eq!(
            scaffold["public_launch_package_testnet_id"],
            package_manifest["testnet_id"]
        );
        assert_eq!(
            scaffold["public_launch_readiness_artifact_root"],
            launch_report["public_launch_readiness_artifact_root"]
        );
        assert_eq!(
            scaffold["release_approval_template_root"],
            value_root("release-approval-template", &release_approval_template)
        );
        assert_eq!(
            scaffold["release_authority_registry_template_root"],
            value_root(
                "release-authority-registry-template",
                &release_authority_registry_template
            )
        );
        assert_eq!(
            scaffold["deployment_preflight_receipt"]["capture_contract_root"],
            scaffold["capture_contract_root"]
        );
        assert_eq!(
            scaffold["deployment_preflight_receipt"]["deployment_preflight_checklist_root"],
            scaffold["deployment_preflight_checklist_root"]
        );
        assert_eq!(
            scaffold["public_deployment_runbook_receipt"]["capture_contract_root"],
            scaffold["capture_contract_root"]
        );

        let audit =
            public_deployment_capture_audit(&scaffold_path, &summary).expect("audit scaffold");
        assert_eq!(audit["missing_required_fields"], json!([]));
        assert_eq!(audit["capture_plan_root_matches"], true);
        assert_eq!(audit["capture_contract_root_matches"], true);
        assert_eq!(
            audit["public_deployment_evidence_template_root_matches"],
            true
        );
        let expected_capture_plan = public_deployment_capture_plan(&summary);
        assert_eq!(
            audit["expected_public_deployment_evidence_template_root"],
            expected_capture_plan["public_deployment_evidence_template_root"]
        );
        assert_eq!(audit["deployment_preflight_checklist_root_matches"], true);
        assert_eq!(audit["public_launch_package_file_set_root_matches"], true);
        assert_eq!(audit["public_launch_package_handoff_root_matches"], true);
        assert_eq!(
            audit["expected_public_launch_package_handoff_root"],
            expected_package_handoff_root
        );
        assert_eq!(audit["public_launch_package_schema_version_matches"], true);
        assert_eq!(audit["public_launch_package_chain_id_matches"], true);
        assert_eq!(audit["public_launch_package_version_matches"], true);
        assert_eq!(audit["public_launch_package_manifest_id_matches"], true);
        assert_eq!(audit["public_launch_package_testnet_id_matches"], true);
        assert_eq!(audit["public_launch_package_manifest_root_matches"], true);
        assert_eq!(audit["public_launch_readiness_artifact_root_matches"], true);
        assert_eq!(audit["placeholder_present"], true);
        assert_eq!(audit["assembler_ready"], false);
        let error = load_public_deployment_evidence(&scaffold_path)
            .expect_err("scaffold must not be accepted as public deployment evidence");
        assert!(error.contains("placeholders"));

        let _ = fs::remove_file(scaffold_path);
        let _ = fs::remove_dir_all(package_dir);
    }

