    #[test]
    fn public_deployment_capture_audit_marks_complete_capture_assembler_ready() {
        let base_cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut base_testnet = Testnet::new(base_cli);
        base_testnet.run().expect("base testnet run");
        let base_summary = base_testnet.summary(Vec::new());
        let capture_path =
            write_public_deployment_evidence(&valid_public_deployment_capture(&base_summary));
        let audit = public_deployment_capture_audit(&capture_path, &base_summary)
            .expect("audit complete capture");
        assert_eq!(audit["structural_ready"], true);
        assert_eq!(audit["strict_verifier_passed"], true);
        assert!(is_hex_root(
            audit["strict_evidence_root"]
                .as_str()
                .expect("strict evidence root")
        ));
        assert_eq!(audit["strict_verifier_error"], Value::Null);
        assert_eq!(audit["assembler_ready"], true);
        assert_eq!(
            audit["next_steps_root"],
            public_deployment_capture_next_steps_root(&audit["next_steps"])
        );
        assert_eq!(audit["commands"], public_deployment_capture_commands());
        assert_eq!(
            audit["commands_root"],
            public_deployment_capture_commands_root(&audit["commands"])
        );
        assert!(audit["next_steps"]["verify_capture"]
            .as_str()
            .expect("audit verify command")
            .contains("--verify-public-deployment-capture"));
        assert!(audit["next_steps"]["assemble_public_deployment"]
            .as_str()
            .expect("audit assemble command")
            .contains("--assemble-public-deployment-evidence"));
        assert_eq!(
            audit["command_sequence"],
            public_deployment_capture_command_sequence()
        );
        assert_eq!(
            audit["command_sequence_root"],
            public_deployment_capture_command_sequence_root(&audit["command_sequence"])
        );
        assert_eq!(audit["structural_failed_check_count"], 0);
        assert_eq!(
            audit["failed_checks"]
                .as_array()
                .expect("failed checks")
                .len(),
            0
        );
        assert_eq!(audit["placeholder_present"], false);
        assert_eq!(audit["capture_plan_root_matches"], true);
        assert_eq!(audit["capture_contract_root_matches"], true);
        assert_eq!(audit["deployment_preflight_checklist_root_matches"], true);
        assert!(is_hex_root(
            audit["expected_capture_plan_root"]
                .as_str()
                .expect("expected capture plan root")
        ));
        assert!(is_hex_root(
            audit["expected_capture_contract_root"]
                .as_str()
                .expect("expected capture contract root")
        ));
        assert!(is_hex_root(
            audit["expected_deployment_preflight_checklist_root"]
                .as_str()
                .expect("expected preflight checklist root")
        ));
        assert_eq!(audit["public_launch_bundle_root_matches"], true);
        assert_eq!(audit["public_status_manifest_root_matches"], true);
        assert_eq!(
            audit["expected_public_launch_package_file_set_root"],
            public_launch_package_file_set_root(
                &base_summary.manifest_id,
                &base_summary.testnet_id
            )
        );
        assert_eq!(audit["public_launch_package_file_set_root_matches"], true);
        assert_eq!(
            audit["missing_required_fields"]
                .as_array()
                .expect("missing fields")
                .len(),
            0
        );
        assert!(is_hex_root(
            audit["capture_audit_root"].as_str().expect("audit root")
        ));
        let _ = fs::remove_file(capture_path);
    }

