    #[test]
    fn public_deployment_report_rejects_stale_capture_roots() {
        let base_cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut base_testnet = Testnet::new(base_cli);
        base_testnet.run().expect("base testnet run");
        let base_summary = base_testnet.summary(Vec::new());
        let path =
            write_public_deployment_evidence(&valid_public_deployment_evidence(&base_summary));
        let mut evidence =
            load_public_deployment_evidence(&path).expect("public deployment evidence");
        let mut contract_only = evidence.clone();
        contract_only.capture_contract_root =
            root(&["test-public-deployment", "wrong-capture-contract"]);
        base_testnet.cli.public_deployment_evidence = Some(contract_only);
        let contract_only_summary = base_testnet.summary(Vec::new());
        assert!(!contract_only_summary.public_deployment.passed);
        assert!(
            !contract_only_summary
                .public_deployment
                .capture_contract_root_bound
        );
        assert!(
            contract_only_summary
                .public_deployment
                .deployment_preflight_checklist_root_bound
        );

        let mut preflight_only = evidence.clone();
        preflight_only.deployment_preflight_checklist_root =
            root(&["test-public-deployment", "wrong-preflight-checklist"]);
        base_testnet.cli.public_deployment_evidence = Some(preflight_only);
        let preflight_only_summary = base_testnet.summary(Vec::new());
        assert!(!preflight_only_summary.public_deployment.passed);
        assert!(
            preflight_only_summary
                .public_deployment
                .capture_contract_root_bound
        );
        assert!(
            !preflight_only_summary
                .public_deployment
                .deployment_preflight_checklist_root_bound
        );
        assert_ne!(
            contract_only_summary.public_deployment.report_root,
            preflight_only_summary.public_deployment.report_root
        );

        evidence.capture_plan_root = root(&["test-public-deployment", "wrong-capture-plan"]);
        evidence.capture_contract_root =
            root(&["test-public-deployment", "wrong-capture-contract"]);
        evidence.deployment_preflight_checklist_root =
            root(&["test-public-deployment", "wrong-preflight-checklist"]);
        base_testnet.cli.public_deployment_evidence = Some(evidence);
        let summary = base_testnet.summary(Vec::new());
        assert!(!summary.public_deployment.passed);
        assert!(!summary.public_deployment.capture_plan_bound);
        assert!(!summary.public_deployment.capture_plan_root_bound);
        assert!(!summary.public_deployment.capture_contract_root_bound);
        assert!(
            !summary
                .public_deployment
                .deployment_preflight_checklist_root_bound
        );
        assert!(is_hex_root(
            summary
                .public_deployment
                .expected_capture_plan_root
                .as_deref()
                .expect("expected capture plan root")
        ));
        assert!(is_hex_root(
            summary
                .public_deployment
                .expected_capture_contract_root
                .as_deref()
                .expect("expected capture contract root")
        ));
        assert!(is_hex_root(
            summary
                .public_deployment
                .expected_deployment_preflight_checklist_root
                .as_deref()
                .expect("expected preflight checklist root")
        ));
        assert_eq!(
            summary.public_launch_readiness.blocking_gaps,
            vec!["public-launch-deployment-attestation"]
        );
        let remediation = summary
            .public_launch_readiness
            .remediations
            .iter()
            .find(|remediation| remediation.blocker_id == "public-launch-deployment-attestation")
            .expect("deployment remediation");
        assert!(remediation
            .failed_subchecks
            .contains(&"capture_plan_bound".to_string()));
        assert!(remediation
            .failed_subchecks
            .contains(&"capture_plan_root_bound".to_string()));
        assert!(remediation
            .failed_subchecks
            .contains(&"capture_contract_root_bound".to_string()));
        assert!(remediation
            .failed_subchecks
            .contains(&"deployment_preflight_checklist_root_bound".to_string()));
        assert_eq!(
            remediation
                .repair_roots
                .get("capture_plan_root_bound")
                .map(String::as_str),
            summary
                .public_deployment
                .expected_capture_plan_root
                .as_deref()
        );
        assert_eq!(
            remediation
                .repair_roots
                .get("capture_contract_root_bound")
                .map(String::as_str),
            summary
                .public_deployment
                .expected_capture_contract_root
                .as_deref()
        );
        assert_eq!(
            remediation
                .repair_roots
                .get("deployment_preflight_checklist_root_bound")
                .map(String::as_str),
            summary
                .public_deployment
                .expected_deployment_preflight_checklist_root
                .as_deref()
        );
        assert!(!remediation.repair_roots.contains_key("capture_plan_bound"));
        let _ = fs::remove_file(path);
    }

