    #[test]
    fn public_deployment_report_rejects_mismatched_bootstrap_topology() {
        let base_cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut base_testnet = Testnet::new(base_cli);
        base_testnet.run().expect("base testnet run");
        let base_summary = base_testnet.summary(Vec::new());
        let path =
            write_public_deployment_evidence(&valid_public_deployment_evidence(&base_summary));
        let mut evidence =
            load_public_deployment_evidence(&path).expect("public deployment evidence");
        let mut registry_count_only = evidence.clone();
        registry_count_only.bootstrap_operator_registry_count = registry_count_only
            .bootstrap_operator_count
            .saturating_sub(1);
        base_testnet.cli.public_deployment_evidence = Some(registry_count_only);
        let registry_count_only_summary = base_testnet.summary(Vec::new());
        assert!(!registry_count_only_summary.public_deployment.passed);
        assert!(
            !registry_count_only_summary
                .public_deployment
                .bootstrap_operator_registry_count_bound
        );
        assert!(
            registry_count_only_summary
                .public_deployment
                .bootstrap_public_endpoint_count_bound
        );
        assert!(
            registry_count_only_summary
                .public_deployment
                .bootstrap_node_probe_count_bound
        );

        let mut endpoint_count_only = evidence.clone();
        endpoint_count_only.bootstrap_public_endpoint_count =
            endpoint_count_only.bootstrap_node_count.saturating_sub(1);
        base_testnet.cli.public_deployment_evidence = Some(endpoint_count_only);
        let endpoint_count_only_summary = base_testnet.summary(Vec::new());
        assert!(!endpoint_count_only_summary.public_deployment.passed);
        assert!(
            endpoint_count_only_summary
                .public_deployment
                .bootstrap_operator_registry_count_bound
        );
        assert!(
            !endpoint_count_only_summary
                .public_deployment
                .bootstrap_public_endpoint_count_bound
        );
        assert!(
            endpoint_count_only_summary
                .public_deployment
                .bootstrap_node_probe_count_bound
        );

        let mut probe_count_only = evidence.clone();
        probe_count_only.bootstrap_node_probe_count =
            probe_count_only.bootstrap_node_count.saturating_sub(1);
        base_testnet.cli.public_deployment_evidence = Some(probe_count_only);
        let probe_count_only_summary = base_testnet.summary(Vec::new());
        assert!(!probe_count_only_summary.public_deployment.passed);
        assert!(
            probe_count_only_summary
                .public_deployment
                .bootstrap_operator_registry_count_bound
        );
        assert!(
            probe_count_only_summary
                .public_deployment
                .bootstrap_public_endpoint_count_bound
        );
        assert!(
            !probe_count_only_summary
                .public_deployment
                .bootstrap_node_probe_count_bound
        );
        assert_ne!(
            registry_count_only_summary.public_deployment.report_root,
            endpoint_count_only_summary.public_deployment.report_root
        );
        assert_ne!(
            registry_count_only_summary.public_deployment.report_root,
            probe_count_only_summary.public_deployment.report_root
        );
        assert_ne!(
            endpoint_count_only_summary.public_deployment.report_root,
            probe_count_only_summary.public_deployment.report_root
        );

        evidence.bootstrap_node_set_root =
            root(&["test-public-deployment", "wrong-bootstrap-node-set"]);
        evidence.bootstrap_node_count = base_summary
            .public_bootstrap_profile
            .bootstrap_node_count
            .saturating_sub(1);
        evidence.bootstrap_operator_set_root =
            root(&["test-public-deployment", "wrong-bootstrap-operator-set"]);
        evidence.bootstrap_operator_count = base_summary
            .public_bootstrap_profile
            .bootstrap_operator_count
            + 1;
        evidence.bootstrap_operator_registry_count = base_summary
            .public_bootstrap_profile
            .bootstrap_operator_count;
        evidence.bootstrap_operator_registry_root =
            "missing-bootstrap-operator-registry-root".to_string();
        evidence.bootstrap_operator_signature_root =
            "missing-bootstrap-operator-signature-root".to_string();
        evidence.bootstrap_region_set_root =
            root(&["test-public-deployment", "wrong-bootstrap-region-set"]);
        evidence.bootstrap_public_endpoint_count = 0;
        evidence.bootstrap_node_probe_count = 0;
        evidence.bootstrap_node_probe_set_root =
            "missing-bootstrap-node-probe-set-root".to_string();
        evidence.bootstrap_p2p_endpoint_set_root =
            "missing-bootstrap-p2p-endpoint-set-root".to_string();
        evidence.bootstrap_status_page_set_root =
            "missing-bootstrap-status-page-set-root".to_string();
        base_testnet.cli.public_deployment_evidence = Some(evidence);
        let summary = base_testnet.summary(Vec::new());
        assert!(!summary.public_deployment.passed);
        assert!(!summary.public_deployment.bootstrap_nodes_bound);
        assert!(!summary.public_deployment.bootstrap_node_set_root_bound);
        assert!(!summary.public_deployment.bootstrap_node_count_sufficient);
        assert!(!summary.public_deployment.bootstrap_operator_set_root_bound);
        assert!(!summary.public_deployment.bootstrap_operator_count_bound);
        assert!(
            !summary
                .public_deployment
                .bootstrap_operator_registry_count_bound
        );
        assert!(
            !summary
                .public_deployment
                .bootstrap_operator_registry_root_bound
        );
        assert!(
            !summary
                .public_deployment
                .bootstrap_operator_signature_root_bound
        );
        assert!(!summary.public_deployment.bootstrap_region_set_root_bound);
        assert!(
            !summary
                .public_deployment
                .bootstrap_public_endpoint_count_bound
        );
        assert!(!summary.public_deployment.bootstrap_node_probe_count_bound);
        assert!(
            !summary
                .public_deployment
                .bootstrap_node_probe_set_root_bound
        );
        assert!(
            !summary
                .public_deployment
                .bootstrap_p2p_endpoint_set_root_bound
        );
        assert!(
            !summary
                .public_deployment
                .bootstrap_status_page_set_root_bound
        );
        assert_eq!(
            summary.public_deployment.bootstrap_operator_count,
            base_summary
                .public_bootstrap_profile
                .bootstrap_operator_count
                + 1
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_bootstrap_node_set_root
                .as_deref(),
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_node_set_root
                    .as_str()
            )
        );
        assert_eq!(
            summary.public_deployment.expected_bootstrap_node_count,
            Some(base_summary.public_bootstrap_profile.bootstrap_node_count)
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_bootstrap_operator_set_root
                .as_deref(),
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_operator_set_root
                    .as_str()
            )
        );
        assert_eq!(
            summary.public_deployment.expected_bootstrap_operator_count,
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_operator_count
            )
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_bootstrap_region_set_root
                .as_deref(),
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_region_set_root
                    .as_str()
            )
        );
        assert_eq!(
            summary.public_launch_readiness.blocking_gaps,
            vec!["public-launch-deployment-attestation"]
        );
        let remediation = summary
            .public_launch_readiness
            .remediations
            .iter()
            .find(|remediation| remediation.blocker_id == "public-launch-deployment-attestation")
            .expect("deployment remediation");
        for failed_subcheck in [
            "bootstrap_nodes_bound",
            "bootstrap_node_set_root_bound",
            "bootstrap_node_count_sufficient",
            "bootstrap_operator_set_root_bound",
            "bootstrap_operator_count_bound",
            "bootstrap_operator_registry_count_bound",
            "bootstrap_operator_registry_root_bound",
            "bootstrap_operator_signature_root_bound",
            "bootstrap_region_set_root_bound",
            "bootstrap_public_endpoint_count_bound",
            "bootstrap_node_probe_count_bound",
            "bootstrap_node_probe_set_root_bound",
            "bootstrap_p2p_endpoint_set_root_bound",
            "bootstrap_status_page_set_root_bound",
        ] {
            assert!(
                remediation
                    .failed_subchecks
                    .contains(&failed_subcheck.to_string()),
                "missing failed subcheck {failed_subcheck}"
            );
        }
        assert_eq!(
            remediation
                .repair_roots
                .get("bootstrap_node_set_root_bound")
                .map(String::as_str),
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_node_set_root
                    .as_str()
            )
        );
        assert_eq!(
            remediation
                .repair_roots
                .get("bootstrap_operator_set_root_bound")
                .map(String::as_str),
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_operator_set_root
                    .as_str()
            )
        );
        assert_eq!(
            remediation
                .repair_roots
                .get("bootstrap_region_set_root_bound")
                .map(String::as_str),
            Some(
                base_summary
                    .public_bootstrap_profile
                    .bootstrap_region_set_root
                    .as_str()
            )
        );
        let _ = fs::remove_file(path);
    }

