    #[test]
    fn public_deployment_report_exposes_expected_runbook_receipt_roots() {
        let base_cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut base_testnet = Testnet::new(base_cli);
        base_testnet.run().expect("base testnet run");
        let base_summary = base_testnet.summary(Vec::new());
        let path =
            write_public_deployment_evidence(&valid_public_deployment_evidence(&base_summary));
        let mut evidence =
            load_public_deployment_evidence(&path).expect("public deployment evidence");
        let _ = fs::remove_file(path);
        let expected_receipt_root = evidence.public_deployment_runbook_receipt_root.clone();
        let expected_step_receipt_set_root = evidence
            .public_deployment_runbook_step_receipt_set_root
            .clone();
        let expected_step_receipt_count = evidence.public_deployment_runbook_step_receipt_count;
        evidence.public_deployment_runbook_receipt_root =
            root(&["test-public-deployment", "wrong-runbook-receipt"]);
        evidence.public_deployment_runbook_step_receipt_set_root =
            root(&["test-public-deployment", "wrong-runbook-step-receipt-set"]);
        evidence.public_deployment_runbook_step_receipt_count = evidence
            .public_deployment_runbook_step_receipt_count
            .saturating_add(1);
        base_testnet.cli.public_deployment_evidence = Some(evidence);
        let summary = base_testnet.summary(Vec::new());
        assert!(!summary.public_deployment.passed);
        assert!(!summary.public_deployment.runbook_receipt_bound);
        assert!(
            !summary
                .public_deployment
                .public_deployment_runbook_receipt_root_bound
        );
        assert!(
            !summary
                .public_deployment
                .public_deployment_runbook_step_receipt_set_root_bound
        );
        assert!(
            !summary
                .public_deployment
                .public_deployment_runbook_step_receipt_count_bound
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_public_deployment_runbook_receipt_root
                .as_deref(),
            Some(expected_receipt_root.as_str())
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_public_deployment_runbook_step_receipt_set_root
                .as_deref(),
            Some(expected_step_receipt_set_root.as_str())
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_public_deployment_runbook_step_receipt_count,
            Some(expected_step_receipt_count)
        );
        let remediation = summary
            .public_launch_readiness
            .remediations
            .iter()
            .find(|remediation| remediation.blocker_id == "public-launch-deployment-attestation")
            .expect("deployment remediation");
        for failed_subcheck in [
            "runbook_receipt_bound",
            "public_deployment_runbook_receipt_root_bound",
            "public_deployment_runbook_step_receipt_set_root_bound",
            "public_deployment_runbook_step_receipt_count_bound",
        ] {
            assert!(
                remediation
                    .failed_subchecks
                    .contains(&failed_subcheck.to_string()),
                "missing failed subcheck {failed_subcheck}"
            );
        }
        assert_eq!(
            remediation
                .repair_roots
                .get("public_deployment_runbook_receipt_root_bound")
                .map(String::as_str),
            Some(expected_receipt_root.as_str())
        );
        assert_eq!(
            remediation
                .repair_roots
                .get("public_deployment_runbook_step_receipt_set_root_bound")
                .map(String::as_str),
            Some(expected_step_receipt_set_root.as_str())
        );
        assert!(!remediation
            .repair_roots
            .contains_key("public_deployment_runbook_step_receipt_count_bound"));
    }

    #[test]
    fn public_deployment_report_exposes_expected_runbook_roots() {
        let base_cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut base_testnet = Testnet::new(base_cli);
        base_testnet.run().expect("base testnet run");
        let base_summary = base_testnet.summary(Vec::new());
        let path =
            write_public_deployment_evidence(&valid_public_deployment_evidence(&base_summary));
        let mut evidence =
            load_public_deployment_evidence(&path).expect("public deployment evidence");
        let _ = fs::remove_file(path);
        evidence.public_deployment_runbook_root =
            root(&["test-public-deployment", "wrong-runbook-root"]);
        evidence.public_deployment_runbook_receipt["public_deployment_runbook_root"] =
            json!(&evidence.public_deployment_runbook_root);
        refresh_public_deployment_runbook_receipt_fields(&mut evidence);
        evidence.provenance_root = public_deployment_provenance_root(&evidence);
        evidence.evidence_root = public_deployment_attestation_root(&evidence);
        let wrong_path =
            write_public_deployment_evidence(&public_deployment_evidence_json(&evidence));
        let loaded = load_public_deployment_evidence(&wrong_path)
            .expect("self-consistent wrong runbook root evidence loads");
        base_testnet.cli.public_deployment_evidence = Some(loaded);
        let summary = base_testnet.summary(Vec::new());
        let expected_runbook = public_deployment_runbook(&summary);
        assert!(!summary.public_deployment.passed);
        assert!(!summary.public_deployment.runbook_receipt_bound);
        assert!(
            !summary
                .public_deployment
                .public_deployment_runbook_root_bound
        );
        assert!(
            summary
                .public_deployment
                .public_deployment_runbook_step_set_root_bound
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_public_deployment_runbook_root
                .as_deref()
                .expect("expected deployment runbook root"),
            expected_runbook["public_deployment_runbook_root"]
                .as_str()
                .expect("expected runbook root")
        );
        assert_eq!(
            summary
                .public_deployment
                .expected_public_deployment_runbook_step_set_root
                .as_deref()
                .expect("expected deployment runbook step-set root"),
            expected_runbook["step_set_root"]
                .as_str()
                .expect("expected runbook step-set root")
        );
        let remediation = summary
            .public_launch_readiness
            .remediations
            .iter()
            .find(|remediation| remediation.blocker_id == "public-launch-deployment-attestation")
            .expect("deployment remediation");
        assert!(remediation
            .failed_subchecks
            .contains(&"runbook_receipt_bound".to_string()));
        assert!(remediation
            .failed_subchecks
            .contains(&"public_deployment_runbook_root_bound".to_string()));
        assert_eq!(
            remediation
                .repair_roots
                .get("public_deployment_runbook_root_bound")
                .map(String::as_str),
            summary
                .public_deployment
                .expected_public_deployment_runbook_root
                .as_deref()
        );
        assert!(!remediation
            .repair_roots
            .contains_key("public_deployment_runbook_step_set_root_bound"));
        let _ = fs::remove_file(wrong_path);
    }

