    #[test]
    fn public_deployment_report_rejects_self_consistent_stale_status_manifest() {
        let base_cli = parse_cli(vec!["--mainnet-readiness".to_string()])
            .expect("mainnet readiness should parse");
        let mut base_testnet = Testnet::new(base_cli);
        base_testnet.run().expect("base testnet run");
        let base_summary = base_testnet.summary(Vec::new());
        let path =
            write_public_deployment_evidence(&valid_public_deployment_evidence(&base_summary));
        let mut evidence =
            load_public_deployment_evidence(&path).expect("public deployment evidence");
        let _ = fs::remove_file(path);

        evidence.public_status_manifest["latest_block_height"] =
            json!(base_summary.latest_block_height.saturating_add(1));
        let mut root_payload = evidence.public_status_manifest.clone();
        root_payload
            .as_object_mut()
            .expect("status manifest object")
            .remove("public_status_manifest_root");
        let public_status_manifest_root = value_root("public-status-manifest", &root_payload);
        evidence.public_status_manifest["public_status_manifest_root"] =
            json!(&public_status_manifest_root);
        evidence.public_status_manifest_root = public_status_manifest_root.clone();
        evidence.status_probe_root = root(&[
            "public-deployment-status-probe",
            &evidence.public_rpc_url,
            &evidence.public_status_manifest_root,
            &evidence.status_probe_http_status.to_string(),
        ]);
        let status_json =
            serde_json::to_string(&evidence.public_status_manifest).expect("status json");
        evidence.p2p_handshake =
            format!("nebula-testnet {}", root(&["p2p", CHAIN_ID, &status_json]));
        evidence.p2p_handshake_root = root(&[
            "public-deployment-p2p-probe",
            &evidence.public_p2p_endpoint,
            &evidence.p2p_handshake,
        ]);
        evidence.health_probe["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        let health_probe_body_root =
            value_root("public-deployment-health-body", &evidence.health_probe);
        evidence.health_probe_root = root(&[
            "public-deployment-health-probe",
            &evidence.health_check_url,
            &evidence.health_probe_http_status.to_string(),
            &health_probe_body_root,
        ]);
        evidence.status_page_probe["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        let status_page_probe_body_root = value_root(
            "public-deployment-status-page-body",
            &evidence.status_page_probe,
        );
        evidence.status_page_probe_root = root(&[
            "public-deployment-status-page-probe",
            &evidence.status_page_url,
            &evidence.status_page_probe_http_status.to_string(),
            &status_page_probe_body_root,
        ]);
        evidence.metrics_probe["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        let metrics_probe_body_root =
            value_root("public-deployment-metrics-body", &evidence.metrics_probe);
        evidence.metrics_probe_root = root(&[
            "public-deployment-metrics-probe",
            &evidence.metrics_url,
            &evidence.metrics_probe_http_status.to_string(),
            &metrics_probe_body_root,
        ]);
        evidence.deployed_finality_probe["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        evidence.deployed_finality_probe["latest_block_height"] =
            json!(base_summary.latest_block_height.saturating_add(1));
        let deployed_finality_body_root = value_root(
            "public-deployment-deployed-finality-body",
            &evidence.deployed_finality_probe,
        );
        evidence.deployed_finality_probe_root = root(&[
            "public-deployment-deployed-finality-probe",
            &evidence.metrics_url,
            &evidence.deployed_finality_probe_http_status.to_string(),
            &deployed_finality_body_root,
        ]);
        evidence.proxy_policy_claims["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        evidence.proxy_policy_root =
            expected_public_proxy_policy_root(&evidence.proxy_policy_claims)
                .expect("proxy policy root");
        evidence.proxy_policy_claims_root = value_root(
            "public-deployment-proxy-policy-claims",
            &evidence.proxy_policy_claims,
        );
        evidence.firewall_policy_claims["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        evidence.firewall_policy_root =
            expected_public_firewall_policy_root(&evidence.firewall_policy_claims)
                .expect("firewall policy root");
        evidence.firewall_policy_claims_root = value_root(
            "public-deployment-firewall-policy-claims",
            &evidence.firewall_policy_claims,
        );
        evidence.rate_limit_policy_claims["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        evidence.rate_limit_policy_claims_root = value_root(
            "public-deployment-rate-limit-policy-claims",
            &evidence.rate_limit_policy_claims,
        );
        evidence.incident_contact_probe["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        let incident_contact_body_root = value_root(
            "public-deployment-incident-contact-body",
            &evidence.incident_contact_probe,
        );
        evidence.incident_contact_probe_root = root(&[
            "public-deployment-incident-contact-probe",
            &evidence.incident_contact_url,
            &evidence.incident_contact_probe_http_status.to_string(),
            &incident_contact_body_root,
        ]);
        evidence.private_summary_probe["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        evidence.private_summary_probe_root = public_deployment_private_summary_probe_root(
            &evidence.public_rpc_url,
            evidence.private_summary_probe_status,
            &evidence.private_summary_probe,
        );
        evidence.deployment_preflight_receipt["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        refresh_public_deployment_preflight_receipt_fields(&mut evidence);
        evidence.public_deployment_runbook_receipt["public_status_manifest_root"] =
            json!(&evidence.public_status_manifest_root);
        refresh_public_deployment_runbook_receipt_fields(&mut evidence);
        refresh_public_deployment_bootstrap_node_probe_fields(&mut evidence);
        refresh_public_deployment_probe_set_fields(&mut evidence);
        refresh_public_deployment_observer_fields(&mut evidence);
        evidence.provenance_root = public_deployment_provenance_root(&evidence);
        evidence.evidence_root = public_deployment_attestation_root(&evidence);

        let stale_path =
            write_public_deployment_evidence(&public_deployment_evidence_json(&evidence));
        let loaded = load_public_deployment_evidence(&stale_path)
            .expect("self-consistent stale evidence should load");
        base_testnet.cli.public_deployment_evidence = Some(loaded);
        let summary = base_testnet.summary(Vec::new());
        assert!(!summary.public_deployment.passed);
        assert!(summary.public_deployment.matches_current_manifest);
        assert!(summary.public_deployment.public_launch_bundle_root_bound);
        assert!(!summary.public_deployment.status_manifest_root_bound);
        assert!(!summary.public_deployment.public_status_manifest_root_bound);
        assert!(
            !summary
                .public_deployment
                .public_status_manifest_payload_bound
        );
        assert!(is_hex_root(
            summary
                .public_deployment
                .expected_public_status_manifest_root
                .as_deref()
                .expect("expected public status manifest root")
        ));
        assert!(!summary.acceptance.public_deployment_attestation_available);
        let remediation = summary
            .public_launch_readiness
            .remediations
            .iter()
            .find(|remediation| remediation.blocker_id == "public-launch-deployment-attestation")
            .expect("deployment remediation");
        assert!(remediation
            .failed_subchecks
            .contains(&"status_manifest_root_bound".to_string()));
        assert!(remediation
            .failed_subchecks
            .contains(&"public_status_manifest_root_bound".to_string()));
        assert!(remediation
            .failed_subchecks
            .contains(&"public_status_manifest_payload_bound".to_string()));
        for failed_subcheck in [
            "status_manifest_root_bound",
            "public_status_manifest_root_bound",
            "public_status_manifest_payload_bound",
        ] {
            assert_eq!(
                remediation
                    .repair_roots
                    .get(failed_subcheck)
                    .map(String::as_str),
                summary
                    .public_deployment
                    .expected_public_status_manifest_root
                    .as_deref(),
                "missing repair root for {failed_subcheck}"
            );
        }
        let _ = fs::remove_file(stale_path);
    }

