    #[test]
    fn distributed_finality_for_run_root_binds_region_counts() {
        let path = write_evidence_bundle(&valid_evidence_bundle());
        let mut evidence = load_readiness_evidence_bundle(&path).expect("valid evidence bundle");
        let mut testnet = Testnet::new(Cli::default());
        testnet.run().expect("testnet run");
        let run_profile = testnet.run_profile_report();
        assert_eq!(testnet.expected_distributed_finality_region_count(), 4);
        let baseline = testnet.distributed_finality_for_run_root(&evidence, &run_profile);
        evidence.distributed_finality_region_count = 3;
        let changed_observed_region =
            testnet.distributed_finality_for_run_root(&evidence, &run_profile);
        assert_ne!(baseline, changed_observed_region);
        evidence.distributed_finality_run_profile_report_root =
            root(&["changed-distributed-finality-run-profile-root"]);
        let changed_run_binding =
            testnet.distributed_finality_for_run_root(&evidence, &run_profile);
        assert_ne!(changed_observed_region, changed_run_binding);

        let mut compact_testnet = Testnet::new(Cli {
            validator_count: 3,
            validator_threshold: 2,
            ..Cli::default()
        });
        compact_testnet.run().expect("compact testnet run");
        let compact_run_profile = compact_testnet.run_profile_report();
        assert_eq!(
            compact_testnet.expected_distributed_finality_region_count(),
            3
        );
        let changed_expected_region =
            compact_testnet.distributed_finality_for_run_root(&evidence, &compact_run_profile);
        assert_ne!(changed_observed_region, changed_expected_region);
        let _ = fs::remove_file(path);
    }

