    #[test]
    fn release_approval_artifact_shape_passes_but_authority_gap_remains() {
        let evidence_path = write_evidence_bundle(&valid_evidence_bundle());
        let evidence = load_readiness_evidence_bundle(&evidence_path).expect("evidence bundle");
        let cli = Cli {
            mainnet_readiness: true,
            adversarial_self_test: true,
            readiness_evidence: Some(evidence.clone()),
            ..Cli::default()
        };
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let bootstrap_summary = testnet.summary(Vec::new());
        let local_fault_root = bootstrap_summary
            .fault_injection
            .as_ref()
            .expect("fault injection report")
            .report_root
            .clone();
        let approval_path = write_release_approval_bundle(&valid_release_approval_bundle(
            &bootstrap_summary.manifest_id,
            &bootstrap_summary.mainnet_readiness.run_checkpoint_root,
            &evidence.bundle_root,
            &local_fault_root,
        ));
        testnet.cli.release_approval =
            Some(load_release_approval_bundle(&approval_path).expect("release approval"));
        let summary = testnet.summary(Vec::new());
        assert!(summary.mainnet_readiness.evidence_bundle_shape_verified);
        assert!(summary.mainnet_readiness.release_approval_shape_verified);
        assert_eq!(
            summary.mainnet_readiness.blocking_gaps,
            vec!["release-authority-registry", "mainnet-release-approval"]
        );
        assert_eq!(summary.mainnet_readiness.level, "mainnet-dry-run-blocked");
        assert!(!summary.mainnet_readiness.mainnet_value_ready);
        assert!(!summary.acceptance.mainnet_value_ready);
        let strict_error = ensure_artifact_readiness_gates(&summary)
            .expect_err("shape-only approval must still require authority registry");
        assert!(strict_error.contains("release-authority-registry"));
        assert!(summary
            .mainnet_readiness
            .checks
            .iter()
            .any(|check| check.id == "release-approval-artifact" && check.status == "pass"));
        assert!(summary
            .mainnet_readiness
            .checks
            .iter()
            .any(|check| check.id == "release-authority-registry" && check.status == "blocked"));
        assert!(summary
            .mainnet_readiness
            .checks
            .iter()
            .any(|check| check.id == "mainnet-release-approval" && check.status == "blocked"));
        let _ = fs::remove_file(evidence_path);
        let _ = fs::remove_file(approval_path);
    }

    #[test]
    fn release_authority_registry_passes_but_custody_gap_remains() {
        let evidence_path = write_evidence_bundle(&valid_evidence_bundle());
        let evidence = load_readiness_evidence_bundle(&evidence_path).expect("evidence bundle");
        let cli = Cli {
            mainnet_readiness: true,
            adversarial_self_test: true,
            readiness_evidence: Some(evidence.clone()),
            ..Cli::default()
        };
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("testnet run");
        let bootstrap_summary = testnet.summary(Vec::new());
        let local_fault_root = bootstrap_summary
            .fault_injection
            .as_ref()
            .expect("fault injection report")
            .report_root
            .clone();
        let registry_path =
            write_release_authority_registry(&valid_release_authority_registry_bundle());
        let registry =
            load_release_authority_registry(&registry_path).expect("release authority registry");
        let approval_path =
            write_release_approval_bundle(&valid_authority_bound_release_approval_bundle(
                &bootstrap_summary.manifest_id,
                &bootstrap_summary.mainnet_readiness.run_checkpoint_root,
                &evidence.bundle_root,
                &local_fault_root,
                &registry.registry_root,
            ));
        testnet.cli.release_approval =
            Some(load_release_approval_bundle(&approval_path).expect("release approval"));
        testnet.cli.release_authority_registry = Some(registry);
        let summary = testnet.summary(Vec::new());
        assert!(summary.mainnet_readiness.evidence_bundle_shape_verified);
        assert!(summary.mainnet_readiness.release_approval_shape_verified);
        assert!(
            summary
                .mainnet_readiness
                .release_authority_registry_verified
        );
        assert_eq!(
            summary.mainnet_readiness.blocking_gaps,
            vec!["mainnet-release-approval"]
        );
        assert_eq!(
            summary.mainnet_readiness.level,
            "mainnet-dry-run-evidence-shape-complete"
        );
        ensure_artifact_readiness_gates(&summary)
            .expect("registry-backed approval leaves only external custody sentinel");
        assert!(summary
            .mainnet_readiness
            .checks
            .iter()
            .any(|check| check.id == "release-authority-registry" && check.status == "pass"));
        assert!(!summary.mainnet_readiness.mainnet_value_ready);
        let _ = fs::remove_file(evidence_path);
        let _ = fs::remove_file(approval_path);
        let _ = fs::remove_file(registry_path);
    }

