    fn public_deployment_evidence_json(evidence: &PublicDeploymentEvidence) -> String {
        let mut value = serde_json::to_value(evidence).expect("public deployment evidence value");
        let map = value
            .as_object_mut()
            .expect("public deployment evidence object");
        map.insert(
            "kind".to_string(),
            json!("nebula-public-deployment-attestation"),
        );
        map.insert("template_only".to_string(), json!(false));
        map.insert("chain_id".to_string(), json!(CHAIN_ID));
        map.insert("version".to_string(), json!(VERSION));
        map.insert("public_alpha_only".to_string(), json!(true));
        map.insert("custody_mode".to_string(), json!("no-mainnet-custody"));
        serde_json::to_string_pretty(&value).expect("public deployment evidence json")
    }

