    fn privacy_policy_component(kind: &str, reviewed_at_height: u64) -> (Value, String) {
        let reviewer_commitment = root(&["test-privacy-policy-reviewer", kind]);
        let scope_root = root(&["test-privacy-policy-scope", kind]);
        let implementation_evidence_root = root(&["test-privacy-policy-implementation", kind]);
        let negative_test_root = root(&["test-privacy-policy-negative-test", kind]);
        let mitigation_root = root(&["test-privacy-policy-mitigation", kind]);
        let mut component = json!({
            "kind": kind,
            "passed": true,
            "reviewed_at_height": reviewed_at_height,
            "reviewer_commitment": reviewer_commitment,
            "scope_root": scope_root,
            "implementation_evidence_root": implementation_evidence_root,
            "negative_test_root": negative_test_root,
            "mitigation_root": mitigation_root,
        });
        match kind {
            "anchor_privacy_profile" => {
                component["constant_size_payload"] = json!(true);
                component["bounded_cadence_jitter"] = json!(true);
                component["unique_amounts_avoided"] = json!(true);
                component["raw_identifiers_excluded"] = json!(true);
                component["independent_submitter_count"] = json!(3);
            }
            "deposit_privacy_profile" => {
                component["one_time_addresses"] = json!(true);
                component["batched_attestations"] = json!(true);
                component["amount_address_mapping_excluded"] = json!(true);
                component["user_mint_delay_supported"] = json!(true);
                component["minimum_batch_size"] = json!(16);
            }
            "withdrawal_privacy_profile" => {
                component["batching_enabled"] = json!(true);
                component["randomized_delay_window"] = json!(true);
                component["amount_bucket_policy"] = json!(true);
                component["raw_recipient_excluded"] = json!(true);
                component["challenge_hold_supported"] = json!(true);
                component["minimum_delay_window_blocks"] = json!(20);
            }
            "wallet_recovery_privacy_profile" => {
                component["scoped_history_recovery_supported"] = json!(true);
                component["da_payload_audit_supported"] = json!(true);
                component["transparent_balance_mode_disabled"] = json!(true);
                component["scoped_disclosure_supported"] = json!(true);
                component["relay_path_commitments_verified"] = json!(true);
                component["wallet_recovery_vector_count"] = json!(4);
            }
            _ => panic!("unexpected privacy policy component kind {kind}"),
        }
        let claims =
            privacy_policy_component_claims(&component, kind).expect("valid privacy claims");
        let evidence_root = privacy_policy_component_root(
            kind,
            reviewed_at_height,
            component["reviewer_commitment"]
                .as_str()
                .expect("reviewer commitment"),
            component["scope_root"].as_str().expect("scope root"),
            component["implementation_evidence_root"]
                .as_str()
                .expect("implementation root"),
            component["negative_test_root"]
                .as_str()
                .expect("negative test root"),
            component["mitigation_root"]
                .as_str()
                .expect("mitigation root"),
            &claims,
        );
        component["evidence_root"] = json!(evidence_root.clone());
        (component, evidence_root)
    }

