    fn test_run_checkpoint_root(cli: Cli) -> String {
        let mut testnet = Testnet::new(cli);
        testnet.run().expect("checkpoint testnet run");
        let consensus = testnet.consensus_report();
        let fault_injection = fault_injection_report(&testnet.cli);
        let run_profile = testnet.run_profile_report();
        let wasm_runtime_local = testnet.wasm_runtime_local_report();
        let finality_latency_profile = testnet.finality_latency_profile_report(&consensus);
        let distributed_finality_local = testnet.distributed_finality_local_report(&consensus);
        let crypto_inventory = crypto_inventory_report();
        let fee_efficiency = testnet.fee_efficiency_report();
        let anchor_capacity = testnet.anchor_capacity_report();
        let wallet_recovery_audit = testnet.wallet_recovery_audit_report();
        let reserve_monitoring = testnet.reserve_monitoring_report();
        let operations_readiness_local =
            testnet.operations_readiness_local_report(&reserve_monitoring);
        let privacy_surface = testnet.privacy_surface_report(
            &wallet_recovery_audit,
            &reserve_monitoring,
            &operations_readiness_local,
        );
        testnet.run_checkpoint_root(
            &consensus,
            Some(&fault_injection),
            &run_profile,
            &wasm_runtime_local,
            &finality_latency_profile,
            &distributed_finality_local,
            &crypto_inventory,
            &fee_efficiency,
            &anchor_capacity,
            &wallet_recovery_audit,
            &reserve_monitoring,
            &operations_readiness_local,
            &privacy_surface,
        )
    }

    fn valid_release_approval_bundle(
        testnet_manifest_id: &str,
        testnet_run_checkpoint_root: &str,
        readiness_evidence_bundle_root: &str,
        local_adversarial_self_test_root: &str,
    ) -> String {
        let signoffs = REQUIRED_RELEASE_SIGNOFF_ROLES
            .iter()
            .map(|role| {
                let signer_commitment = root(&["test-release-signer", role]);
                let pq_signature_root = root(&["test-release-pq-signature", role]);
                let signoff_id = root(&["test-release-signoff-id", role]);
                json!({
                    "role": role,
                    "accepted": true,
                    "signer_commitment": signer_commitment,
                    "pq_signature_root": pq_signature_root,
                    "signoff_id": signoff_id,
                })
            })
            .collect::<Vec<_>>();
        let signoff_roots = signoffs
            .iter()
            .map(|signoff| {
                root(&[
                    "release-approval-signoff",
                    signoff["role"].as_str().expect("role"),
                    signoff["signer_commitment"].as_str().expect("signer"),
                    signoff["pq_signature_root"].as_str().expect("signature"),
                    signoff["signoff_id"].as_str().expect("signoff id"),
                ])
            })
            .collect::<Vec<_>>();
        let signoff_root = collection_root("release-approval-signoff-quorum", signoff_roots);
        let report_root = root(&[
            "test-production-readiness-report",
            readiness_evidence_bundle_root,
            local_adversarial_self_test_root,
            &signoff_root,
        ]);
        let signed_at_height = 1;
        let expires_at_height = 10_080;
        let threshold = REQUIRED_RELEASE_SIGNOFF_ROLES.len() as u64;
        let count = threshold;
        let approval_root = release_approval_root(
            "mainnet",
            testnet_manifest_id,
            testnet_run_checkpoint_root,
            readiness_evidence_bundle_root,
            local_adversarial_self_test_root,
            &report_root,
            &signoff_root,
            signed_at_height,
            expires_at_height,
            threshold,
            count,
        );
        json!({
            "schema_version": 1,
            "chain_id": CHAIN_ID,
            "approval_kind": "nebula-mainnet-release-approval",
            "target_network": "mainnet",
            "custody_mode": "external-mainnet-process-required",
            "approved": true,
            "testnet_manifest_id": testnet_manifest_id,
            "testnet_run_checkpoint_root": testnet_run_checkpoint_root,
            "readiness_evidence_bundle_root": readiness_evidence_bundle_root,
            "local_adversarial_self_test_root": local_adversarial_self_test_root,
            "production_readiness_report": {
                "release_candidate": true,
                "open_blockers": 0,
                "release_score_bps": 9_500,
                "critical_score_bps": 10_000,
                "report_root": report_root,
                "signoff_root": signoff_root,
            },
            "signoff_quorum": {
                "threshold": threshold,
                "signoffs": signoffs,
            },
            "signed_at_height": signed_at_height,
            "expires_at_height": expires_at_height,
            "approval_root": approval_root,
        })
        .to_string()
    }

